diffs.replacement:
{
  "name": "İnşaat Mühendisi & Müteahhit Asistanı",
  "description": "Arsa bilgilerine dayanarak TAKS/KAKS hesabı yapan, çekme mesafelerini görselleştiren ve daire tipolojisi öneren profesyonel mühendislik aracı."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum NizamType {
  AYRIK = 'AYRIK',
  BITISIK = 'BITISIK'
}

export interface ArsaBilgileri {
  alan: number;
  il: string;
  ilce: string;
  mahalle: string;
  ada: string;
  parsel: string;
  nizam: NizamType;
  cekmeOn: number;
  cekmeYan: number;
  cekmeArka: number;
  taks: number;
  katAdedi: number;
  daireSayisiTercihi: number;
}

export interface HesapSonuclari {
  kaks: number;
  tabanAlani: number;
  zeminBrut: number;
  normalKatBrut: number;
  toplamKat: number; // Bodrum + Kat
  daireTipi: string;
  daireBasiMetrekare: number;
}

import React, { useState, useEffect } from 'react';
import { NizamType, ArsaBilgileri, HesapSonuclari } from './types';
import ConstructionForm from './components/ConstructionForm';
import PlotVisualizer from './components/PlotVisualizer';
import ResultsPanel from './components/ResultsPanel';
import Header from './components/Header';

const App: React.FC = () => {
  const [darkMode, setDarkMode] = useState(true);
  const [formData, setFormData] = useState<ArsaBilgileri | null>(null);
  const [results, setResults] = useState<HesapSonuclari | null>(null);

  useEffect(() => {
    if (darkMode) {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [darkMode]);

  const calculateData = (data: ArsaBilgileri) => {
    const kaks = data.taks * data.katAdedi;
    const tabanAlani = data.alan * data.taks;
    const zeminBrut = tabanAlani * 1.1;
    const normalKatBrut = zeminBrut * 1.15;
    const daireBasiMetrekare = normalKatBrut / data.daireSayisiTercihi;

    let daireTipi = "4+1 veya daha büyük";
    if (daireBasiMetrekare < 105) {
      daireTipi = "1+1 Apart";
    } else if (daireBasiMetrekare >= 105 && daireBasiMetrekare < 115) {
      daireTipi = "2+1 Daire";
    } else if (daireBasiMetrekare >= 115 && daireBasiMetrekare < 150) {
      daireTipi = "3+1 Daire";
    }

    setResults({
      kaks,
      tabanAlani,
      zeminBrut,
      normalKatBrut,
      toplamKat: data.katAdedi + 1, // Bodrum + Kat
      daireTipi,
      daireBasiMetrekare
    });
    setFormData(data);
  };

  return (
    <div className="min-h-screen pb-12 transition-colors duration-300 bg-gray-50 dark:bg-slate-900 text-slate-900 dark:text-slate-100">
      <Header darkMode={darkMode} setDarkMode={setDarkMode} />

      <main className="container mx-auto px-4 mt-8 max-w-6xl">
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
          <div className="space-y-6">
            <section className="bg-white dark:bg-slate-800 p-6 rounded-2xl shadow-xl border border-gray-200 dark:border-slate-700">
              <h2 className="text-xl font-bold mb-6 flex items-center gap-2">
                <i className="fa-solid fa-hard-hat text-blue-500"></i>
                Arsa ve Proje Bilgileri
              </h2>
              <ConstructionForm onCalculate={calculateData} />
            </section>

            {results && formData && (
              <div className="block lg:hidden">
                <ResultsPanel results={results} data={formData} />
              </div>
            )}
          </div>

          <div className="space-y-6">
            {formData ? (
              <>
                <PlotVisualizer data={formData} results={results} />
                <div className="hidden lg:block">
                  {results && <ResultsPanel results={results} data={formData} />}
                </div>
              </>
            ) : (
              <div className="h-full flex flex-col items-center justify-center p-12 bg-white dark:bg-slate-800 rounded-2xl border-2 border-dashed border-gray-300 dark:border-slate-700 text-center">
                <i className="fa-solid fa-map-location-dot text-6xl text-gray-300 dark:text-slate-600 mb-4"></i>
                <p className="text-lg text-gray-500 dark:text-slate-400">Görselleştirme için lütfen bilgileri girin.</p>
              </div>
            )}
          </div>
        </div>
      </main>

      <footer className="mt-12 text-center text-sm text-gray-500 dark:text-slate-500 p-8">
        © 2024 Mühendis & Müteahhit Proje Yazılımı | T.C. Mevzuatlarına Uygundur
      </footer>
    </div>
  );
};

export default App;

import React from 'react';

interface HeaderProps {
  darkMode: boolean;
  setDarkMode: (val: boolean) => void;
}

const Header: React.FC<HeaderProps> = ({ darkMode, setDarkMode }) => {
  return (
    <header className="sticky top-0 z-50 bg-white/80 dark:bg-slate-900/80 backdrop-blur-md border-b border-gray-200 dark:border-slate-800 shadow-sm">
      <div className="container mx-auto px-4 h-16 flex items-center justify-between">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 bg-blue-600 rounded-lg flex items-center justify-center shadow-lg shadow-blue-500/30">
            <i className="fa-solid fa-compass-drafting text-white text-xl"></i>
          </div>
          <div>
            <h1 className="font-bold text-lg leading-tight">İnşaat Proje <span className="text-blue-600">Asistanı</span></h1>
            <p className="text-[10px] uppercase tracking-wider text-gray-500 font-bold">Mühendis & Müteahhit Portalı</p>
          </div>
        </div>

        <button
          onClick={() => setDarkMode(!darkMode)}
          className="p-2 w-10 h-10 rounded-full bg-gray-100 dark:bg-slate-800 hover:bg-gray-200 dark:hover:bg-slate-700 transition-all flex items-center justify-center border border-gray-200 dark:border-slate-700"
        >
          {darkMode ? (
            <i className="fa-solid fa-sun text-yellow-400"></i>
          ) : (
            <i className="fa-solid fa-moon text-indigo-600"></i>
          )}
        </button>
      </div>
