export default Header;

import React, { useState } from 'react';
import { NizamType, ArsaBilgileri } from '../types';

interface ConstructionFormProps {
  onCalculate: (data: ArsaBilgileri) => void;
}

const ConstructionForm: React.FC<ConstructionFormProps> = ({ onCalculate }) => {
  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState<Partial<ArsaBilgileri>>({
    alan: 400,
    nizam: NizamType.AYRIK,
    daireSayisiTercihi: 4,
    taks: 0.3,
    katAdedi: 3,
    cekmeOn: 5,
    cekmeYan: 3,
    cekmeArka: 5
  });

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: name === 'nizam' ? value : (isNaN(Number(value)) ? value : Number(value))
    }));
  };

  const nextStep = () => setStep(s => s + 1);
  const prevStep = () => setStep(s => s - 1);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (formData.nizam === NizamType.BITISIK) {
      alert("Şu an sadece Ayrık Nizam hesaplamaları desteklenmektedir.");
      return;
    }
    onCalculate(formData as ArsaBilgileri);
  };

  const InputField = ({ label, name, type = "text", placeholder = "", icon = "" }: any) => (
    <div className="space-y-1">
      <label className="text-xs font-bold text-gray-500 dark:text-slate-400 uppercase">{label}</label>
      <div className="relative">
        {icon && <i className={`fa-solid ${icon} absolute left-3 top-1/2 -translate-y-1/2 text-gray-400`}></i>}
        <input
          type={type}
          name={name}
          value={(formData as any)[name] || ''}
          onChange={handleChange}
          placeholder={placeholder}
          required
          className={`w-full bg-gray-50 dark:bg-slate-900 border border-gray-200 dark:border-slate-700 rounded-lg py-2 ${icon ? 'pl-10' : 'px-4'} pr-4 focus:ring-2 focus:ring-blue-500 focus:border-transparent outline-none transition-all`}
        />
      </div>
    </div>
  );

  return (
    <form onSubmit={handleSubmit} className="space-y-6">
      {step === 1 && (
        <div className="space-y-4 animate-in fade-in duration-500">
          <div className="grid grid-cols-2 gap-4">
            <InputField label="Arsa Alanı (m²)" name="alan" type="number" icon="fa-chart-area" />
            <div className="space-y-1">
              <label className="text-xs font-bold text-gray-500 dark:text-slate-400 uppercase">Nizam Tipi</label>
              <select 
                name="nizam" 
                value={formData.nizam} 
                onChange={handleChange}
                className="w-full bg-gray-50 dark:bg-slate-900 border border-gray-200 dark:border-slate-700 rounded-lg py-2 px-4 outline-none focus:ring-2 focus:ring-blue-500"
              >
                <option value={NizamType.AYRIK}>Ayrık Nizam</option>
                <option value={NizamType.BITISIK}>Bitişik Nizam</option>
              </select>
            </div>
          </div>
          <div className="grid grid-cols-2 gap-4">
            <InputField label="İl" name="il" icon="fa-city" placeholder="Örn: İstanbul" />
            <InputField label="İlçe" name="ilce" icon="fa-building" placeholder="Örn: Kadıköy" />
          </div>
          <div className="grid grid-cols-3 gap-4">
            <InputField label="Mahalle" name="mahalle" placeholder="Örn: Moda" />
            <InputField label="Ada" name="ada" type="text" placeholder="101" />
            <InputField label="Parsel" name="parsel" type="text" placeholder="5" />
          </div>
          <button 
            type="button" 
            onClick={nextStep}
            className="w-full bg-blue-600 hover:bg-blue-700 text-white font-bold py-3 rounded-xl transition-all shadow-lg shadow-blue-500/30 flex items-center justify-center gap-2"
          >
            İmar Detaylarına Geç <i className="fa-solid fa-arrow-right"></i>
          </button>
        </div>
      )}

      {step === 2 && (
        <div className="space-y-4 animate-in slide-in-from-right duration-500">
          <div className="grid grid-cols-3 gap-4">
            <InputField label="Ön Çekme (m)" name="cekmeOn" type="number" />
            <InputField label="Yan Çekme (m)" name="cekmeYan" type="number" />
            <InputField label="Arka Çekme (m)" name="cekmeArka" type="number" />
          </div>
          <div className="grid grid-cols-2 gap-4">
            <InputField label="TAKS Değeri" name="taks" type="number" step="0.01" />
            <InputField label="Kat Adedi" name="katAdedi" type="number" />
          </div>
          <div className="space-y-1">
            <label className="text-xs font-bold text-gray-500 dark:text-slate-400 uppercase">Bir Katta Kaç Daire Olsun?</label>
            <div className="grid grid-cols-4 gap-2">
              {[1, 2, 3, 4].map(num => (
                <button
                  key={num}
                  type="button"
                  onClick={() => setFormData(p => ({ ...p, daireSayisiTercihi: num }))}
                  className={`py-2 rounded-lg border font-bold transition-all ${
                    formData.daireSayisiTercihi === num 
                      ? 'bg-blue-600 border-blue-600 text-white shadow-md' 
                      : 'bg-white dark:bg-slate-900 border-gray-200 dark:border-slate-700 text-gray-600 dark:text-slate-300'
                  }`}
                >
                  {num}
                </button>
              ))}
            </div>
          </div>
          <div className="flex gap-4">
            <button 
              type="button" 
              onClick={prevStep}
              className="flex-1 bg-gray-200 dark:bg-slate-700 hover:bg-gray-300 dark:hover:bg-slate-600 text-gray-700 dark:text-white font-bold py-3 rounded-xl transition-all"
            >
              Geri
            </button>
            <button 
              type="submit"
              className="flex-[2] bg-emerald-600 hover:bg-emerald-700 text-white font-bold py-3 rounded-xl transition-all shadow-lg shadow-emerald-500/30 flex items-center justify-center gap-2"
            >
              Hesapla ve Çiz <i className="fa-solid fa-calculator"></i>
            </button>
          </div>
        </div>
      )}
    </form>
  );
};

export default ConstructionForm;

import React from 'react';
import { ArsaBilgileri, HesapSonuclari } from '../types';

interface PlotVisualizerProps {
  data: ArsaBilgileri;
  results: HesapSonuclari | null;
}

const PlotVisualizer: React.FC<PlotVisualizerProps> = ({ data, results }) => {
  // Basit bir dikdörtgen arsa varsayımıyla (Alan = W * H)
  // W/H oranını koruyarak görselleştirme
  const scale = 5; // m to pixel
  const arsaW = Math.sqrt(data.alan) * 1.2;
  const arsaH = data.alan / arsaW;

  const width = arsaW * scale;
  const height = arsaH * scale;

  const padding = 60;
  const svgW = width + padding * 2;
  const svgH = height + padding * 2;

  // Çekme mesafeleri
  const front = data.cekmeOn * scale;
  const side = data.cekmeYan * scale;
  const rear = data.cekmeArka * scale;

  // Bina alanı (basitleştirilmiş dikdörtgen)
  const bldgW = width - (side * 2);
  const bldgH = height - front - rear;

  const tkgmUrl = `https://parselsorgu.tkgm.gov.tr/#tip=ada&il=${data.il || ''}&ilce=${data.ilce || ''}&mahalle=${data.mahalle || ''}&ada=${data.ada || ''}&parsel=${data.parsel || ''}`;

  return (
    <div className="bg-white dark:bg-slate-800 rounded-2xl shadow-xl overflow-hidden border border-gray-200 dark:border-slate-700">
      <div className="p-4 border-b border-gray-100 dark:border-slate-700 flex justify-between items-center bg-gray-50/50 dark:bg-slate-900/50">
        <h3 className="font-bold text-sm uppercase tracking-wider text-slate-500 dark:text-slate-400">Vaziyet Planı Taslağı</h3>
        <a 
          href={tkgmUrl} 
          target="_blank" 
          rel="noopener noreferrer"
          className="text-xs bg-blue-100 dark:bg-blue-900/30 text-blue-600 dark:text-blue-400 px-3 py-1 rounded-full font-bold hover:bg-blue-600 hover:text-white transition-all flex items-center gap-1"
        >
          TKGM'de Gör <i className="fa-solid fa-external-link text-[10px]"></i>
        </a>
      </div>

      <div className="p-6 flex justify-center items-center overflow-auto bg-[radial-gradient(#e5e7eb_1px,transparent_1px)] dark:bg-[radial-gradient(#1e293b_1px,transparent_1px)] [background-size:20px_20px]">
        <svg width={svgW} height={svgH} viewBox={`0 0 ${svgW} ${svgH}`} className="drop-shadow-2xl">
          {/* Arsa Dış Sınırları */}
          <rect 
            x={padding} 
            y={padding} 
            width={width} 
            height={height} 
            fill="none" 
            stroke="currentColor" 
            strokeWidth="3"
            className="text-slate-400 dark:text-slate-500"
          />

          {/* Çekme Çizgileri - Front */}
          <line 
            x1={padding} y1={padding + front} 
            x2={padding + width} y2={padding + front} 
            strokeDasharray="5,5" stroke="gray" 
          />
          {/* Çekme Çizgileri - Sides */}
          <line 
            x1={padding + side} y1={padding} 
            x2={padding + side} y2={padding + height} 
            strokeDasharray="5,5" stroke="gray" 
          />
          <line 
            x1={padding + width - side} y1={padding} 
            x2={padding + width - side} y2={padding + height} 
            strokeDasharray="5,5" stroke="gray" 
          />
          {/* Çekme Çizgileri - Rear */}
          <line 
            x1={padding} y1={padding + height - rear} 
            x2={padding + width} y2={padding + height - rear} 
            strokeDasharray="5,5" stroke="gray" 
          />

          {/* Ölçü Okları ve Yazılar */}
          <text x={padding + width/2} y={padding - 10} textAnchor="middle" className="text-[10px] font-bold fill-slate-400">ARSA GENİŞLİĞİ: {arsaW.toFixed(1)}m</text>
          <text x={padding - 10} y={padding + height/2} textAnchor="middle" transform={`rotate(-90, ${padding-10}, ${padding + height/2})`} className="text-[10px] font-bold fill-slate-400">ARSA DERİNLİĞİ: {arsaH.toFixed(1)}m</text>

          {/* Çekme Mesafesi Yazıları */}
          <text x={padding + width/2} y={padding + front/2} textAnchor="middle" className="text-[10px] italic fill-blue-500">Ön Çekme: {data.cekmeOn}m</text>
          <text x={padding + side/2} y={padding + height/2} textAnchor="middle" transform={`rotate(-90, ${padding + side/2}, ${padding + height/2})`} className="text-[10px] italic fill-blue-500">Yan: {data.cekmeYan}m</text>

          {/* Bina Oturumu */}
          {results && (
            <g>
              <rect 
                x={padding + side} 
                y={padding + front} 
                width={bldgW} 
                height={bldgH} 
                className="fill-blue-500/20 stroke-blue-600"
                strokeWidth="2"
              />
              <text 
                x={padding + width/2} 
                y={padding + front + bldgH/2} 
                textAnchor="middle" 
                className="fill-blue-600 font-bold text-sm"
              >
                BİNA OTURUM ALANI
              </text>
              <text 
                x={padding + width/2} 
                y={padding + front + bldgH/2 + 15} 
                textAnchor="middle" 
                className="fill-blue-600 text-[10px]"
              >
                ~{results.tabanAlani.toFixed(2)} m²
              </text>
            </g>
          )}
        </svg>
      </div>

      <div className="p-4 text-xs text-gray-500 dark:text-slate-400 italic bg-gray-50 dark:bg-slate-900/30">
        * Görselleştirme temsilidir. Kesin sonuçlar için profesyonel mimari proje gereklidir.
      </div>
    </div>
  );
};

export default PlotVisualizer;

import React from 'react';
import { HesapSonuclari, ArsaBilgileri } from '../types';

interface ResultsPanelProps {
  results: HesapSonuclari;
  data: ArsaBilgileri;
}

const ResultsPanel: React.FC<ResultsPanelProps> = ({ results, data }) => {
  const StatItem = ({ label, value, unit = "", subValue = "" }: any) => (
    <div className="bg-gray-50 dark:bg-slate-900 p-4 rounded-xl border border-gray-100 dark:border-slate-800">
      <p className="text-[10px] font-bold text-gray-400 dark:text-slate-500 uppercase mb-1">{label}</p>
      <div className="flex items-baseline gap-1">
        <span className="text-xl font-bold text-slate-800 dark:text-white">{value}</span>
        <span className="text-xs font-medium text-gray-500">{unit}</span>
      </div>
      {subValue && <p className="text-[10px] text-blue-500 mt-1 font-medium">{subValue}</p>}
    </div>
  );

  return (
    <div className="bg-white dark:bg-slate-800 rounded-2xl shadow-xl p-6 border border-gray-200 dark:border-slate-700">
      <h3 className="text-lg font-bold mb-6 flex items-center gap-2">
        <i className="fa-solid fa-square-poll-vertical text-emerald-500"></i>
        Mühendislik Hesap Özeti
      </h3>

      <div className="grid grid-cols-2 gap-4">
        <StatItem label="Toplam Kat" value={results.toplamKat} subValue="Bodrum + Zemin + Normal" />
        <StatItem label="Hesaplanan KAKS" value={results.kaks.toFixed(2)} subValue={`${data.taks} x ${data.katAdedi}`} />
        <StatItem label="Taban Alanı" value={results.tabanAlani.toFixed(1)} unit="m²" />
        <StatItem label="Zemin Kat Brüt" value={results.zeminBrut.toFixed(1)} unit="m²" subValue="Taban Alanı x 1.1" />
        <StatItem label="Normal Kat Brüt" value={results.normalKatBrut.toFixed(1)} unit="m²" subValue="Zemin Brüt x 1.15" />
        <StatItem label="Daire Başı Alan" value={results.daireBasiMetrekare.toFixed(1)} unit="m²" subValue={`Kat Başı ${data.daireSayisiTercihi} Daire`} />
      </div>

      <div className="mt-6 p-5 bg-blue-600 rounded-2xl text-white shadow-lg shadow-blue-500/30">
        <div className="flex items-center justify-between mb-2">
          <span className="text-xs font-bold uppercase tracking-widest opacity-80">Önerilen Tipoloji</span>
          <i className="fa-solid fa-house-circle-check text-2xl"></i>
        </div>
        <p className="text-2xl font-bold mb-1">{results.daireTipi}</p>
        <p className="text-sm opacity-90 leading-relaxed">
          Arsanızın imar şartlarına göre her katta <b>{data.daireSayisiTercihi} adet</b> daire yapılması durumunda 
          projede en verimli sonuç <b>{results.daireTipi}</b> planıdır.
        </p>
      </div>

      <div className="mt-6 grid grid-cols-1 gap-3">
        <div className="flex items-center gap-3 p-3 bg-amber-50 dark:bg-amber-900/20 border border-amber-100 dark:border-amber-900/40 rounded-xl text-amber-700 dark:text-amber-400">
          <i className="fa-solid fa-circle-info text-xl"></i>
          <p className="text-xs leading-tight">
            Bodrum kat emsal dışı bırakılmıştır. Çekme mesafeleri ve TAKS hesabı minimum standartlara göre optimize edilmiştir.
          </p>
        </div>
      </div>
    </div>
  );
};

export default ResultsPanel;

import React, { useState } from 'react';
import { NizamType, ArsaBilgileri } from '../types';

interface InputFieldProps {
  label: string;
  name: string;
  value: any;
  onChange: (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => void;
  type?: string;
  placeholder?: string;
  icon?: string;
  step?: string;
}

const InputField: React.FC<InputFieldProps> = ({ label, name, value, onChange, type = "text", placeholder = "", icon = "", step }) => (
  <div className="space-y-1">
    <label className="text-xs font-bold text-gray-500 dark:text-slate-400 uppercase">{label}</label>
    <div className="relative">
      {icon && <i className={`fa-solid ${icon} absolute left-3 top-1/2 -translate-y-1/2 text-gray-400`}></i>}
      <input
        type={type}
        name={name}
        value={value ?? ''}
        onChange={onChange}
        placeholder={placeholder}
        step={step}
        required
        className={`w-full bg-gray-50 dark:bg-slate-900 border border-gray-200 dark:border-slate-700 rounded-lg py-2 ${icon ? 'pl-10' : 'px-4'} pr-4 focus:ring-2 focus:ring-blue-500 focus:border-transparent outline-none transition-all`}
      />
    </div>
  </div>
);

interface ConstructionFormProps {
  onCalculate: (data: ArsaBilgileri) => void;
}

const ConstructionForm: React.FC<ConstructionFormProps> = ({ onCalculate }) => {
  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState<any>({
    alan: '400',
    nizam: NizamType.AYRIK,
    daireSayisiTercihi: 4,
    taks: '0.3',
    katAdedi: '3',
    cekmeOn: '5',
