  const handleUsakSearch = async () => {
    if (!formData.mahalle || !formData.ada || !formData.parsel) {
      alert("Lütfen Mahalle, Ada ve Parsel bilgilerini giriniz.");
      return;
    }
    const result = await onSearchUsak(formData.mahalle, formData.ada, formData.parsel);
    if (result) {
      setFormData((prev: any) => ({
        ...prev,
        taks: result.taks || prev.taks,
        katAdedi: result.kat || prev.katAdedi,
        cekmeOn: result.onCekme || prev.cekmeOn,
        cekmeYan: result.yanCekme || prev.cekmeYan,
        cekmeArka: result.arkaCekme || prev.cekmeArka
      }));
      alert("İmar bilgileri başarıyla güncellendi.");
    } else {
      alert("Sistemde kayıt bulunamadı veya bir hata oluştu. Lütfen manuel giriniz.");
    }
  };

  const nextStep = () => setStep(s => s + 1);
  const prevStep = () => setStep(s => s - 1);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (formData.nizam === NizamType.BITISIK) {
      alert("Şu an sadece Ayrık Nizam hesaplamaları desteklenmektedir.");
