      cekmeYan: formData.cekmeYan ? Number(formData.cekmeYan) : undefined,
      cekmeArka: formData.cekmeArka ? Number(formData.cekmeArka) : undefined,
      taks: Number(formData.taks),
      katAdedi: Number(formData.katAdedi),
      daireSayisiTercihi: Number(formData.daireSayisiTercihi)
