              }`}
            >
              {isSearching ? (
                <> <i className="fa-solid fa-spinner fa-spin"></i> KEOS Sorgulanıyor... </>
              ) : (
                <> <i className="fa-solid fa-search-location"></i> Uşak İmar Bilgisini KEOS'tan Getir </>
              )}
            </button>
          )}

          <button 
            type="button" 
            onClick={nextStep}
            className="w-full bg-blue-600 hover:bg-blue-700 text-white font-bold py-3 rounded-xl transition-all shadow-lg shadow-blue-500/30 flex items-center justify-center gap-2"
          >
            İmar Detaylarına Geç <i className="fa-solid fa-arrow-right"></i>
          </button>
        </div>
      )}

      {step === 2 && (
        <div className="space-y-4 animate-in slide-in-from-right duration-500">
          <div className="grid grid-cols-3 gap-4">
            <InputField label="Ön Çekme (m)" name="cekmeOn" type="number" value={formData.cekmeOn} onChange={handleChange} required={false} />
            <InputField label="Yan Çekme (m)" name="cekmeYan" type="number" value={formData.cekmeYan} onChange={handleChange} required={false} />
            <InputField label="Arka Çekme (m)" name="cekmeArka" type="number" value={formData.cekmeArka} onChange={handleChange} required={false} />
          </div>
          <div className="grid grid-cols-2 gap-4">
            <InputField label="TAKS Değeri" name="taks" type="number" step="0.01" value={formData.taks} onChange={handleChange} />
            <InputField label="Kat Adedi" name="katAdedi" type="number" value={formData.katAdedi} onChange={handleChange} />
          </div>
          <div className="space-y-1">
            <label className="text-xs font-bold text-gray-500 dark:text-slate-400 uppercase">Bir Katta Kaç Daire Olsun?</label>
            <div className="grid grid-cols-4 gap-2">
              {[1, 2, 3, 4].map(num => (
                <button
                  key={num}
                  type="button"
                  onClick={() => setFormData((p: any) => ({ ...p, daireSayisiTercihi: num }))}
                  className={`py-2 rounded-lg border font-bold transition-all ${
                    formData.daireSayisiTercihi === num 
                      ? 'bg-blue-600 border-blue-600 text-white shadow-md' 
                      : 'bg-white dark:bg-slate-900 border-gray-200 dark:border-slate-700 text-gray-600 dark:text-slate-300'
                  }`}
                >
                  {num}
                </button>
              ))}
            </div>
          </div>
          <div className="flex gap-4">
            <button 
              type="button" 
              onClick={prevStep}
              className="flex-1 bg-gray-200 dark:bg-slate-700 hover:bg-gray-300 dark:hover:bg-slate-600 text-gray-700 dark:text-white font-bold py-3 rounded-xl transition-all"
