import React, { useState, useEffect } from 'react';
import { NizamType, ArsaBilgileri, HesapSonuclari } from './types';
import ConstructionForm from './components/ConstructionForm';
import PlotVisualizer from './components/PlotVisualizer';
import ResultsPanel from './components/ResultsPanel';
import Header from './components/Header';
import { GoogleGenAI } from "@google/genai";

const App: React.FC = () => {
  const [darkMode, setDarkMode] = useState(true);
  const [formData, setFormData] = useState<ArsaBilgileri | null>(null);
  const [results, setResults] = useState<HesapSonuclari | null>(null);
  const [isSearching, setIsSearching] = useState(false);

  useEffect(() => {
    if (darkMode) {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [darkMode]);

  const fetchUsakImarData = async (mahalle: string, ada: string, parsel: string) => {
    setIsSearching(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      // KEOS sorgusu için optimize edilmiş prompt
      const prompt = `Uşak ili, ${mahalle} mahallesi, Ada: ${ada}, Parsel: ${parsel} için Uşak Belediyesi KEOS imar portalını (https://keos.usak.bel.tr/imardurumu/index.aspx) sorgula. 
      Lütfen şu teknik imar bilgilerini bulmaya çalış: TAKS, KAKS, Kat Adedi (Hmax), Ön Çekme, Yan Çekme, Arka Çekme. 
      Bulduğun sonuçları JSON formatında şu anahtarlarla döndür: taks, kaks, kat, onCekme, yanCekme, arkaCekme. 
      Sadece rakam içeren JSON döndür, açıklama yapma. Bilgi yoksa 0 döndür.`;

      const response = await ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: prompt,
        config: {
          tools: [{ googleSearch: {} }],
        },
      });

      const text = response.text || "";
      const jsonMatch = text.match(/\{.*\}/s);
      if (jsonMatch) {
        return JSON.parse(jsonMatch[0]);
      }
      return null;
    } catch (error) {
      console.error("KEOS sorgu hatası:", error);
      return null;
    } finally {
      setIsSearching(false);
    }
  };

  const calculateData = (data: ArsaBilgileri) => {
    const on = data.cekmeOn || 0;
    const yan = data.cekmeYan || 0;
    const arka = data.cekmeArka || 0;

    const kaks = data.taks * data.katAdedi;
    const tabanAlani = data.alan * data.taks;
    const zeminBrut = tabanAlani * 1.1;
    const normalKatBrut = zeminBrut * 1.15;
    const daireBasiMetrekare = normalKatBrut / data.daireSayisiTercihi;

    let daireTipi = "4+1 veya daha büyük";
    if (daireBasiMetrekare < 105) {
      daireTipi = "1+1 Apart";
    } else if (daireBasiMetrekare >= 105 && daireBasiMetrekare < 115) {
      daireTipi = "2+1 Daire";
    } else if (daireBasiMetrekare >= 115 && daireBasiMetrekare < 150) {
      daireTipi = "3+1 Daire";
    }

    setResults({
      kaks,
      tabanAlani,
      zeminBrut,
      normalKatBrut,
      toplamKat: data.katAdedi + 1,
      daireTipi,
      daireBasiMetrekare
    });
    setFormData(data);
  };

  return (
    <div className="min-h-screen pb-12 transition-colors duration-300 bg-gray-50 dark:bg-slate-900 text-slate-900 dark:text-slate-100">
      <Header darkMode={darkMode} setDarkMode={setDarkMode} />

      <main className="container mx-auto px-4 mt-8 max-w-6xl">
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
          <div className="space-y-6">
            <section className="bg-white dark:bg-slate-800 p-6 rounded-2xl shadow-xl border border-gray-200 dark:border-slate-700">
              <h2 className="text-xl font-bold mb-6 flex items-center gap-2">
                <i className="fa-solid fa-hard-hat text-blue-500"></i>
                Arsa ve Proje Bilgileri
              </h2>
              <ConstructionForm 
                onCalculate={calculateData} 
                onSearchUsak={fetchUsakImarData} 
                isSearching={isSearching}
              />
            </section>

            {results && formData && (
              <div className="block lg:hidden">
                <ResultsPanel results={results} data={formData} />
              </div>
            )}
          </div>

          <div className="space-y-6">
            {formData ? (
              <>
                <PlotVisualizer data={formData} results={results} />
                <div className="hidden lg:block">
                  {results && <ResultsPanel results={results} data={formData} />}
                </div>
              </>
            ) : (
              <div className="h-full flex flex-col items-center justify-center p-12 bg-white dark:bg-slate-800 rounded-2xl border-2 border-dashed border-gray-300 dark:border-slate-700 text-center">
                <i className="fa-solid fa-map-location-dot text-6xl text-gray-300 dark:text-slate-600 mb-4"></i>
                <p className="text-lg text-gray-500 dark:text-slate-400">Görselleştirme için lütfen bilgileri girin.</p>
              </div>
            )}
          </div>
        </div>
      </main>

      <footer className="mt-12 text-center text-sm text-gray-500 dark:text-slate-500 p-8">
        © 2024 Mühendis & Müteahhit Proje Yazılımı | T.C. Mevzuatlarına Uygundur
      </footer>
    </div>
  );
};

