import React from 'react';
import { ArsaBilgileri, HesapSonuclari } from '../types';

interface PlotVisualizerProps {
  data: ArsaBilgileri;
  results: HesapSonuclari | null;
  id?: string;
}

const PlotVisualizer: React.FC<PlotVisualizerProps> = ({ data, results, id }) => {
  // Ölçek ve boyutlar artırıldı (Görseli daha büyük yapmak için)
  const scale = 8; // m to pixel (önceden 5 idi)
  const arsaW = Math.sqrt(data.alan) * 1.2;
  const arsaH = data.alan / arsaW;

  const width = arsaW * scale;
  const height = arsaH * scale;

  const padding = 100; // Yazılar için padding artırıldı
  const svgW = width + padding * 2;
  const svgH = height + padding * 2;

  // Çekme mesafeleri (varsayılan 0)
  const front = (data.cekmeOn || 0) * scale;
  const side = (data.cekmeYan || 0) * scale;
  const rear = (data.cekmeArka || 0) * scale;

  // Bina alanı
  const bldgW = width - (side * 2);
  const bldgH = height - front - rear;

  const tkgmUrl = `https://parselsorgu.tkgm.gov.tr/#tip=ada&il=${data.il || ''}&ilce=${data.ilce || ''}&mahalle=${data.mahalle || ''}&ada=${data.ada || ''}&parsel=${data.parsel || ''}`;

  return (
    <div id={id} className="bg-white dark:bg-slate-800 rounded-2xl shadow-xl overflow-hidden border border-gray-200 dark:border-slate-700 transition-all">
      <div className="p-4 border-b border-gray-100 dark:border-slate-700 flex justify-between items-center bg-gray-50/50 dark:bg-slate-900/50">
        <h3 className="font-bold text-sm uppercase tracking-wider text-slate-500 dark:text-slate-400">Vaziyet Planı Taslağı</h3>
        <a 
          href={tkgmUrl} 
          target="_blank" 
          rel="noopener noreferrer"
          className="text-xs bg-blue-100 dark:bg-blue-900/30 text-blue-600 dark:text-blue-400 px-3 py-1 rounded-full font-bold hover:bg-blue-600 hover:text-white transition-all flex items-center gap-1"
        >
          TKGM'de Gör <i className="fa-solid fa-external-link text-[10px]"></i>
        </a>
      </div>

      <div className="p-8 flex justify-center items-center overflow-auto bg-[radial-gradient(#e5e7eb_1px,transparent_1px)] dark:bg-[radial-gradient(#1e293b_1px,transparent_1px)] [background-size:30px_30px]">
        <svg width={svgW} height={svgH} viewBox={`0 0 ${svgW} ${svgH}`} className="drop-shadow-2xl">
          {/* Arsa Dış Sınırları */}
          <rect 
            x={padding} 
            y={padding} 
            width={width} 
            height={height} 
            fill="none" 
            stroke="currentColor" 
            strokeWidth="4"
            className="text-slate-400 dark:text-slate-500"
          />

          {/* Çekme Çizgileri - Front */}
          <line 
            x1={padding} y1={padding + front} 
            x2={padding + width} y2={padding + front} 
            strokeDasharray="8,8" stroke="#3b82f6" strokeWidth="1"
          />
          {/* Çekme Çizgileri - Sides */}
          <line 
            x1={padding + side} y1={padding} 
            x2={padding + side} y2={padding + height} 
            strokeDasharray="8,8" stroke="#3b82f6" strokeWidth="1"
          />
          <line 
            x1={padding + width - side} y1={padding} 
            x2={padding + width - side} y2={padding + height} 
            strokeDasharray="8,8" stroke="#3b82f6" strokeWidth="1"
          />
          {/* Çekme Çizgileri - Rear */}
          <line 
            x1={padding} y1={padding + height - rear} 
            x2={padding + width} y2={padding + height - rear} 
            strokeDasharray="8,8" stroke="#3b82f6" strokeWidth="1"
          />

          {/* Ölçü Okları ve Yazılar - Arsa Boyutları (Büyütüldü) */}
          <text x={padding + width/2} y={padding - 20} textAnchor="middle" className="text-sm font-bold fill-slate-500 dark:fill-slate-400">ARSA GENİŞLİĞİ: {arsaW.toFixed(1)}m</text>
          <text x={padding - 25} y={padding + height/2} textAnchor="middle" transform={`rotate(-90, ${padding-25}, ${padding + height/2})`} className="text-sm font-bold fill-slate-500 dark:fill-slate-400">ARSA DERİNLİĞİ: {arsaH.toFixed(1)}m</text>

          {/* Çekme Mesafesi Yazıları (Büyütüldü) */}
          {data.cekmeOn! > 0 && <text x={padding + width/2} y={padding + front/2 + 5} textAnchor="middle" className="text-xs font-semibold fill-blue-600">Ön: {data.cekmeOn}m</text>}
          {data.cekmeYan! > 0 && <text x={padding + side/2} y={padding + height/2} textAnchor="middle" transform={`rotate(-90, ${padding + side/2}, ${padding + height/2})`} className="text-xs font-semibold fill-blue-600">Yan: {data.cekmeYan}m</text>}

          {/* Bina Oturumu */}
          {results && (
            <g>
              <rect 
                x={padding + side} 
                y={padding + front} 
                width={bldgW} 
                height={bldgH} 
                className="fill-blue-500/15 stroke-blue-600"
                strokeWidth="3"
              />
              <text 
                x={padding + width/2} 
                y={padding + front + bldgH/2 - 5} 
                textAnchor="middle" 
                className="fill-blue-700 font-bold text-base uppercase"
              >
                BİNA OTURUMU
              </text>
              <text 
                x={padding + width/2} 
                y={padding + front + bldgH/2 + 20} 
                textAnchor="middle" 
                className="fill-blue-700 font-bold text-sm"
              >
                {results.tabanAlani.toFixed(1)} m²
              </text>
            </g>
          )}
        </svg>
      </div>

      <div className="p-4 text-xs text-gray-500 dark:text-slate-400 font-medium italic bg-gray-50 dark:bg-slate-900/30 border-t border-gray-100 dark:border-slate-700">
        * Vaziyet planı, girilen çekme mesafelerine ve TAKS değerine göre ölçekli olarak oluşturulmuştur.
      </div>
    </div>
  );
};

export default PlotVisualizer;

