      // @ts-ignore
      const canvas = await html2canvas(reportElement, {
        scale: 2, // Daha yüksek kalite
        useCORS: true,
        backgroundColor: document.documentElement.classList.contains('dark') ? '#0f172a' : '#f8fafc',
        logging: false
      });

