      const link = document.createElement('a');
      link.href = image;
      link.download = `Proje_Raporu_${data.ada}_${data.parsel}.png`;
      link.click();
    } catch (err) {
      console.error("İndirme hatası:", err);
      alert("Rapor indirilirken bir hata oluştu.");
