            className={`flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-bold transition-all shadow-md ${
              isDownloading 
              ? 'bg-gray-100 text-gray-400 cursor-not-allowed' 
              : 'bg-indigo-600 text-white hover:bg-indigo-700 shadow-indigo-500/20'
            }`}
          >
            {isDownloading ? (
              <> <i className="fa-solid fa-spinner fa-spin"></i> Hazırlanıyor... </>
            ) : (
              <> <i className="fa-solid fa-file-export"></i> Raporu İndir (PNG) </>
            )}
          </button>
        </div>

        <div className="grid grid-cols-2 gap-4">
          <StatItem label="Toplam Kat" value={results.toplamKat} subValue="Bodrum + Zemin + Normal" />
          <StatItem label="Hesaplanan KAKS" value={results.kaks.toFixed(2)} subValue="TAKS x Kat Adedi" />
          <StatItem label="Taban Alanı" value={results.tabanAlani.toFixed(1)} unit="m²" />
