          <StatItem label="Normal Kat Brüt" value={results.normalKatBrut.toFixed(1)} unit="m²" />
          <StatItem label="Daire Başı Brüt Alan" value={results.daireBasiMetrekare.toFixed(1)} unit="m² Brüt" subValue={`Kat Başı ${data.daireSayisiTercihi} Daire`} />
        </div>

        <div className="mt-6 p-5 bg-blue-600 rounded-2xl text-white shadow-lg shadow-blue-500/30">
          <div className="flex items-center justify-between mb-2">
            <span className="text-xs font-bold uppercase tracking-widest opacity-80">Önerilen Tipoloji</span>
            <i className="fa-solid fa-house-circle-check text-2xl"></i>
          </div>
          <p className="text-2xl font-bold mb-1">{results.daireTipi}</p>
          <p className="text-sm opacity-90 leading-relaxed">
            Arsanızın imar şartlarına göre her katta <b>{data.daireSayisiTercihi} adet</b> daire yapılması durumunda 
            projede en verimli sonuç <b>{results.daireTipi}</b> planıdır.
          </p>
        </div>
      </div>

      {/* Görünmez veya İndirme İçin Hazırlanmış İnfografik Şablonu (Opsiyonel: Eğer özel bir tasarım istenirse burası genişletilebilir) */}
    </div>
  );
};

