  icon = "", step, required = true, keosError = false 
}) => (
  <div className="space-y-1">
    <div className="flex justify-between items-center">
      <label className={`text-xs font-bold uppercase ${keosError ? 'text-red-500' : 'text-gray-500 dark:text-slate-400'}`}>
        {label}
      </label>
      {keosError && (
        <span className="text-[9px] bg-red-100 text-red-600 px-1.5 py-0.5 rounded font-bold animate-pulse">
          KEOS'tan erişilemedi!
        </span>
      )}
      {!required && !keosError && <span className="text-[10px] text-gray-400 italic">(Opsiyonel)</span>}
    </div>
    <div className="relative">
      {icon && <i className={`fa-solid ${icon} absolute left-3 top-1/2 -translate-y-1/2 ${keosError ? 'text-red-400' : 'text-gray-400'}`}></i>}
      <input
        type={type}
        name={name}
        value={value ?? ''}
        onChange={onChange}
        placeholder={placeholder}
        step={step}
        required={required}
        className={`w-full bg-gray-50 dark:bg-slate-900 border rounded-lg py-2 ${icon ? 'pl-10' : 'px-4'} pr-4 focus:ring-2 outline-none transition-all ${
          keosError 
          ? 'border-red-300 focus:ring-red-500 dark:border-red-900/50' 
          : 'border-gray-200 dark:border-slate-700 focus:ring-blue-500'
