interface ConstructionFormProps {
  onCalculate: (data: ArsaBilgileri) => void;
  onSearchUsak: (mahalle: string, ada: string, parsel: string) => Promise<any>;
  isSearching: boolean;
}

const ConstructionForm: React.FC<ConstructionFormProps> = ({ onCalculate, onSearchUsak, isSearching }) => {
  const [step, setStep] = useState(1);
  const [missingKeosFields, setMissingKeosFields] = useState<string[]>([]);
  const [formData, setFormData] = useState<any>({
    alan: '',
    nizam: NizamType.AYRIK,
    daireSayisiTercihi: 4,
    taks: '',
    katAdedi: '',
    cekmeOn: '',
    cekmeYan: '',
    cekmeArka: '',
    il: 'Uşak',
    ilce: '',
    mahalle: '',
    ada: '',
    parsel: ''
  });

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
    const { name, value } = e.target;
    setFormData((prev: any) => ({
      ...prev,
      [name]: value
    }));
    // Manuel müdahale edilirse hata uyarısını kaldır
    if (missingKeosFields.includes(name)) {
      setMissingKeosFields(prev => prev.filter(f => f !== name));
    }
  };

  const handleUsakSearch = async () => {
    if (!formData.mahalle || !formData.ada || !formData.parsel) {
      alert("Lütfen Mahalle, Ada ve Parsel bilgilerini eksiksiz giriniz.");
      return;
    }

    const result = await onSearchUsak(formData.mahalle, formData.ada, formData.parsel);

    if (result) {
      const missing: string[] = [];
      const updatedFields: any = {};

      const checkField = (key: string, keosKey: string) => {
        if (result[keosKey] && result[keosKey] !== 0) {
          updatedFields[key] = result[keosKey].toString();
        } else {
          missing.push(key);
        }
      };

      checkField('alan', 'alan');
      checkField('taks', 'taks');
      checkField('katAdedi', 'kat');
      checkField('cekmeOn', 'onCekme');
      checkField('cekmeYan', 'yanCekme');
      checkField('cekmeArka', 'arkaCekme');

      setFormData((prev: any) => ({ ...prev, ...updatedFields }));
      setMissingKeosFields(missing);

      if (missing.length > 0) {
        alert("Bazı bilgilere KEOS üzerinden erişilemedi. Lütfen eksik alanları kontrol edip manuel doldurunuz.");
      } else {
        alert("Arsa alanı ve tüm imar bilgileri KEOS üzerinden başarıyla güncellendi.");
      }
    } else {
      alert("Sorgulanan Ada/Parsel için KEOS verisi bulunamadı. Lütfen tüm alanları manuel giriniz.");
      setMissingKeosFields(['alan', 'taks', 'katAdedi', 'cekmeOn', 'cekmeYan', 'cekmeArka']);
    }
  };

  const nextStep = () => {
    if (!formData.alan || Number(formData.alan) <= 0) {
      alert("Lütfen geçerli bir Arsa Alanı giriniz.");
      return;
    }
    setStep(s => s + 1);
  }
  const prevStep = () => setStep(s => s - 1);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    const processedData: ArsaBilgileri = {
      ...formData,
      alan: Number(formData.alan),
      cekmeOn: formData.cekmeOn ? Number(formData.cekmeOn) : 0,
      cekmeYan: formData.cekmeYan ? Number(formData.cekmeYan) : 0,
      cekmeArka: formData.cekmeArka ? Number(formData.cekmeArka) : 0,
      taks: Number(formData.taks) || 0.30,
      katAdedi: Number(formData.katAdedi) || 1,
      daireSayisiTercihi: Number(formData.daireSayisiTercihi)
    };

    onCalculate(processedData);
  };

  const isUsak = formData.il?.trim().toLocaleLowerCase('tr-TR') === 'uşak' || formData.il?.trim().toLocaleLowerCase('tr-TR') === 'usak';
  const hasPlotInfo = formData.mahalle && formData.ada && formData.parsel;
  const showUsakButton = isUsak && hasPlotInfo;

  return (
    <form onSubmit={handleSubmit} className="space-y-6">
      {step === 1 && (
        <div className="space-y-4 animate-in fade-in duration-500">
          <div className="grid grid-cols-2 gap-4">
            <InputField 
              label="Arsa Alanı (m²)" 
              name="alan" 
              type="number" 
              value={formData.alan} 
              onChange={handleChange} 
              icon="fa-chart-area" 
              keosError={missingKeosFields.includes('alan')}
            />
            <div className="space-y-1">
              <label className="text-xs font-bold text-gray-500 dark:text-slate-400 uppercase">Nizam Tipi</label>
              <select 
                name="nizam" 
                value={formData.nizam} 
                onChange={handleChange}
                className="w-full bg-gray-50 dark:bg-slate-900 border border-gray-200 dark:border-slate-700 rounded-lg py-2 px-4 outline-none focus:ring-2 focus:ring-blue-500"
              >
                <option value={NizamType.AYRIK}>Ayrık Nizam</option>
                <option value={NizamType.BITISIK}>Bitişik Nizam</option>
              </select>
            </div>
          </div>
          <div className="grid grid-cols-2 gap-4">
            <InputField label="İl" name="il" value={formData.il} onChange={handleChange} icon="fa-city" placeholder="Örn: Uşak" />
            <InputField label="İlçe" name="ilce" value={formData.ilce} onChange={handleChange} icon="fa-building" placeholder="Örn: Merkez" />
          </div>
          <div className="grid grid-cols-3 gap-4">
            <InputField label="Mahalle" name="mahalle" value={formData.mahalle} onChange={handleChange} placeholder="Örn: Atatürk" />
            <InputField label="Ada" name="ada" value={formData.ada} onChange={handleChange} type="text" placeholder="101" />
            <InputField label="Parsel" name="parsel" value={formData.parsel} onChange={handleChange} type="text" placeholder="5" />
          </div>

          {showUsakButton && (
            <button 
              type="button" 
              onClick={handleUsakSearch}
              disabled={isSearching}
              className={`w-full py-3 rounded-lg font-bold text-sm transition-all border flex items-center justify-center gap-2 animate-in zoom-in-95 duration-300 ${
                isSearching 
                ? 'bg-gray-100 text-gray-400 border-gray-200 cursor-not-allowed' 
                : 'bg-emerald-600 text-white border-emerald-500 hover:bg-emerald-700 shadow-lg shadow-emerald-500/20'
              }`}
            >
              {isSearching ? (
                <> <i className="fa-solid fa-circle-notch fa-spin"></i> KEOS Sorgulanıyor... </>
              ) : (
                <> <i className="fa-solid fa-map-marked-alt"></i> Uşak İmar Bilgisini KEOS'tan Getir </>
              )}
            </button>
          )}

          <button 
            type="button" 
            onClick={nextStep}
            className="w-full bg-blue-600 hover:bg-blue-700 text-white font-bold py-3 rounded-xl transition-all shadow-lg shadow-blue-500/30 flex items-center justify-center gap-2"
          >
            İmar Detaylarına Geç <i className="fa-solid fa-arrow-right"></i>
          </button>
        </div>
      )}

      {step === 2 && (
        <div className="space-y-4 animate-in slide-in-from-right duration-500">
          <div className="p-3 bg-blue-50 dark:bg-blue-900/20 border border-blue-100 dark:border-blue-800 rounded-lg">
             <p className="text-[11px] text-blue-700 dark:text-blue-300 leading-tight">
               <i className="fa-solid fa-info-circle mr-1"></i>
               Çekme mesafeleri opsiyoneldir. Bilmiyorsanız boş bırakabilirsiniz (0 kabul edilir). 
               {missingKeosFields.length > 0 && <span className="font-bold"> Kırmızı alanlara KEOS'tan erişilemedi, lütfen doldurun.</span>}
             </p>
          </div>

          <div className="grid grid-cols-3 gap-4">
            <InputField 
              label="Ön Çekme (m)" name="cekmeOn" type="number" 
              value={formData.cekmeOn} onChange={handleChange} 
              required={false} keosError={missingKeosFields.includes('cekmeOn')}
            />
            <InputField 
              label="Yan Çekme (m)" name="cekmeYan" type="number" 
              value={formData.cekmeYan} onChange={handleChange} 
              required={false} keosError={missingKeosFields.includes('cekmeYan')}
            />
            <InputField 
              label="Arka Çekme (m)" name="cekmeArka" type="number" 
              value={formData.cekmeArka} onChange={handleChange} 
              required={false} keosError={missingKeosFields.includes('cekmeArka')}
            />
          </div>
          <div className="grid grid-cols-2 gap-4">
            <InputField 
              label="TAKS Değeri" name="taks" type="number" step="0.01" 
              value={formData.taks} onChange={handleChange} 
              keosError={missingKeosFields.includes('taks')}
            />
            <InputField 
              label="Kat Adedi" name="katAdedi" type="number" 
              value={formData.katAdedi} onChange={handleChange} 
              keosError={missingKeosFields.includes('katAdedi')}
            />
          </div>
          <div className="space-y-1">
            <label className="text-xs font-bold text-gray-500 dark:text-slate-400 uppercase">Bir Katta Kaç Daire Olsun?</label>
            <div className="grid grid-cols-4 gap-2">
              {[1, 2, 3, 4].map(num => (
                <button
                  key={num}
                  type="button"
                  onClick={() => setFormData((p: any) => ({ ...p, daireSayisiTercihi: num }))}
                  className={`py-2 rounded-lg border font-bold transition-all ${
                    formData.daireSayisiTercihi === num 
                      ? 'bg-blue-600 border-blue-600 text-white shadow-md' 
                      : 'bg-white dark:bg-slate-900 border-gray-200 dark:border-slate-700 text-gray-600 dark:text-slate-300'
                  }`}
                >
                  {num}
                </button>
              ))}
            </div>
          </div>
          <div className="flex gap-4">
            <button 
              type="button" 
              onClick={prevStep}
              className="flex-1 bg-gray-200 dark:bg-slate-700 hover:bg-gray-300 dark:hover:bg-slate-600 text-gray-700 dark:text-white font-bold py-3 rounded-xl transition-all"
            >
              Geri
            </button>
            <button 
              type="submit"
              className="flex-[2] bg-emerald-600 hover:bg-emerald-700 text-white font-bold py-3 rounded-xl transition-all shadow-lg shadow-emerald-500/30 flex items-center justify-center gap-2"
            >
              Hesapla ve Çiz <i className="fa-solid fa-calculator"></i>
            </button>
