import React, { useState, useEffect } from 'react';
import { NizamType, ArsaBilgileri, HesapSonuclari } from './types';
import ConstructionForm from './components/ConstructionForm';
import PlotVisualizer from './components/PlotVisualizer';
import ResultsPanel from './components/ResultsPanel';
import Header from './components/Header';
import { GoogleGenAI } from "@google/genai";

const App: React.FC = () => {
  const [darkMode, setDarkMode] = useState(true);
  const [formData, setFormData] = useState<ArsaBilgileri | null>(null);
  const [results, setResults] = useState<HesapSonuclari | null>(null);
  const [isSearching, setIsSearching] = useState(false);

  useEffect(() => {
    if (darkMode) {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [darkMode]);

  const fetchUsakImarData = async (mahalle: string, ada: string, parsel: string) => {
    setIsSearching(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      // Prompt, özellikle T.A.K.S etiketi için optimize edildi
      const prompt = `Uşak ili, ${mahalle} mahallesi, Ada: ${ada}, Parsel: ${parsel} için Uşak Belediyesi KEOS imar portalını (https://keos.usak.bel.tr/imardurumu/index.aspx) sorgula. 
      Lütfen portalda "T.A.K.S" (veya TAKS) yazan yerin hemen yanındaki değeri bulmaya çalış. 
      Ayrıca şu bilgileri de bul: Arsa Alanı (m²), KAKS, Kat Adedi (Hmax), Ön Çekme, Yan Çekme, Arka Çekme. 
      Bulduğun sonuçları JSON formatında şu anahtarlarla döndür: alan, taks, kaks, kat, onCekme, yanCekme, arkaCekme. 
      Sadece rakam içeren JSON döndür, açıklama yapma. Bilgi yoksa 0 döndür.`;

      const response = await ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: prompt,
        config: {
          tools: [{ googleSearch: {} }],
        },
      });

      const text = response.text || "";
      const jsonMatch = text.match(/\{.*\}/s);
      if (jsonMatch) {
        return JSON.parse(jsonMatch[0]);
      }
      return null;
    } catch (error) {
      console.error("KEOS sorgu hatası:", error);
      return null;
    } finally {
      setIsSearching(false);
    }
  };

  const calculateData = (data: ArsaBilgileri) => {
    // KAKS Hesabı: TAKS * Kat Adedi (Resmi bodrumsuz kat adedi)
    const kaks = data.taks * data.katAdedi;
    const tabanAlani = data.alan * data.taks;
    // Zemin Kat Brüt = Taban Alanı * 1.1
    const zeminBrut = tabanAlani * 1.1;
    // Normal Kat Brüt = Zemin Brüt * 1.15
    const normalKatBrut = zeminBrut * 1.15;
    const daireBasiMetrekare = normalKatBrut / data.daireSayisiTercihi;

    let daireTipi = "4+1 veya daha büyük";
    if (daireBasiMetrekare < 105) {
      daireTipi = "1+1 Apart";
    } else if (daireBasiMetrekare >= 105 && daireBasiMetrekare < 115) {
      daireTipi = "2+1 Daire";
    } else if (daireBasiMetrekare >= 115 && daireBasiMetrekare < 150) {
      daireTipi = "3+1 Daire";
    }

    setResults({
      kaks,
      tabanAlani,
      zeminBrut,
      normalKatBrut,
      toplamKat: data.katAdedi + 1, // Bodrum + Kat
      daireTipi,
      daireBasiMetrekare
    });
    setFormData(data);
  };

  return (
    <div className="min-h-screen pb-12 transition-colors duration-300 bg-gray-50 dark:bg-slate-900 text-slate-900 dark:text-slate-100">
      <Header darkMode={darkMode} setDarkMode={setDarkMode} />

      <main className="container mx-auto px-4 mt-8 max-w-6xl">
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
          <div className="space-y-6">
            <section className="bg-white dark:bg-slate-800 p-6 rounded-2xl shadow-xl border border-gray-200 dark:border-slate-700">
              <h2 className="text-xl font-bold mb-6 flex items-center gap-2">
                <i className="fa-solid fa-hard-hat text-blue-500"></i>
                Arsa ve Proje Bilgileri
              </h2>
              <ConstructionForm 
                onCalculate={calculateData} 
                onSearchUsak={fetchUsakImarData} 
                isSearching={isSearching}
              />
            </section>

            {results && formData && (
              <div className="block lg:hidden">
                <ResultsPanel results={results} data={formData} />
              </div>
            )}
          </div>

          <div id="main-report-container" className="space-y-6 p-2 rounded-3xl">
            {formData ? (
              <>
                <div className="bg-white dark:bg-slate-800 p-4 rounded-2xl border border-gray-200 dark:border-slate-700 shadow-sm flex flex-wrap gap-4 items-center">
                   <div className="flex-1 min-w-[150px]">
                      <p className="text-[10px] font-bold text-gray-400 uppercase">Lokasyon</p>
                      <p className="text-sm font-bold">{formData.il} / {formData.ilce} / {formData.mahalle}</p>
                   </div>
                   <div className="flex-1 min-w-[100px]">
                      <p className="text-[10px] font-bold text-gray-400 uppercase">Ada/Parsel</p>
                      <p className="text-sm font-bold">{formData.ada} / {formData.parsel}</p>
                   </div>
                   <div className="flex-1 min-w-[100px]">
                      <p className="text-[10px] font-bold text-gray-400 uppercase">Arsa Alanı</p>
                      <p className="text-sm font-bold">{formData.alan} m²</p>
                   </div>
                </div>

                <PlotVisualizer data={formData} results={results} />
                <div className="hidden lg:block">
                  {results && <ResultsPanel results={results} data={formData} />}
                </div>
              </>
            ) : (
              <div className="h-full flex flex-col items-center justify-center p-12 bg-white dark:bg-slate-800 rounded-2xl border-2 border-dashed border-gray-300 dark:border-slate-700 text-center">
                <i className="fa-solid fa-map-location-dot text-6xl text-gray-300 dark:text-slate-600 mb-4"></i>
                <p className="text-lg text-gray-500 dark:text-slate-400">Görselleştirme için lütfen bilgileri girin.</p>
              </div>
            )}
          </div>
        </div>
      </main>

      <footer className="mt-12 text-center text-sm text-gray-500 dark:text-slate-500 p-8">
        © 2024 Mühendis & Müteahhit Proje Yazılımı | T.C. Mevzuatlarına Uygundur
      </footer>
    </div>
  );
};

export default App;

import React from 'react';
import { ArsaBilgileri, HesapSonuclari } from '../types';

interface PlotVisualizerProps {
  data: ArsaBilgileri;
  results: HesapSonuclari | null;
  id?: string;
}

const PlotVisualizer: React.FC<PlotVisualizerProps> = ({ data, results, id }) => {
  // Ölçek ve boyutlar okunabilirlik için artırıldı
  const scale = 10; // m to pixel
  const arsaW = Math.sqrt(data.alan) * 1.2;
  const arsaH = data.alan / arsaW;

  const width = arsaW * scale;
  const height = arsaH * scale;

  const padding = 120; // Yazılar için padding artırıldı
  const svgW = width + padding * 2;
  const svgH = height + padding * 2;

  // Çekme mesafeleri
  const front = (data.cekmeOn || 0) * scale;
  const side = (data.cekmeYan || 0) * scale;
  const rear = (data.cekmeArka || 0) * scale;

  // Bina alanı
  const bldgW = width - (side * 2);
  const bldgH = height - front - rear;

  const tkgmUrl = `https://parselsorgu.tkgm.gov.tr/#tip=ada&il=${data.il || ''}&ilce=${data.ilce || ''}&mahalle=${data.mahalle || ''}&ada=${data.ada || ''}&parsel=${data.parsel || ''}`;

  return (
    <div id={id} className="bg-white dark:bg-slate-800 rounded-2xl shadow-xl overflow-hidden border border-gray-200 dark:border-slate-700 transition-all">
      <div className="p-5 border-b border-gray-100 dark:border-slate-700 flex justify-between items-center bg-gray-50/50 dark:bg-slate-900/50">
        <h3 className="font-extrabold text-base uppercase tracking-wider text-slate-600 dark:text-slate-300">Vaziyet Planı Taslağı</h3>
        <a 
          href={tkgmUrl} 
          target="_blank" 
          rel="noopener noreferrer"
          className="text-sm bg-blue-100 dark:bg-blue-900/30 text-blue-600 dark:text-blue-400 px-4 py-1.5 rounded-full font-bold hover:bg-blue-600 hover:text-white transition-all flex items-center gap-1 shadow-sm"
        >
          TKGM Sorgu <i className="fa-solid fa-external-link text-[10px]"></i>
        </a>
      </div>

      <div className="p-10 flex justify-center items-center overflow-auto bg-[radial-gradient(#e5e7eb_1px,transparent_1px)] dark:bg-[radial-gradient(#1e293b_1px,transparent_1px)] [background-size:30px_30px]">
        <svg width={svgW} height={svgH} viewBox={`0 0 ${svgW} ${svgH}`} className="drop-shadow-2xl">
          {/* Arsa Dış Sınırları */}
          <rect 
            x={padding} 
            y={padding} 
            width={width} 
            height={height} 
            fill="none" 
            stroke="currentColor" 
            strokeWidth="5"
            className="text-slate-500 dark:text-slate-400"
          />

          {/* Çekme Çizgileri */}
          <line 
            x1={padding} y1={padding + front} 
            x2={padding + width} y2={padding + front} 
            strokeDasharray="10,10" stroke="#3b82f6" strokeWidth="2"
          />
          <line 
            x1={padding + side} y1={padding} 
            x2={padding + side} y2={padding + height} 
            strokeDasharray="10,10" stroke="#3b82f6" strokeWidth="2"
          />
          <line 
            x1={padding + width - side} y1={padding} 
            x2={padding + width - side} y2={padding + height} 
            strokeDasharray="10,10" stroke="#3b82f6" strokeWidth="2"
          />
          <line 
            x1={padding} y1={padding + height - rear} 
            x2={padding + width} y2={padding + height - rear} 
            strokeDasharray="10,10" stroke="#3b82f6" strokeWidth="2"
          />

          {/* Arsa Boyutları */}
          <text x={padding + width/2} y={padding - 35} textAnchor="middle" className="text-lg font-extrabold fill-slate-700 dark:fill-slate-200">ARSA GENİŞLİĞİ: {arsaW.toFixed(1)}m</text>
          <text x={padding - 40} y={padding + height/2} textAnchor="middle" transform={`rotate(-90, ${padding-40}, ${padding + height/2})`} className="text-lg font-extrabold fill-slate-700 dark:fill-slate-200">ARSA DERİNLİĞİ: {arsaH.toFixed(1)}m</text>

          {/* Çekme Mesafesi Yazıları */}
          {data.cekmeOn! > 0 && <text x={padding + width/2} y={padding + front/2 + 8} textAnchor="middle" className="text-sm font-bold fill-blue-600">ÖN: {data.cekmeOn}m</text>}
          {data.cekmeYan! > 0 && <text x={padding + side/2} y={padding + height/2} textAnchor="middle" transform={`rotate(-90, ${padding + side/2}, ${padding + height/2})`} className="text-sm font-bold fill-blue-600">YAN: {data.cekmeYan}m</text>}

          {/* Bina Oturumu */}
          {results && (
            <g>
              <rect 
                x={padding + side} 
                y={padding + front} 
                width={bldgW} 
                height={bldgH} 
                className="fill-blue-500/20 stroke-blue-600"
                strokeWidth="4"
              />
              <text 
                x={padding + side + bldgW/2} 
                y={padding + front + bldgH/2 - 10} 
                textAnchor="middle" 
                className="fill-blue-800 dark:fill-blue-400 font-extrabold text-xl uppercase"
              >
                BİNA OTURUMU
              </text>
              <text 
                x={padding + side + bldgW/2} 
                y={padding + front + bldgH/2 + 25} 
                textAnchor="middle" 
                className="fill-blue-800 dark:fill-blue-400 font-bold text-lg"
              >
                {results.tabanAlani.toFixed(1)} m²
              </text>
            </g>
          )}
        </svg>
      </div>

      <div className="p-5 text-sm text-gray-600 dark:text-slate-400 font-bold italic bg-gray-50 dark:bg-slate-900/40 border-t border-gray-100 dark:border-slate-700">
        <i className="fa-solid fa-circle-info mr-2"></i>
        Vaziyet planı, girilen çekme mesafeleri ve TAKS oranına göre mühendislik standartlarında çizilmiştir.
      </div>
    </div>
  );
};

