import React, { useState } from 'react';
import { NizamType, ArsaBilgileri, Point } from '../types';

interface InputFieldProps {
  label: string;
  name: string;
  value: any;
  onChange: (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement>) => void;
  type?: string;
  placeholder?: string;
  icon?: string;
  step?: string;
  required?: boolean;
  keosError?: boolean;
}

const InputField: React.FC<InputFieldProps> = ({ 
  label, name, value, onChange, type = "text", placeholder = "", 
  icon = "", step, required = true, keosError = false 
}) => (
  <div className="space-y-1">
    <div className="flex justify-between items-center">
      <label className={`text-xs font-bold uppercase ${keosError ? 'text-red-500' : 'text-gray-500 dark:text-slate-400'}`}>
        {label}
      </label>
      {keosError && (
        <span className="text-[9px] bg-red-100 text-red-600 px-1.5 py-0.5 rounded font-bold animate-pulse">
          KEOS'tan erişilemedi!
        </span>
      )}
    </div>
    <div className="relative">
      {icon && <i className={`fa-solid ${icon} absolute left-3 top-1/2 -translate-y-1/2 ${keosError ? 'text-red-400' : 'text-gray-400'}`}></i>}
      {type === "textarea" ? (
        <textarea
          name={name}
          value={value ?? ''}
          onChange={onChange}
          placeholder={placeholder}
          required={required}
          className="w-full bg-gray-50 dark:bg-slate-900 border border-gray-200 dark:border-slate-700 rounded-lg py-2 px-4 h-24 text-xs font-mono focus:ring-2 focus:ring-blue-500 outline-none transition-all"
        />
      ) : (
        <input
          type={type}
          name={name}
          value={value ?? ''}
          onChange={onChange}
          placeholder={placeholder}
          step={step}
          required={required}
          className={`w-full bg-gray-50 dark:bg-slate-900 border rounded-lg py-2 ${icon ? 'pl-10' : 'px-4'} pr-4 focus:ring-2 outline-none transition-all ${
            keosError ? 'border-red-300 focus:ring-red-500' : 'border-gray-200 dark:border-slate-700 focus:ring-blue-500'
          }`}
        />
      )}
    </div>
  </div>
);

interface ConstructionFormProps {
  onCalculate: (data: ArsaBilgileri) => void;
  onSearchUsak: (mahalle: string, ada: string, parsel: string) => Promise<any>;
  isSearching: boolean;
}

const ConstructionForm: React.FC<ConstructionFormProps> = ({ onCalculate, onSearchUsak, isSearching }) => {
  const [step, setStep] = useState(1);
  const [missingKeosFields, setMissingKeosFields] = useState<string[]>([]);
  const [formData, setFormData] = useState<any>({
    alan: '',
    nizam: NizamType.AYRIK,
    daireSayisiTercihi: 4,
    taks: '',
    katAdedi: '',
    cekmeOn: '',
    cekmeYan: '',
    cekmeArka: '',
    il: 'Uşak',
    ilce: '',
    mahalle: '',
    ada: '',
    parsel: '',
    geoJsonInput: ''
  });

  const parseCoordinates = (input: string): Point[] => {
    try {
      // GeoJSON formatı ise (TKGM'den indirilen dosya içeriği)
      if (input.includes('features')) {
        const data = JSON.parse(input);
        const coords = data.features[0].geometry.coordinates[0];
        return coords.map((c: number[]) => ({ x: c[0], y: c[1] }));
      }
      // Sadece koordinat listesi ise
      const lines = input.trim().split('\n');
      return lines.map(line => {
        const [x, y] = line.replace(',', ' ').split(/\s+/).map(Number);
        return { x, y };
      });
    } catch (e) {
      console.error("Koordinat ayrıştırma hatası:", e);
      return [];
    }
  };

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement>) => {
    const { name, value } = e.target;
    setFormData((prev: any) => ({ ...prev, [name]: value }));
  };

  const handleUsakSearch = async () => {
    const result = await onSearchUsak(formData.mahalle, formData.ada, formData.parsel);
    if (result) {
      setFormData((prev: any) => ({ ...prev, ...result }));
      setMissingKeosFields(Object.keys(result).filter(k => !result[k]));
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const coords = parseCoordinates(formData.geoJsonInput);

    const processedData: ArsaBilgileri = {
      ...formData,
      alan: Number(formData.alan),
      cekmeOn: Number(formData.cekmeOn) || 0,
      cekmeYan: Number(formData.cekmeYan) || 0,
      cekmeArka: Number(formData.cekmeArka) || 0,
      taks: Number(formData.taks) || 0.3,
      katAdedi: Number(formData.katAdedi) || 1,
      daireSayisiTercihi: Number(formData.daireSayisiTercihi),
      koordinatlar: coords.length > 0 ? coords : undefined
    };

    onCalculate(processedData);
  };

  return (
    <form onSubmit={handleSubmit} className="space-y-6">
      {step === 1 && (
        <div className="space-y-4">
          <div className="grid grid-cols-2 gap-4">
            <InputField label="Arsa Alanı (m²)" name="alan" type="number" value={formData.alan} onChange={handleChange} icon="fa-chart-area" />
            <div className="space-y-1">
              <label className="text-xs font-bold text-gray-500 uppercase">Nizam</label>
              <select name="nizam" value={formData.nizam} onChange={handleChange} className="w-full bg-gray-50 dark:bg-slate-900 border rounded-lg py-2 px-4 outline-none focus:ring-2 focus:ring-blue-500">
                <option value={NizamType.AYRIK}>Ayrık Nizam</option>
                <option value={NizamType.BITISIK}>Bitişik Nizam</option>
              </select>
            </div>
          </div>
          <div className="grid grid-cols-3 gap-4">
            <InputField label="Mahalle" name="mahalle" value={formData.mahalle} onChange={handleChange} />
            <InputField label="Ada" name="ada" value={formData.ada} onChange={handleChange} />
            <InputField label="Parsel" name="parsel" value={formData.parsel} onChange={handleChange} />
          </div>

          <div className="p-4 bg-amber-50 dark:bg-amber-900/20 border border-amber-200 dark:border-amber-800 rounded-xl space-y-3">
            <h4 className="text-xs font-bold text-amber-700 dark:text-amber-400 uppercase flex items-center gap-2">
              <i className="fa-solid fa-draw-polygon"></i> Gerçek Arsa Sınırları (Opsiyonel)
            </h4>
            <p className="text-[10px] text-amber-600 dark:text-amber-500 leading-tight">
              TKGM Parsel Sorgu'dan indirdiğiniz <b>GeoJSON</b> dosyasının içeriğini veya koordinat listesini buraya yapıştırarak gerçek vaziyet planını görebilirsiniz.
            </p>
            <InputField 
              label="GeoJSON veya Koordinat Listesi" 
              name="geoJsonInput" 
              type="textarea" 
              value={formData.geoJsonInput} 
              onChange={handleChange} 
              required={false}
              placeholder='Örn: {"features": [...] } veya 29.416, 38.659...' 
            />
          </div>

          <button type="button" onClick={() => setStep(2)} className="w-full bg-blue-600 text-white font-bold py-3 rounded-xl shadow-lg shadow-blue-500/30">İleri</button>
        </div>
      )}

      {step === 2 && (
        <div className="space-y-4">
          <div className="grid grid-cols-3 gap-4">
            <InputField label="Ön (m)" name="cekmeOn" type="number" value={formData.cekmeOn} onChange={handleChange} required={false} />
            <InputField label="Yan (m)" name="cekmeYan" type="number" value={formData.cekmeYan} onChange={handleChange} required={false} />
            <InputField label="Arka (m)" name="cekmeArka" type="number" value={formData.cekmeArka} onChange={handleChange} required={false} />
          </div>
          <div className="grid grid-cols-2 gap-4">
            <InputField label="TAKS" name="taks" type="number" step="0.01" value={formData.taks} onChange={handleChange} />
            <InputField label="Kat" name="katAdedi" type="number" value={formData.katAdedi} onChange={handleChange} />
          </div>
          <div className="flex gap-4">
            <button type="button" onClick={() => setStep(1)} className="flex-1 bg-gray-200 dark:bg-slate-700 py-3 rounded-xl font-bold">Geri</button>
            <button type="submit" className="flex-[2] bg-emerald-600 text-white py-3 rounded-xl font-bold shadow-lg shadow-emerald-500/20">Hesapla ve Görselleştir</button>
          </div>
        </div>
      )}
    </form>
  );
};

