import React from 'react';
import { ArsaBilgileri, HesapSonuclari, Point } from '../types';

interface PlotVisualizerProps {
  data: ArsaBilgileri;
  results: HesapSonuclari | null;
  id?: string;
}

const PlotVisualizer: React.FC<PlotVisualizerProps> = ({ data, results, id }) => {
  const scale = 15; // Görselleştirme ölçeği
  const padding = 120;

  // Koordinatları metrik (X,Y) düzlemine basitçe projeksiyon yapar (Derece -> Metre yaklaşık)
  const getMetricalPoints = (coords: Point[]): Point[] => {
    if (coords.length === 0) return [];

    // Orta noktayı bul
    const minX = Math.min(...coords.map(p => p.x));
    const minY = Math.min(...coords.map(p => p.y));

    // GPS derecesini metreye çevir (1 derece yakl. 111.000 metre)
    const latFactor = 111320;
    const lonFactor = 40075000 * Math.cos(minY * Math.PI / 180) / 360;

    return coords.map(p => ({
      x: (p.x - minX) * lonFactor,
      y: (p.y - minY) * latFactor * -1 // Y ekseni SVG'de ters
    }));
  };

  const metricPoints = data.koordinatlar ? getMetricalPoints(data.koordinatlar) : [];

  // SVG Boyutları
  let svgW = 600;
  let svgH = 600;
  let pointsStr = "";
  let insetPointsStr = "";

  if (metricPoints.length > 0) {
    const xs = metricPoints.map(p => p.x);
    const ys = metricPoints.map(p => p.y);
    const w = Math.max(...xs) - Math.min(...xs);
    const h = Math.max(...ys) - Math.min(...ys);

    const viewScale = Math.min(400 / w, 400 / h);
    const scaledPoints = metricPoints.map(p => ({
      x: padding + (p.x - Math.min(...xs)) * viewScale,
      y: padding + (p.y - Math.min(...ys)) * viewScale
    }));

    pointsStr = scaledPoints.map(p => `${p.x},${p.y}`).join(' ');

    // Basit Inset (Çekme mesafesi simülasyonu)
    const insetVal = (data.cekmeYan || 3) * viewScale;
    const insetPoints = scaledPoints.map((p, i) => {
      // Çok basitleştirilmiş poligon küçültme (merkeze doğru çekme)
      const centerX = padding + (w * viewScale) / 2;
      const centerY = padding + (h * viewScale) / 2;
      const dx = p.x - centerX;
      const dy = p.y - centerY;
      const dist = Math.sqrt(dx*dx + dy*dy);
      return {
        x: p.x - (dx / dist) * insetVal,
        y: p.y - (dy / dist) * insetVal
      };
    });
    insetPointsStr = insetPoints.map(p => `${p.x},${p.y}`).join(' ');
  }

  // Varsayılan dikdörtgen çizimi (Koordinat yoksa)
  const renderDefault = () => {
    const arsaW = Math.sqrt(data.alan) * scale;
    const arsaH = (data.alan / (arsaW / scale)) * scale;
    const bldgW = arsaW - (data.cekmeYan || 0) * 2 * scale;
    const bldgH = arsaH - (data.cekmeOn || 0) * scale - (data.cekmeArka || 0) * scale;

    return (
      <svg width={arsaW + padding*2} height={arsaH + padding*2} className="drop-shadow-2xl">
        <rect x={padding} y={padding} width={arsaW} height={arsaH} fill="none" stroke="currentColor" strokeWidth="4" className="text-slate-500" />
        {results && (
          <rect x={padding + (data.cekmeYan || 0)*scale} y={padding + (data.cekmeOn || 0)*scale} width={bldgW} height={bldgH} className="fill-blue-500/20 stroke-blue-600" strokeWidth="3" />
        )}
        <text x={padding + arsaW/2} y={padding - 20} textAnchor="middle" className="text-sm font-bold fill-slate-600">Arsa Genişliği: {(arsaW/scale).toFixed(1)}m</text>
      </svg>
    );
  };

  return (
    <div id={id} className="bg-white dark:bg-slate-800 rounded-2xl shadow-xl border border-gray-200 dark:border-slate-700 overflow-hidden">
      <div className="p-4 bg-gray-50 dark:bg-slate-900 border-b border-gray-100 dark:border-slate-700 flex justify-between items-center">
        <h3 className="font-extrabold text-slate-600 dark:text-slate-300">Vaziyet Planı & Gerçek Sınırlar</h3>
        <span className="text-[10px] bg-emerald-100 text-emerald-700 px-2 py-1 rounded font-bold">ÖLÇEKLİ ÇİZİM</span>
      </div>

      <div className="p-10 flex justify-center items-center bg-[radial-gradient(#e5e7eb_1px,transparent_1px)] dark:bg-[radial-gradient(#1e293b_1px,transparent_1px)] [background-size:25px_25px] overflow-auto">
        {metricPoints.length > 0 ? (
          <svg width={600} height={600} viewBox="0 0 600 600" className="drop-shadow-2xl">
            <polygon points={pointsStr} fill="none" stroke="#64748b" strokeWidth="4" />
            {results && (
              <polygon points={insetPointsStr} className="fill-blue-500/20 stroke-blue-600" strokeWidth="3" />
            )}
            <text x="300" y="580" textAnchor="middle" className="text-[10px] fill-slate-400 font-bold uppercase tracking-tighter">
              GPS Koordinatlarından Gerçek Poligon Verisi Oluşturuldu
            </text>
          </svg>
        ) : renderDefault()}
      </div>

      <div className="p-4 bg-blue-50 dark:bg-blue-900/10 text-[11px] font-bold text-blue-700 dark:text-blue-400 border-t border-gray-100 dark:border-slate-700">
        <i className="fa-solid fa-triangle-exclamation mr-1"></i>
        Çizim metrik bazda gerçek koordinat verilerine dayanmaktadır. Resmi projelerde ldr/lihkab verilerini baz alınız.
      </div>
    </div>
  );
};

export default PlotVisualizer;

import React, { useState, useEffect } from 'react';
import { NizamType, ArsaBilgileri, HesapSonuclari } from './types';
import ConstructionForm from './components/ConstructionForm';
import PlotVisualizer from './components/PlotVisualizer';
import ResultsPanel from './components/ResultsPanel';
import Header from './components/Header';
import { GoogleGenAI } from "@google/genai";

const App: React.FC = () => {
  const [darkMode, setDarkMode] = useState(true);
  const [formData, setFormData] = useState<ArsaBilgileri | null>(null);
  const [results, setResults] = useState<HesapSonuclari | null>(null);
  const [isSearching, setIsSearching] = useState(false);

  useEffect(() => {
    if (darkMode) {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [darkMode]);

  const fetchUsakImarData = async (mahalle: string, ada: string, parsel: string) => {
    setIsSearching(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const prompt = `Uşak ili, ${mahalle} mahallesi, Ada: ${ada}, Parsel: ${parsel} için Uşak Belediyesi KEOS imar portalını (https://keos.usak.bel.tr/imardurumu/index.aspx) sorgula. 
      Lütfen şu teknik bilgileri portal verilerinden çıkar:
      1. Arsa Alanı (m²) -> JSON: 'alan'
      2. T.A.K.S (Yanında yazan değer) -> JSON: 'taks'
      3. Kat Adedi (Hmax/Kat) -> JSON: 'kat'
      4. Ön Çekme Mesafesi -> JSON: 'onCekme'
      5. Yan Çekme Mesafesi -> JSON: 'yanCekme'
      6. Arka Çekme Mesafesi -> JSON: 'arkaCekme'

      Sadece JSON formatında döndür. Değer yoksa 0 döndür. Örn: {"alan": 497.10, "taks": 0.30, "kat": 3, "onCekme": 5, "yanCekme": 3, "arkaCekme": 3}`;

      const response = await ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: prompt,
        config: {
          tools: [{ googleSearch: {} }],
        },
      });

      const text = response.text || "";
      const jsonMatch = text.match(/\{.*\}/s);
      if (jsonMatch) {
        return JSON.parse(jsonMatch[0]);
      }
      return null;
    } catch (error) {
      console.error("KEOS sorgu hatası:", error);
      return null;
    } finally {
      setIsSearching(false);
    }
  };

  const calculateData = (data: ArsaBilgileri) => {
    // KAKS: TAKS * Kat Adedi
    const kaks = data.taks * data.katAdedi;
    const tabanAlani = data.alan * data.taks;
    const zeminBrut = tabanAlani * 1.1;
    const normalKatBrut = zeminBrut * 1.15;
    const daireBasiMetrekare = normalKatBrut / data.daireSayisiTercihi;

    let daireTipi = "Özel Proje";
    if (daireBasiMetrekare < 105) daireTipi = "1+1 Apart";
    else if (daireBasiMetrekare >= 105 && daireBasiMetrekare < 115) daireTipi = "2+1 Daire";
    else if (daireBasiMetrekare >= 110 && daireBasiMetrekare < 150) daireTipi = "3+1 Daire";
    else if (daireBasiMetrekare >= 150) daireTipi = "4+1 Daire";

    setResults({
      kaks,
      tabanAlani,
      zeminBrut,
      normalKatBrut,
      toplamKat: data.katAdedi,
      daireTipi,
      daireBasiMetrekare
    });
    setFormData(data);
  };

  return (
    <div className="min-h-screen pb-12 transition-colors duration-300 bg-gray-50 dark:bg-slate-900 text-slate-900 dark:text-slate-100 font-sans">
      <Header darkMode={darkMode} setDarkMode={setDarkMode} />

      <main className="container mx-auto px-4 mt-8 max-w-6xl">
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
          <div className="space-y-6">
            <section className="bg-white dark:bg-slate-800 p-6 rounded-3xl shadow-2xl border border-gray-100 dark:border-slate-700">
              <h2 className="text-xl font-bold mb-6 flex items-center gap-2">
                <i className="fa-solid fa-hard-hat text-blue-600"></i>
                Proje Giriş Paneli
              </h2>
              <ConstructionForm 
                onCalculate={calculateData} 
                onSearchUsak={fetchUsakImarData} 
                isSearching={isSearching}
              />
            </section>
            {results && formData && (
              <div className="lg:hidden">
                <ResultsPanel results={results} data={formData} />
              </div>
            )}
          </div>

          <div id="main-report-container" className="space-y-6">
            {formData ? (
              <>
                <PlotVisualizer data={formData} results={results} />
                <div className="hidden lg:block">
                  {results && <ResultsPanel results={results} data={formData} />}
                </div>
              </>
            ) : (
              <div className="h-[500px] flex flex-col items-center justify-center bg-white dark:bg-slate-800 rounded-3xl border-4 border-dashed border-gray-200 dark:border-slate-700 text-center p-12">
                <i className="fa-solid fa-map-marked-alt text-7xl text-gray-200 dark:text-slate-700 mb-6"></i>
                <h3 className="text-xl font-bold text-gray-400 dark:text-slate-600">Analiz Başlatılmadı</h3>
                <p className="text-gray-400 dark:text-slate-600 mt-2">Lütfen sol taraftaki formu doldurarak KEOS sorgusu yapın veya manuel verileri girin.</p>
              </div>
            )}
          </div>
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { NizamType, ArsaBilgileri, Point } from '../types';

