interface ConstructionFormProps {
  onCalculate: (data: ArsaBilgileri) => void;
  onSearchUsak: (mahalle: string, ada: string, parsel: string) => Promise<any>;
  isSearching: boolean;
}

const ConstructionForm: React.FC<ConstructionFormProps> = ({ onCalculate, onSearchUsak, isSearching }) => {
  const [step, setStep] = useState(1);
  const [missingKeosFields, setMissingKeosFields] = useState<string[]>([]);
  const [formData, setFormData] = useState<any>({
    alan: '',
    nizam: NizamType.AYRIK,
    daireSayisiTercihi: 4,
    taks: '',
    katAdedi: '',
    cekmeOn: '',
    cekmeYan: '',
    cekmeArka: '',
    il: 'Uşak',
    ilce: 'Merkez',
    mahalle: '',
    ada: '',
    parsel: '',
    geoJsonInput: ''
  });

  const parseCoordinates = (input: string): Point[] => {
    try {
      if (input.includes('features')) {
        const data = JSON.parse(input);
        const coords = data.features[0].geometry.coordinates[0];
        return coords.map((c: number[]) => ({ x: c[0], y: c[1] }));
      }
      const lines = input.trim().split('\n');
      return lines.map(line => {
        const parts = line.replace(',', ' ').split(/\s+/).map(Number);
        return { x: parts[0], y: parts[1] };
      }).filter(p => !isNaN(p.x));
    } catch (e) {
      return [];
    }
  };

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement>) => {
    const { name, value } = e.target;
    setFormData((prev: any) => ({ ...prev, [name]: value }));
    if (missingKeosFields.includes(name)) {
      setMissingKeosFields(prev => prev.filter(f => f !== name));
    }
  };

  const handleUsakSearch = async () => {
    if (!formData.mahalle || !formData.ada || !formData.parsel) {
      alert("Lütfen önce Mahalle, Ada ve Parsel bilgilerini girin.");
      return;
    }
    const result = await onSearchUsak(formData.mahalle, formData.ada, formData.parsel);
    if (result) {
      const updatedFields: any = {};
      const missing: string[] = [];

      const fields = [
        { key: 'alan', keosKey: 'alan' },
        { key: 'taks', keosKey: 'taks' },
        { key: 'katAdedi', keosKey: 'kat' },
        { key: 'cekmeOn', keosKey: 'onCekme' },
        { key: 'cekmeYan', keosKey: 'yanCekme' },
        { key: 'cekmeArka', keosKey: 'arkaCekme' }
      ];

      fields.forEach(f => {
        if (result[f.keosKey] && result[f.keosKey] !== 0) {
          updatedFields[f.key] = result[f.keosKey].toString();
        } else {
          missing.push(f.key);
        }
      });

      setFormData((prev: any) => ({ ...prev, ...updatedFields }));
      setMissingKeosFields(missing);

      if (missing.length > 0) {
        alert("Sorgulama yapıldı ancak bazı değerlere KEOS'tan erişilemedi. Lütfen kırmızı alanları manuel doldurun.");
      }
    } else {
      alert("Ada/Parsel bulunamadı veya portal yanıt vermedi.");
      setMissingKeosFields(['alan', 'taks', 'katAdedi', 'cekmeOn', 'cekmeYan', 'cekmeArka']);
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const coords = parseCoordinates(formData.geoJsonInput);
    const processedData: ArsaBilgileri = {
      ...formData,
      alan: Number(formData.alan),
      cekmeOn: Number(formData.cekmeOn) || 0,
      cekmeYan: Number(formData.cekmeYan) || 0,
      cekmeArka: Number(formData.cekmeArka) || 0,
      taks: Number(formData.taks) || 0.3,
      katAdedi: Number(formData.katAdedi) || 1,
      daireSayisiTercihi: Number(formData.daireSayisiTercihi),
      koordinatlar: coords.length > 0 ? coords : undefined
    };
    onCalculate(processedData);
  };

  return (
    <form onSubmit={handleSubmit} className="space-y-6">
      {step === 1 && (
        <div className="space-y-4 animate-in fade-in duration-500">
          <div className="grid grid-cols-2 gap-4">
            <InputField label="Arsa Alanı (m²)" name="alan" type="number" value={formData.alan} onChange={handleChange} icon="fa-chart-area" keosError={missingKeosFields.includes('alan')} />
            <div className="space-y-1">
              <label className="text-[10px] font-extrabold text-gray-500 uppercase px-1">İmar Nizamı</label>
