import React from 'react';
import { ArsaBilgileri, HesapSonuclari, Point } from '../types';

interface PlotVisualizerProps {
  data: ArsaBilgileri;
  results: HesapSonuclari | null;
  id?: string;
}

const PlotVisualizer: React.FC<PlotVisualizerProps> = ({ data, results, id }) => {
  const padding = 100;
  const canvasSize = 600;

  // Koordinatları Metrik Sisteme Dönüştürme (EPSG:4326 to Metric Approx)
  const getMetricPoints = (coords: Point[]): Point[] => {
    if (coords.length === 0) return [];
    const minX = Math.min(...coords.map(p => p.x));
    const minY = Math.min(...coords.map(p => p.y));
    const latFactor = 111320;
    const lonFactor = 40075000 * Math.cos(minY * Math.PI / 180) / 360;

    return coords.map(p => ({
      x: (p.x - minX) * lonFactor,
      y: (p.y - minY) * latFactor * -1
    }));
  };

  const metricPoints = data.koordinatlar ? getMetricPoints(data.koordinatlar) : [];

  let arsaPointsStr = "";
  let binaPointsStr = "";

  if (metricPoints.length > 0) {
    const xs = metricPoints.map(p => p.x);
    const ys = metricPoints.map(p => p.y);
    const w = Math.max(...xs) - Math.min(...xs);
    const h = Math.max(...ys) - Math.min(...ys);

    const scale = Math.min((canvasSize - padding * 2) / w, (canvasSize - padding * 2) / h);

    const scaledPoints = metricPoints.map(p => ({
      x: padding + (p.x - Math.min(...xs)) * scale,
      y: padding + (p.y - Math.min(...ys)) * scale
    }));

    arsaPointsStr = scaledPoints.map(p => `${p.x},${p.y}`).join(' ');

    // Basit Polygon Inset (Bina Oturumu Simülasyonu)
    if (results) {
      const centerX = scaledPoints.reduce((sum, p) => sum + p.x, 0) / scaledPoints.length;
      const centerY = scaledPoints.reduce((sum, p) => sum + p.y, 0) / scaledPoints.length;

      const setbackScale = 1 - (Math.sqrt(data.cekmeYan || 3) / 10); // Yaklaşık küçültme
      const binaPoints = scaledPoints.map(p => ({
        x: centerX + (p.x - centerX) * setbackScale,
        y: centerY + (p.y - centerY) * setbackScale
      }));
      binaPointsStr = binaPoints.map(p => `${p.x},${p.y}`).join(' ');
    }
  }

  const renderDefault = () => {
    const arsaSize = Math.sqrt(data.alan) * 15;
    const offset = padding;
    const bW = arsaSize - (data.cekmeYan || 0) * 2 * 15;
    const bH = arsaSize - (data.cekmeOn || 0) * 15 - (data.cekmeArka || 0) * 15;

    return (
      <svg width={arsaSize + padding*2} height={arsaSize + padding*2} className="drop-shadow-2xl overflow-visible">
        <rect x={offset} y={offset} width={arsaSize} height={arsaSize} fill="none" stroke="currentColor" strokeWidth="6" className="text-slate-400 dark:text-slate-500" />
        {results && (
          <rect x={offset + (data.cekmeYan || 0)*15} y={offset + (data.cekmeOn || 0)*15} width={bW} height={bH} className="fill-blue-500/20 stroke-blue-600" strokeWidth="4" />
        )}
        <text x={offset + arsaSize/2} y={offset - 25} textAnchor="middle" className="text-sm font-black fill-slate-500">ARSA GENİŞLİĞİ: {Math.sqrt(data.alan).toFixed(1)}m</text>
        <text x={offset - 25} y={offset + arsaSize/2} textAnchor="middle" transform={`rotate(-90, ${offset-25}, ${offset+arsaSize/2})`} className="text-sm font-black fill-slate-500">ARSA DERİNLİĞİ: {Math.sqrt(data.alan).toFixed(1)}m</text>
      </svg>
    );
  };

  return (
    <div id={id} className="bg-white dark:bg-slate-800 rounded-[2.5rem] shadow-2xl border border-gray-100 dark:border-slate-700 overflow-hidden">
      <div className="p-6 bg-gray-50 dark:bg-slate-900/50 border-b border-gray-100 dark:border-slate-700 flex justify-between items-center">
        <h3 className="font-black text-slate-700 dark:text-slate-300 tracking-tighter uppercase">Vaziyet Planı Taslağı</h3>
        <div className="flex gap-2">
          <span className="text-[9px] bg-blue-100 text-blue-700 px-3 py-1 rounded-full font-black uppercase">Mühendislik Ölçeği: 1/100</span>
          {data.koordinatlar && <span className="text-[9px] bg-emerald-100 text-emerald-700 px-3 py-1 rounded-full font-black uppercase">GERÇEK GEOMETRİ</span>}
        </div>
      </div>

      <div className="p-12 flex justify-center items-center bg-[radial-gradient(#e2e8f0_1.5px,transparent_1.5px)] dark:bg-[radial-gradient(#1e293b_1.5px,transparent_1.5px)] [background-size:40px_40px] overflow-auto min-h-[500px]">
        {metricPoints.length > 0 ? (
          <svg width={canvasSize} height={canvasSize} viewBox={`0 0 ${canvasSize} ${canvasSize}`} className="drop-shadow-2xl overflow-visible">
            {/* Arsa Dış Sınırı */}
            <polygon points={arsaPointsStr} fill="none" stroke="#64748b" strokeWidth="6" strokeLinejoin="round" />
            {/* Bina Oturumu */}
            {results && (
              <g>
                <polygon points={binaPointsStr} className="fill-blue-500/10 stroke-blue-600" strokeWidth="4" strokeLinejoin="round" />
                <text x="300" y="300" textAnchor="middle" className="fill-blue-800 dark:fill-blue-400 font-black text-lg uppercase tracking-tighter">Bina Oturumu</text>
                <text x="300" y="325" textAnchor="middle" className="fill-blue-800 dark:fill-blue-400 font-bold text-sm">{results.tabanAlani.toFixed(1)} m²</text>
              </g>
            )}
            {/* Koordinat Etiketleri */}
            <text x="300" y="580" textAnchor="middle" className="text-[10px] fill-slate-400 font-black uppercase tracking-widest opacity-50 italic">TKGM GPS Verileri Üzerinden Çizilmiştir</text>
          </svg>
        ) : renderDefault()}
      </div>

      <div className="p-6 bg-blue-600 text-white flex items-center justify-between">
         <div className="flex items-center gap-3">
            <i className="fa-solid fa-circle-check text-2xl opacity-80"></i>
            <div>
               <p className="text-[10px] font-black uppercase opacity-70 leading-none">Hesaplanan Taban Alanı</p>
               <p className="text-2xl font-black leading-tight">{results ? results.tabanAlani.toFixed(1) : "0"} <span className="text-xs">m²</span></p>
            </div>
         </div>
         <div className="text-right">
            <p className="text-[10px] font-black uppercase opacity-70 leading-none">Daire Tipolojisi</p>
            <p className="text-xl font-black leading-tight">{results ? results.daireTipi : "-"}</p>
         </div>
      </div>
    </div>
  );
};

export default PlotVisualizer;

