interface ConstructionFormProps {
  onCalculate: (data: ArsaBilgileri) => void;
  onSearchUsak: (mahalle: string, ada: string, parsel: string) => Promise<any>;
  isSearching: boolean;
}

const ConstructionForm: React.FC<ConstructionFormProps> = ({ onCalculate, onSearchUsak, isSearching }) => {
  const [step, setStep] = useState(1);
  const [missingKeosFields, setMissingKeosFields] = useState<string[]>([]);
  const [formData, setFormData] = useState<any>({
    alan: '',
    nizam: NizamType.AYRIK,
    daireSayisiTercihi: 4,
    taks: '',
    katAdedi: '',
    cekmeOn: '',
    cekmeYan: '',
    cekmeArka: '',
    il: 'Uşak',
    ilce: 'Merkez',
    mahalle: '',
    ada: '',
    parsel: '',
    geoJsonInput: ''
  });

  const parseCoordinates = (input: string): Point[] => {
    try {
      if (!input.trim()) return [];

      // GeoJSON Control
      if (input.includes('features')) {
        const data = JSON.parse(input);
        const coords = data.features[0].geometry.coordinates[0];
        return coords.map((c: number[]) => ({ x: c[0], y: c[1] }));
      }

      // TKGM Coordinate List Control (NoktaNo Y X or Y X format)
      const lines = input.trim().split('\n');
      const points: Point[] = [];

      lines.forEach(line => {
        const parts = line.replace(/,/g, '.').split(/\s+/).filter(p => p.length > 0);
        if (parts.length >= 2) {
          // Eğer 3 parça varsa ilkini Nokta No say, son iki Enlem/Boylam
          const y = parseFloat(parts[parts.length - 2]);
          const x = parseFloat(parts[parts.length - 1]);
          if (!isNaN(x) && !isNaN(y)) {
            points.push({ x, y });
          }
        }
      });
      return points;
    } catch (e) {
      console.error("Parse Error:", e);
      return [];
    }
  };

  const handleUsakSearch = async () => {
    const result = await onSearchUsak(formData.mahalle, formData.ada, formData.parsel);
    if (result) {
      setFormData((prev: any) => ({ ...prev, ...result }));
      setMissingKeosFields(Object.keys(result).filter(k => !result[k]));
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const coords = parseCoordinates(formData.geoJsonInput);
    onCalculate({
      ...formData,
      alan: Number(formData.alan),
      taks: Number(formData.taks) || 0.3,
      katAdedi: Number(formData.katAdedi) || 1,
      cekmeOn: Number(formData.cekmeOn) || 0,
      cekmeYan: Number(formData.cekmeYan) || 0,
      cekmeArka: Number(formData.cekmeArka) || 0,
      daireSayisiTercihi: Number(formData.daireSayisiTercihi),
      koordinatlar: coords
    });
  };

  return (
    <form onSubmit={handleSubmit} className="space-y-6">
      {step === 1 && (
        <div className="space-y-4 animate-in fade-in zoom-in-95 duration-500">
          <div className="grid grid-cols-2 gap-4">
            <InputField label="Arsa Alanı (m²)" name="alan" type="number" value={formData.alan} onChange={(e) => setFormData({...formData, alan: e.target.value})} icon="fa-chart-area" />
            <div className="space-y-1">
              <label className="text-[10px] font-extrabold text-gray-500 uppercase px-1">Nizam</label>
              <select name="nizam" value={formData.nizam} onChange={(e) => setFormData({...formData, nizam: e.target.value as NizamType})} className="w-full bg-gray-50 dark:bg-slate-900 border rounded-2xl py-2.5 px-4 font-semibold outline-none focus:ring-2 focus:ring-blue-500">
                <option value={NizamType.AYRIK}>Ayrık Nizam</option>
                <option value={NizamType.BITISIK}>Bitişik Nizam</option>
              </select>
            </div>
          </div>
          <div className="grid grid-cols-3 gap-4">
            <InputField label="Mahalle" name="mahalle" value={formData.mahalle} onChange={(e) => setFormData({...formData, mahalle: e.target.value})} />
            <InputField label="Ada" name="ada" value={formData.ada} onChange={(e) => setFormData({...formData, ada: e.target.value})} />
            <InputField label="Parsel" name="parsel" value={formData.parsel} onChange={(e) => setFormData({...formData, parsel: e.target.value})} />
          </div>

          <button type="button" onClick={handleUsakSearch} className="w-full py-4 bg-emerald-600 text-white rounded-2xl font-black text-sm shadow-xl shadow-emerald-500/20 flex items-center justify-center gap-2">
            <i className="fa-solid fa-globe"></i> KEOS'TAN BİLGİLERİ GETİR
          </button>

          <div className="p-4 bg-blue-50 dark:bg-blue-900/10 border-2 border-dashed border-blue-200 dark:border-blue-800 rounded-3xl space-y-2">
            <h4 className="text-[10px] font-black text-blue-700 uppercase tracking-widest flex items-center gap-2">
              <i className="fa-solid fa-paste"></i> TKGM Koordinat Listesi Yapıştır
            </h4>
            <InputField 
              label="Koordinatlar (NoktaNo X Y)" 
              name="geoJsonInput" 
              type="textarea" 
              value={formData.geoJsonInput} 
              onChange={(e) => setFormData({...formData, geoJsonInput: e.target.value})}
              required={false}
              placeholder="TKGM'den kopyaladığınız listeyi buraya yapıştırın. Örn:&#10;1 38.659 29.416&#10;2 38.659 29.417..." 
            />
          </div>

          <button type="button" onClick={() => setStep(2)} className="w-full bg-blue-600 text-white font-black py-4 rounded-2xl">İLERİ <i className="fa-solid fa-arrow-right ml-2"></i></button>
        </div>
      )}

      {step === 2 && (
        <div className="space-y-4 animate-in slide-in-from-right duration-500">
          <div className="grid grid-cols-3 gap-4">
            <InputField label="Ön (m)" name="cekmeOn" type="number" value={formData.cekmeOn} onChange={(e) => setFormData({...formData, cekmeOn: e.target.value})} required={false} />
            <InputField label="Yan (m)" name="cekmeYan" type="number" value={formData.cekmeYan} onChange={(e) => setFormData({...formData, cekmeYan: e.target.value})} required={false} />
            <InputField label="Arka (m)" name="cekmeArka" type="number" value={formData.cekmeArka} onChange={(e) => setFormData({...formData, cekmeArka: e.target.value})} required={false} />
          </div>
          <div className="grid grid-cols-2 gap-4">
            <InputField label="TAKS" name="taks" type="number" step="0.01" value={formData.taks} onChange={(e) => setFormData({...formData, taks: e.target.value})} />
            <InputField label="Kat" name="katAdedi" type="number" value={formData.katAdedi} onChange={(e) => setFormData({...formData, katAdedi: e.target.value})} />
          </div>
          <div className="flex gap-4">
            <button type="button" onClick={() => setStep(1)} className="flex-1 bg-gray-100 dark:bg-slate-700 font-bold py-4 rounded-2xl uppercase">Geri</button>
            <button type="submit" className="flex-[2] bg-blue-600 text-white font-black py-4 rounded-2xl shadow-xl shadow-blue-500/20 uppercase tracking-widest">Hesapla & Çiz</button>
          </div>
        </div>
      )}
    </form>
  );
};

