import React from 'react';
import { ArsaBilgileri, HesapSonuclari, Point } from '../types';

interface PlotVisualizerProps {
  data: ArsaBilgileri;
  results: HesapSonuclari | null;
  id?: string;
}

const PlotVisualizer: React.FC<PlotVisualizerProps> = ({ data, results, id }) => {
  const canvasSize = 650;
  const padding = 120;

  // Haversine Mesafesi (Metre cinsinden iki GPS noktası arası)
  const calculateDistance = (p1: Point, p2: Point): number => {
    const R = 6371000; // Dünya yarıçapı (m)
    const dLat = (p2.y - p1.y) * Math.PI / 180;
    const dLon = (p2.x - p1.x) * Math.PI / 180;
    const a = Math.sin(dLat / 2) * Math.sin(dLat / 2) +
              Math.cos(p1.y * Math.PI / 180) * Math.cos(p2.y * Math.PI / 180) *
              Math.sin(dLon / 2) * Math.sin(dLon / 2);
    const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
    return R * c;
  };

  // Koordinatları Metrik Sisteme İzdüşür
  const getMetricPoints = (coords: Point[]): Point[] => {
    if (coords.length === 0) return [];
    const minY = Math.min(...coords.map(p => p.y));
    const minX = Math.min(...coords.map(p => p.x));

    const latFactor = 111320; // 1 derece enlem ~111km
    const lonFactor = 40075000 * Math.cos(minY * Math.PI / 180) / 360;

    return coords.map(p => ({
      x: (p.x - minX) * lonFactor,
      y: (p.y - minY) * latFactor * -1
    }));
  };

  const metricPoints = data.koordinatlar ? getMetricPoints(data.koordinatlar) : [];

  // Ölçekleme ve Çizim Hazırlığı
  let points: { x: number, y: number, id: number }[] = [];
  let sideLengths: number[] = [];
  let binaPoints: { x: number, y: number }[] = [];

  if (metricPoints.length > 0) {
    const xs = metricPoints.map(p => p.x);
    const ys = metricPoints.map(p => p.y);
    const w = Math.max(...xs) - Math.min(...xs);
    const h = Math.max(...ys) - Math.min(...ys);
    const scale = Math.min((canvasSize - padding * 2) / w, (canvasSize - padding * 2) / h);

    points = metricPoints.map((p, i) => ({
      x: padding + (p.x - Math.min(...xs)) * scale,
      y: padding + (p.y - Math.min(...ys)) * scale,
      id: i + 1
    }));

    // Kenar Uzunluklarını Hesapla
    for (let i = 0; i < data.koordinatlar!.length; i++) {
      const p1 = data.koordinatlar![i];
      const p2 = data.koordinatlar![(i + 1) % data.koordinatlar!.length];
      sideLengths.push(calculateDistance(p1, p2));
    }

    // Bina Oturumu Offset (Küçültme)
    if (results) {
      const centerX = points.reduce((sum, p) => sum + p.x, 0) / points.length;
      const centerY = points.reduce((sum, p) => sum + p.y, 0) / points.length;
      const reduction = 0.8; // Basit küçültme (Gelişmiş offset yerine)
      binaPoints = points.map(p => ({
        x: centerX + (p.x - centerX) * reduction,
        y: centerY + (p.y - centerY) * reduction
      }));
    }
  }

  const renderPlot = () => {
    if (points.length === 0) {
      // Varsayılan Dikdörtgen
      const size = 300;
      return (
        <svg width={canvasSize} height={canvasSize}>
          <rect x={(canvasSize-size)/2} y={(canvasSize-size)/2} width={size} height={size} fill="none" stroke="#64748b" strokeWidth="4" />
          <text x={canvasSize/2} y={(canvasSize-size)/2 - 10} textAnchor="middle" className="text-[10px] font-black fill-slate-400 uppercase">Veri Bekleniyor</text>
        </svg>
      );
    }

    const arsaPath = points.map(p => `${p.x},${p.y}`).join(' ');
    const binaPath = binaPoints.map(p => `${p.x},${p.y}`).join(' ');

    return (
      <svg width={canvasSize} height={canvasSize} className="overflow-visible drop-shadow-2xl">
        {/* Izgara */}
        <defs>
          <pattern id="grid" width="40" height="40" patternUnits="userSpaceOnUse">
            <path d="M 40 0 L 0 0 0 40" fill="none" stroke="currentColor" strokeWidth="0.5" className="text-slate-200 dark:text-slate-800" />
          </pattern>
        </defs>
        <rect width="100%" height="100%" fill="url(#grid)" />

        {/* Arsa Sınırı */}
        <polygon points={arsaPath} fill="none" stroke="#334155" strokeWidth="6" strokeLinejoin="round" />

        {/* Bina Oturumu */}
        {results && <polygon points={binaPath} className="fill-blue-500/10 stroke-blue-600" strokeWidth="4" strokeDasharray="8,4" strokeLinejoin="round" />}

        {/* Kenar Uzunlukları ve Köşeler */}
        {points.map((p, i) => {
          const nextP = points[(i + 1) % points.length];
          const midX = (p.x + nextP.x) / 2;
          const midY = (p.y + nextP.y) / 2;
          const angle = Math.atan2(nextP.y - p.y, nextP.x - p.x) * 180 / Math.PI;

          return (
            <g key={i}>
              {/* Köşe Noktası */}
              <circle cx={p.x} cy={p.y} r="14" className="fill-white dark:fill-slate-900 stroke-slate-500" strokeWidth="2" />
              <text x={p.x} y={p.y} dy=".35em" textAnchor="middle" className="text-[9px] font-black fill-slate-700 dark:fill-slate-300">{p.id}</text>

              {/* Uzunluk Yazısı */}
              <g transform={`translate(${midX},${midY}) rotate(${angle > 90 || angle < -90 ? angle + 180 : angle})`}>
                <rect x="-25" y="-12" width="50" height="12" rx="4" fill="white" fillOpacity="0.8" className="dark:fill-slate-800" />
                <text y="-3" textAnchor="middle" className="text-[9px] font-black fill-blue-600 dark:fill-blue-400">
                  {sideLengths[i].toFixed(2)} m
                </text>
              </g>
            </g>
          );
        })}

        {/* Bilgi Yazıları */}
        <text x="20" y="30" className="text-[12px] font-black fill-slate-800 dark:fill-slate-200 uppercase tracking-tighter">VAZİYET PLANI DETAYI</text>
        <text x="20" y="50" className="text-[10px] font-bold fill-slate-400 uppercase tracking-widest italic">TKGM KOORDİNAT LİSTESİ TABANLI ÖLÇEKLENDİRME</text>
      </svg>
    );
  };

  return (
    <div id={id} className="bg-white dark:bg-slate-800 rounded-[2.5rem] shadow-2xl border border-gray-100 dark:border-slate-700 overflow-hidden transition-all duration-500">
      <div className="p-6 bg-slate-50 dark:bg-slate-900/50 border-b border-gray-100 dark:border-slate-700 flex justify-between items-center">
        <div>
          <h3 className="font-black text-slate-700 dark:text-slate-300 tracking-tighter uppercase leading-none">Vaziyet Planı & Metraj</h3>
          <p className="text-[9px] font-bold text-slate-400 mt-1 uppercase">Hassas Geometrik Çizim</p>
        </div>
        <div className="flex gap-2">
           <span className="text-[10px] bg-blue-100 dark:bg-blue-900/30 text-blue-700 dark:text-blue-400 px-3 py-1.5 rounded-xl font-black">GPS: WGS84</span>
           {data.koordinatlar && <span className="text-[10px] bg-emerald-100 dark:bg-emerald-900/30 text-emerald-700 dark:text-emerald-400 px-3 py-1.5 rounded-xl font-black">DOĞRULANMIŞ VERİ</span>}
        </div>
      </div>

      <div className="flex justify-center items-center bg-[radial-gradient(#cbd5e1_1px,transparent_1px)] dark:bg-[radial-gradient(#1e293b_1px,transparent_1px)] [background-size:20px_20px] overflow-auto min-h-[550px] p-4">
        {renderPlot()}
      </div>

      <div className="p-6 bg-slate-900 text-white flex items-center justify-between">
         <div className="flex gap-4">
            <div>
               <p className="text-[9px] font-black text-slate-400 uppercase leading-none mb-1">Arsa Çevresi</p>
               <p className="text-xl font-black">{sideLengths.reduce((a, b) => a + b, 0).toFixed(2)} <span className="text-[10px]">m</span></p>
            </div>
            <div className="w-px h-8 bg-slate-700"></div>
            <div>
               <p className="text-[9px] font-black text-slate-400 uppercase leading-none mb-1">Toplam Alan</p>
               <p className="text-xl font-black">{data.alan.toFixed(1)} <span className="text-[10px]">m²</span></p>
            </div>
         </div>
         <div className="text-right">
            <p className="text-[9px] font-black text-blue-400 uppercase leading-none mb-1">Bina Oturumu</p>
            <p className="text-xl font-black text-blue-400">{results ? results.tabanAlani.toFixed(1) : "0"} <span className="text-[10px]">m²</span></p>
         </div>
      </div>
    </div>
  );
};

export default PlotVisualizer;

import React from 'react';
import { ArsaBilgileri, HesapSonuclari, Point } from '../types';

interface PlotVisualizerProps {
  data: ArsaBilgileri;
  results: HesapSonuclari | null;
  id?: string;
}

const PlotVisualizer: React.FC<PlotVisualizerProps> = ({ data, results, id }) => {
  const canvasSize = 650;
  const padding = 100;

  // Haversine Mesafesi (Metre cinsinden iki GPS noktası arası)
  const calculateDistance = (p1: Point, p2: Point): number => {
    const R = 6371000; // Dünya yarıçapı (m)
    const dLat = (p2.y - p1.y) * Math.PI / 180;
    const dLon = (p2.x - p1.x) * Math.PI / 180;
    const a = Math.sin(dLat / 2) * Math.sin(dLat / 2) +
              Math.cos(p1.y * Math.PI / 180) * Math.cos(p2.y * Math.PI / 180) *
              Math.sin(dLon / 2) * Math.sin(dLon / 2);
    const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
    return R * c;
  };

  const getMetricPoints = (coords: Point[]): Point[] => {
    if (coords.length === 0) return [];
    const minY = Math.min(...coords.map(p => p.y));
    const minX = Math.min(...coords.map(p => p.x));
    const latFactor = 111320; 
    const lonFactor = 40075000 * Math.cos(minY * Math.PI / 180) / 360;

    return coords.map(p => ({
      x: (p.x - minX) * lonFactor,
      y: (p.y - minY) * latFactor * -1
    }));
  };

  const metricPoints = data.koordinatlar ? getMetricPoints(data.koordinatlar) : [];

  let points: { x: number, y: number, id: number }[] = [];
  let sideLengths: number[] = [];
  let binaPoints: { x: number, y: number }[] = [];

  if (metricPoints.length > 0) {
    const xs = metricPoints.map(p => p.x);
    const ys = metricPoints.map(p => p.y);
    const w = Math.max(...xs) - Math.min(...xs);
    const h = Math.max(...ys) - Math.min(...ys);
    const scale = Math.min((canvasSize - padding * 2) / w, (canvasSize - padding * 2) / h);

    points = metricPoints.map((p, i) => ({
      x: padding + (p.x - Math.min(...xs)) * scale,
      y: padding + (p.y - Math.min(...ys)) * scale,
      id: i + 1
    }));

    for (let i = 0; i < data.koordinatlar!.length; i++) {
      const p1 = data.koordinatlar![i];
      const p2 = data.koordinatlar![(i + 1) % data.koordinatlar!.length];
      sideLengths.push(calculateDistance(p1, p2));
    }

    if (results) {
      const centerX = points.reduce((sum, p) => sum + p.x, 0) / points.length;
      const centerY = points.reduce((sum, p) => sum + p.y, 0) / points.length;
      // Arsa alanına göre bina alanının oranını bularak ölçekleme yapıyoruz
      const areaRatio = results.tabanAlani / data.alan;
      const scaleFactor = Math.sqrt(areaRatio); 

      binaPoints = points.map(p => ({
        x: centerX + (p.x - centerX) * scaleFactor,
        y: centerY + (p.y - centerY) * scaleFactor
      }));
    }
  }

  const renderPlot = () => {
    if (points.length === 0) {
      const size = 300;
      const offset = (canvasSize - size) / 2;
      return (
        <svg width={canvasSize} height={canvasSize}>
          <rect x={offset} y={offset} width={size} height={size} fill="none" stroke="#64748b" strokeWidth="2" strokeDasharray="4" />
          <text x={canvasSize/2} y={canvasSize/2} textAnchor="middle" className="text-xs font-bold fill-slate-400">Koordinat Verisi Bekleniyor...</text>
        </svg>
      );
    }

    const arsaPath = points.map(p => `${p.x},${p.y}`).join(' ');
    const binaPath = binaPoints.map(p => `${p.x},${p.y}`).join(' ');

    return (
      <svg width={canvasSize} height={canvasSize} className="overflow-visible">
        <defs>
          <pattern id="grid-large" width="50" height="50" patternUnits="userSpaceOnUse">
            <path d="M 50 0 L 0 0 0 50" fill="none" stroke="currentColor" strokeWidth="0.5" className="text-slate-200 dark:text-slate-800" />
          </pattern>
        </defs>
        <rect width="100%" height="100%" fill="url(#grid-large)" />

        {/* Arsa Dış Hattı */}
        <polygon points={arsaPath} fill="none" stroke="#1e293b" strokeWidth="4" strokeLinejoin="round" />

        {/* Çekme Mesafesi / Bina Oturumu */}
        {results && (
          <g>
            <polygon points={binaPath} className="fill-blue-500/10 stroke-blue-600" strokeWidth="2" strokeDasharray="5,3" strokeLinejoin="round" />
            <text 
              x={binaPoints.reduce((s,p) => s+p.x, 0)/binaPoints.length} 
              y={binaPoints.reduce((s,p) => s+p.y, 0)/binaPoints.length} 
              textAnchor="middle" 
              className="fill-blue-600 dark:fill-blue-400 font-black text-[10px] uppercase"
            >
              Bina Oturumu: {results.tabanAlani.toFixed(1)} m²
            </text>
          </g>
        )}

        {/* Köşeler ve Kenarlar */}
        {points.map((p, i) => {
          const nextP = points[(i + 1) % points.length];
          const midX = (p.x + nextP.x) / 2;
          const midY = (p.y + nextP.y) / 2;
          const angle = Math.atan2(nextP.y - p.y, nextP.x - p.x) * 180 / Math.PI;

          return (
            <g key={i}>
              <circle cx={p.x} cy={p.y} r="10" className="fill-white dark:fill-slate-900 stroke-slate-500" strokeWidth="1.5" />
              <text x={p.x} y={p.y} dy=".3em" textAnchor="middle" className="text-[8px] font-bold fill-slate-700 dark:fill-slate-300">{p.id}</text>

              <g transform={`translate(${midX},${midY}) rotate(${angle > 90 || angle < -90 ? angle + 180 : angle})`}>
                <text y="-5" textAnchor="middle" className="text-[9px] font-black fill-slate-500 bg-white px-1">
                  {sideLengths[i].toFixed(2)} m
                </text>
              </g>
            </g>
          );
        })}

        <text x="20" y="30" className="text-[10px] font-black fill-slate-400 uppercase tracking-widest italic opacity-50">TKGM Koordinat Bazlı Vaziyet Planı</text>
      </svg>
    );
  };

  return (
    <div id={id} className="bg-white dark:bg-slate-800 rounded-3xl shadow-2xl border border-gray-100 dark:border-slate-700 overflow-hidden">
      <div className="p-5 border-b border-gray-50 dark:border-slate-700 flex justify-between items-center bg-gray-50/50 dark:bg-slate-900/50">
        <h3 className="font-black text-slate-700 dark:text-slate-300 tracking-tight uppercase text-sm">Arsa Geometrisi & Kenar Uzunlukları</h3>
        <div className="flex gap-2">
           <span className="text-[9px] bg-blue-100 dark:bg-blue-900/40 text-blue-700 dark:text-blue-300 px-2 py-1 rounded-lg font-bold">WGS84 GPS</span>
        </div>
      </div>

      <div className="flex justify-center items-center overflow-auto min-h-[500px] bg-slate-50/20 dark:bg-slate-900/20">
        {renderPlot()}
      </div>

      <div className="p-4 bg-slate-900 text-white flex justify-around items-center border-t border-slate-800">
         <div className="text-center">
            <p className="text-[9px] font-black text-slate-500 uppercase">Arsa Alanı</p>
            <p className="text-lg font-black">{data.alan.toFixed(1)} <span className="text-[10px]">m²</span></p>
         </div>
         <div className="h-8 w-px bg-slate-800"></div>
         <div className="text-center">
            <p className="text-[9px] font-black text-slate-500 uppercase">Çevre</p>
            <p className="text-lg font-black">{sideLengths.reduce((a, b) => a + b, 0).toFixed(2)} <span className="text-[10px]">m</span></p>
         </div>
         <div className="h-8 w-px bg-slate-800"></div>
         <div className="text-center text-blue-400">
            <p className="text-[9px] font-black uppercase">Oturum</p>
            <p className="text-lg font-black">{results ? results.tabanAlani.toFixed(1) : "0"} <span className="text-[10px]">m²</span></p>
         </div>
      </div>
    </div>
  );
};

export default PlotVisualizer;

import React, { useState } from 'react';
import { NizamType, ArsaBilgileri, Point } from '../types';

