          <div className="flex gap-4">
            <button type="button" onClick={() => setStep(1)} className="flex-1 bg-gray-100 dark:bg-slate-700 font-bold py-4 rounded-2xl uppercase">Geri</button>
            <button type="submit" className="flex-[2] bg-blue-600 text-white font-black py-4 rounded-2xl shadow-xl shadow-blue-500/20 uppercase tracking-widest">Hesapla & Çiz</button>
          </div>
        </div>
      )}
    </form>
  );
};

