import React, { useState, useEffect } from 'react';
import { NizamType, ArsaBilgileri, HesapSonuclari } from './types';
import ConstructionForm from './components/ConstructionForm';
import PlotVisualizer from './components/PlotVisualizer';
import ResultsPanel from './components/ResultsPanel';
import Header from './components/Header';
import { GoogleGenAI } from "@google/genai";

const App: React.FC = () => {
  const [darkMode, setDarkMode] = useState(true);
  const [formData, setFormData] = useState<ArsaBilgileri | null>(null);
  const [results, setResults] = useState<HesapSonuclari | null>(null);
  const [isSearching, setIsSearching] = useState(false);

  useEffect(() => {
    if (darkMode) {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [darkMode]);

  const fetchUsakImarData = async (mahalle: string, ada: string, parsel: string) => {
    setIsSearching(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const prompt = `Uşak ili, ${mahalle} mahallesi, Ada: ${ada}, Parsel: ${parsel} için Uşak Belediyesi KEOS imar portalını sorgula. 
      Şu verileri bulmaya çalış: Arsa Alanı, TAKS, Kat Adedi (Hmax), Çekme mesafeleri.
      Sadece şu formatta JSON döndür: {"alan": 450, "taks": 0.30, "kat": 4, "onCekme": 5, "yanCekme": 3, "arkaCekme": 3}. Bulamadığın değer için 0 yaz.`;

      const response = await ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: prompt,
        config: {
          tools: [{ googleSearch: {} }],
        },
      });

      const text = response.text || "";
      const jsonMatch = text.match(/\{.*\}/s);
      if (jsonMatch) {
        return JSON.parse(jsonMatch[0]);
      }
      return null;
    } catch (error) {
      console.error("KEOS sorgu hatası:", error);
      return null;
    } finally {
      setIsSearching(false);
    }
  };

  const calculateData = (data: ArsaBilgileri) => {
    // KAKS: TAKS * Kat Adedi
    const kaks = data.taks * data.katAdedi;
    const tabanAlani = data.alan * data.taks;
    const zeminBrut = tabanAlani * 1.1;
    const normalKatBrut = zeminBrut * 1.15;
    const daireBasiMetrekare = normalKatBrut / data.daireSayisiTercihi;

    let daireTipi = "Özel Proje";
    // Mantık: 105 altı 1+1, 105-115 2+1, 115-150 3+1, 150+ 4+1
    if (daireBasiMetrekare < 105) daireTipi = "1+1 Apart";
    else if (daireBasiMetrekare >= 105 && daireBasiMetrekare < 115) daireTipi = "2+1 Daire";
    else if (daireBasiMetrekare >= 115 && daireBasiMetrekare < 150) daireTipi = "3+1 Daire";
    else if (daireBasiMetrekare >= 150) daireTipi = "4+1 Daire";

    setResults({
      kaks,
      tabanAlani,
      zeminBrut,
      normalKatBrut,
      toplamKat: data.katAdedi,
      daireTipi,
      daireBasiMetrekare
    });
    setFormData(data);
  };

  return (
    <div className="min-h-screen pb-12 transition-colors duration-300 bg-gray-50 dark:bg-slate-900 text-slate-900 dark:text-slate-100 font-sans">
      <Header darkMode={darkMode} setDarkMode={setDarkMode} />

      <main className="container mx-auto px-4 mt-8 max-w-6xl">
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
          <div className="space-y-6">
            <section className="bg-white dark:bg-slate-800 p-6 rounded-3xl shadow-2xl border border-gray-100 dark:border-slate-700">
              <h2 className="text-xl font-bold mb-6 flex items-center gap-2">
                <i className="fa-solid fa-hard-hat text-blue-600"></i>
                Proje Giriş Paneli
              </h2>
              <ConstructionForm 
                onCalculate={calculateData} 
                onSearchUsak={fetchUsakImarData} 
                isSearching={isSearching}
              />
            </section>
            {results && formData && (
              <div className="lg:hidden">
                <ResultsPanel results={results} data={formData} />
              </div>
            )}
          </div>

          <div id="main-report-container" className="space-y-6">
            {formData ? (
              <>
                <PlotVisualizer data={formData} results={results} />
                <div className="hidden lg:block">
                  {results && <ResultsPanel results={results} data={formData} />}
                </div>
              </>
            ) : (
              <div className="h-[500px] flex flex-col items-center justify-center bg-white dark:bg-slate-800 rounded-3xl border-4 border-dashed border-gray-200 dark:border-slate-700 text-center p-12">
                <i className="fa-solid fa-map-marked-alt text-7xl text-gray-200 dark:text-slate-700 mb-6"></i>
                <h3 className="text-xl font-bold text-gray-400 dark:text-slate-600">Arsa Çizimi Bekleniyor</h3>
                <p className="text-gray-400 dark:text-slate-600 mt-2">Lütfen koordinatları yapıştırın veya manuel verileri girip hesaplayın.</p>
              </div>
            )}
          </div>
        </div>
      </main>
    </div>
  );
};

export default App;

