);

interface ConstructionFormProps {
  onCalculate: (data: ArsaBilgileri) => void;
  onSearchUsak: (mahalle: string, ada: string, parsel: string) => Promise<any>;
  isSearching: boolean;
}

const ConstructionForm: React.FC<ConstructionFormProps> = ({ onCalculate, onSearchUsak, isSearching }) => {
  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState<any>({
    alan: '',
    nizam: NizamType.AYRIK,
    daireSayisiTercihi: 4,
    taks: '',
    katAdedi: '',
    cekmeOn: 5,
    cekmeYan: 3,
    cekmeArka: 3,
    il: 'Uşak',
    ilce: 'Merkez',
    mahalle: '',
    ada: '',
    parsel: '',
    geoJsonInput: ''
  });

  const parseTkgmData = (input: string): { points: Point[], alan?: number, ada?: string, parsel?: string } => {
    try {
      if (!input.trim()) return { points: [] };

      // JSON (GeoJSON) formatındaysa
      if (input.includes('features')) {
        const data = JSON.parse(input);
        const feature = data.features[0];
        const rawCoords = feature.geometry.coordinates[0];
        const points = rawCoords.map((c: any) => ({ x: c[0], y: c[1] }));
        return {
          points,
          alan: parseFloat(feature.properties?.Alan?.replace(',', '.')),
          ada: feature.properties?.Ada,
          parsel: feature.properties?.ParselNo
        };
      }

      // Ham koordinat listesi formatındaysa (Lat, Lon veya Lon, Lat)
      const lines = input.trim().split('\n');
      const points: Point[] = [];
      lines.forEach(line => {
        const parts = line.replace(/,/g, ' ').split(/\s+/).map(p => parseFloat(p.trim())).filter(p => !isNaN(p));
        if (parts.length >= 2) {
          // Genellikle TKGM: Lon(29.x), Lat(38.x) formatında verir
          points.push({ x: parts[0], y: parts[1] });
        }
      });
      return { points };
    } catch (e) {
      console.error("Veri ayıklama hatası:", e);
      return { points: [] };
    }
  };

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement>) => {
    const { name, value } = e.target;
    setFormData((prev: any) => ({ ...prev, [name]: value }));
  };

  const handleUsakSearch = async () => {
    if(!formData.mahalle || !formData.ada || !formData.parsel) return alert("Lütfen Ada/Parsel bilgilerini girin.");
    const result = await onSearchUsak(formData.mahalle, formData.ada, formData.parsel);
    if (result) {
      setFormData((prev: any) => ({ ...prev, ...result }));
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const tkgm = parseTkgmData(formData.geoJsonInput);

    onCalculate({
      ...formData,
      alan: tkgm.alan || Number(formData.alan),
      taks: Number(formData.taks) || 0.3,
      katAdedi: Number(formData.katAdedi) || 1,
      cekmeOn: Number(formData.cekmeOn),
      cekmeYan: Number(formData.cekmeYan),
      cekmeArka: Number(formData.cekmeArka),
      daireSayisiTercihi: Number(formData.daireSayisiTercihi),
      koordinatlar: tkgm.points.length > 0 ? tkgm.points : undefined
    });
  };

  return (
    <form onSubmit={handleSubmit} className="space-y-6">
      {step === 1 && (
        <div className="space-y-4 animate-in fade-in duration-500">
          <div className="bg-blue-50 dark:bg-blue-900/10 p-4 rounded-3xl border-2 border-dashed border-blue-200 dark:border-blue-800 space-y-3">
            <h4 className="text-[10px] font-black text-blue-700 uppercase tracking-widest flex items-center gap-2">
              <i className="fa-solid fa-file-import"></i> TKGM / GeoJSON Verisi
            </h4>
            <InputField 
              label="Veriyi Buraya Yapıştırın" 
              name="geoJsonInput" 
              type="textarea" 
              value={formData.geoJsonInput} 
              onChange={handleInputChange}
              required={false}
              placeholder='TKGM "İndir -> GeoJSON" içeriğini veya koordinat listesini buraya yapıştırın...' 
            />
          </div>

          <div className="grid grid-cols-3 gap-3">
            <InputField label="Mahalle" name="mahalle" value={formData.mahalle} onChange={handleInputChange} placeholder="Atatürk" />
            <InputField label="Ada" name="ada" value={formData.ada} onChange={handleInputChange} placeholder="4177" />
            <InputField label="Parsel" name="parsel" value={formData.parsel} onChange={handleInputChange} placeholder="7" />
          </div>

          <button type="button" onClick={handleUsakSearch} disabled={isSearching} className="w-full py-4 bg-emerald-600 text-white rounded-2xl font-black text-sm shadow-xl flex items-center justify-center gap-2">
            {isSearching ? <i className="fa-solid fa-sync fa-spin"></i> : <i className="fa-solid fa-search"></i>}
            KEOS SORGULA
          </button>

          <div className="grid grid-cols-2 gap-4">
            <InputField label="Arsa Alanı (m²)" name="alan" type="number" value={formData.alan} onChange={handleInputChange} icon="fa-chart-area" />
            <div className="space-y-1">
              <label className="text-[10px] font-extrabold text-gray-500 uppercase px-1">İmar Nizamı</label>
              <select name="nizam" value={formData.nizam} onChange={handleInputChange} className="w-full bg-gray-50 dark:bg-slate-900 border border-gray-200 dark:border-slate-700 rounded-2xl py-2.5 px-4 font-semibold outline-none focus:ring-2 focus:ring-blue-500">
                <option value={NizamType.AYRIK}>Ayrık Nizam</option>
                <option value={NizamType.BITISIK}>Bitişik Nizam</option>
              </select>
            </div>
          </div>

          <button type="button" onClick={() => setStep(2)} className="w-full bg-blue-600 text-white font-black py-4 rounded-2xl shadow-xl shadow-blue-500/20">
            HESAPLAMA DETAYLARI <i className="fa-solid fa-arrow-right ml-2"></i>
          </button>
        </div>
      )}

      {step === 2 && (
        <div className="space-y-4 animate-in slide-in-from-right duration-500">
          <div className="grid grid-cols-3 gap-3">
            <InputField label="Ön Çekme (m)" name="cekmeOn" type="number" value={formData.cekmeOn} onChange={handleInputChange} />
            <InputField label="Yan Çekme (m)" name="cekmeYan" type="number" value={formData.cekmeYan} onChange={handleInputChange} />
            <InputField label="Arka Çekme (m)" name="cekmeArka" type="number" value={formData.cekmeArka} onChange={handleInputChange} />
          </div>
          <div className="grid grid-cols-2 gap-4">
            <InputField label="T.A.K.S Değeri" name="taks" type="number" step="0.01" value={formData.taks} onChange={handleInputChange} placeholder="Örn: 0.30" />
            <InputField label="Resmi Kat Sayısı" name="katAdedi" type="number" value={formData.katAdedi} onChange={handleInputChange} placeholder="Örn: 3" />
          </div>
          <div className="space-y-1">
            <label className="text-[10px] font-black text-gray-500 uppercase px-1">Bir Katta İstenen Daire Sayısı</label>
            <div className="grid grid-cols-4 gap-2">
              {[1, 2, 3, 4].map(n => (
                <button key={n} type="button" onClick={() => setFormData((p:any) => ({...p, daireSayisiTercihi: n}))} className={`py-3 rounded-xl font-bold border-2 transition-all ${formData.daireSayisiTercihi === n ? 'bg-blue-600 border-blue-600 text-white shadow-lg' : 'bg-white dark:bg-slate-900 border-gray-100 dark:border-slate-700 text-gray-400'}`}>
                  {n} Daire
                </button>
              ))}
            </div>
          </div>
          <div className="flex gap-4 pt-4">
            <button type="button" onClick={() => setStep(1)} className="flex-1 bg-gray-100 dark:bg-slate-700 text-gray-600 dark:text-white font-black py-4 rounded-2xl uppercase">Geri</button>
            <button type="submit" className="flex-[2] bg-blue-600 text-white font-black py-4 rounded-2xl shadow-xl shadow-blue-500/20 uppercase tracking-widest">HESAPLA VE ÇİZ</button>
          </div>
        </div>
      )}
    </form>
  );
};

