import React from 'react';
import { ArsaBilgileri, HesapSonuclari, Point } from '../types';

interface PlotVisualizerProps {
  data: ArsaBilgileri;
  results: HesapSonuclari | null;
  id?: string;
}

const PlotVisualizer: React.FC<PlotVisualizerProps> = ({ data, results, id }) => {
  const canvasSize = 650;
  const padding = 120;

  // Koordinatları Metrik Sisteme (Piksel) Dönüştürme
  const getMetricPoints = (coords: Point[]): Point[] => {
    if (coords.length === 0) return [];

    // GPS verileri genellikle Lon, Lat (X, Y)
    const minX = Math.min(...coords.map(p => p.x));
    const maxX = Math.max(...coords.map(p => p.x));
    const minY = Math.min(...coords.map(p => p.y));
    const maxY = Math.max(...coords.map(p => p.y));

    // Ölçek katsayıları (Küçük alanlarda doğrusal yaklaşım yeterli)
    const w = maxX - minX;
    const h = maxY - minY;

    // En-boy oranını koruyarak sığdır
    const scale = Math.min((canvasSize - padding * 2) / w, (canvasSize - padding * 2) / h);

    return coords.map(p => ({
      x: padding + (p.x - minX) * scale,
      y: padding + (maxY - p.y) * scale // Y ekseni SVG'de terstir
    }));
  };

  const calculateDistance = (p1: Point, p2: Point): number => {
    // Haversine veya basit öklid (bu ölçekte fark etmez)
    const factor = 111320; // 1 derece ~111km
    const dx = (p1.x - p2.x) * factor * Math.cos(p1.y * Math.PI / 180);
    const dy = (p1.y - p2.y) * factor;
    return Math.sqrt(dx * dx + dy * dy);
  };

  const points = data.koordinatlar ? getMetricPoints(data.koordinatlar) : [];

  // Basit Vektörel Offset (Bina Oturumu İçin)
  const getOffsetPoints = (pts: Point[], setback: number): Point[] => {
    if (pts.length < 3) return [];
    const centerX = pts.reduce((s,p) => s+p.x, 0) / pts.length;
    const centerY = pts.reduce((s,p) => s+p.y, 0) / pts.length;

    // Alan oranına göre küçültme (Daha kompleks bir offset algoritması yerine MVP için ölçekleme)
    const areaRatio = results ? results.tabanAlani / data.alan : 0.6;
    const scale = Math.sqrt(areaRatio);

    return pts.map(p => ({
      x: centerX + (p.x - centerX) * scale,
      y: centerY + (p.y - centerY) * scale
    }));
  };

  const binaPoints = points.length > 0 ? getOffsetPoints(points, 5) : [];

  return (
    <div id={id} className="bg-white dark:bg-slate-800 rounded-[2.5rem] shadow-2xl border border-gray-100 dark:border-slate-700 overflow-hidden">
      <div className="p-6 bg-slate-50 dark:bg-slate-900/50 border-b border-gray-100 dark:border-slate-700 flex justify-between items-center">
        <div>
          <h3 className="font-black text-slate-800 dark:text-slate-200 tracking-tighter uppercase leading-none">VAZİYET PLANI TASLAĞI</h3>
          <p className="text-[10px] font-bold text-slate-400 mt-1 uppercase tracking-widest">TKGM Verileri & Çekme Mesafeleri</p>
        </div>
        <div className="flex gap-2">
           <span className="text-[10px] bg-blue-100 dark:bg-blue-900/40 text-blue-700 dark:text-blue-300 px-3 py-1.5 rounded-xl font-black uppercase">Ölçek: 1/100</span>
        </div>
      </div>

      <div className="relative flex justify-center items-center bg-[radial-gradient(#cbd5e1_1px,transparent_1px)] dark:bg-[radial-gradient(#1e293b_1px,transparent_1px)] [background-size:20px_20px] overflow-auto min-h-[550px] p-8">
        {points.length > 0 ? (
          <svg width={canvasSize} height={canvasSize} className="overflow-visible drop-shadow-2xl">
            {/* Arsa Dış Sınırı */}
            <polygon 
              points={points.map(p => `${p.x},${p.y}`).join(' ')} 
              fill="none" 
              stroke="#334155" 
              strokeWidth="4" 
              strokeLinejoin="round" 
            />

            {/* Bina Oturumu (Çekme Mesafesi Sonrası) */}
            {results && (
              <polygon 
                points={binaPoints.map(p => `${p.x},${p.y}`).join(' ')} 
                className="fill-blue-500/10 stroke-blue-600 animate-pulse" 
                strokeWidth="3" 
                strokeDasharray="8,4" 
                strokeLinejoin="round" 
              />
            )}

            {/* Köşe Numaraları ve Kenar Uzunlukları */}
            {points.map((p, i) => {
              const nextP = points[(i + 1) % points.length];
              const midX = (p.x + nextP.x) / 2;
              const midY = (p.y + nextP.y) / 2;

              const dist = data.koordinatlar ? calculateDistance(data.koordinatlar[i], data.koordinatlar[(i+1)%points.length]) : 0;

              return (
                <g key={i}>
                  {/* Köşe Noktası */}
                  <circle cx={p.x} cy={p.y} r="12" className="fill-white dark:fill-slate-900 stroke-slate-400" strokeWidth="2" />
                  <text x={p.x} y={p.y} dy=".35em" textAnchor="middle" className="text-[10px] font-black fill-slate-800 dark:fill-slate-200">{i+1}</text>

                  {/* Kenar Uzunluğu */}
                  <g transform={`translate(${midX},${midY})`}>
                    <rect x="-25" y="-12" width="50" height="15" rx="4" className="fill-white dark:fill-slate-800" fillOpacity="0.9" />
                    <text textAnchor="middle" className="text-[9px] font-black fill-blue-600 dark:fill-blue-400">
                      {dist > 0 ? dist.toFixed(2) + 'm' : ''}
                    </text>
                  </g>
                </g>
              );
            })}

            {/* Açıklama Kutusu */}
            <g transform={`translate(20, ${canvasSize - 40})`}>
