import React, { useState, useCallback, useEffect } from 'react';
import { NizamType, ArsaBilgileri, Point } from '../types';

interface ConstructionFormProps {
  onCalculate: (data: ArsaBilgileri) => void;
  onSearchUsak: (mahalle: string, ada: string, parsel: string) => Promise<any>;
  isSearching: boolean;
}

const ConstructionForm: React.FC<ConstructionFormProps> = ({ onCalculate, onSearchUsak, isSearching }) => {
  const [step, setStep] = useState(1);
  const [isDragging, setIsDragging] = useState(false);
  const [formData, setFormData] = useState<any>({
    alan: '',
    nizam: NizamType.AYRIK,
    daireSayisiTercihi: 4,
    taks: '',
    katAdedi: '',
    cekmeOn: 5,
    cekmeYan: 3,
    cekmeArka: 3,
    il: 'Uşak',
    ilce: 'Merkez',
    mahalle: '',
    ada: '',
    parsel: '',
    geoJsonInput: ''
  });

  // Gelişmiş GeoJSON ve Koordinat Ayıklayıcı
  const processRawInput = (input: string) => {
    try {
      if (input.includes('features')) {
        const data = JSON.parse(input);
        const feature = data.features[0];
        const rawCoords = feature.geometry.coordinates[0];

        // Poligon içindeki koordinatları temizle
        const points = rawCoords.map((c: any) => ({ x: c[0], y: c[1] }));

        // Otomatik Form Doldurma (TKGM Properties)
        const props = feature.properties || {};
        setFormData((prev: any) => ({
          ...prev,
          mahalle: props.Mahalle || prev.mahalle,
          ada: props.Ada || prev.ada,
          parsel: props.ParselNo || prev.parsel,
          alan: props.Alan ? parseFloat(props.Alan.replace(',', '.')) : prev.alan,
          geoJsonInput: input
        }));

        return points;
      }
      return [];
    } catch (e) {
      console.error("Parse error:", e);
      return [];
    }
  };

  // Sürükle Bırak İşleyicisi
  const handleDrop = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);
    const file = e.dataTransfer.files[0];
    if (file && (file.name.endsWith('.json') || file.name.endsWith('.geojson'))) {
      const reader = new FileReader();
      reader.onload = (event) => {
        const content = event.target?.result as string;
        processRawInput(content);
      };
      reader.readAsText(file);
    }
  }, []);

  // Global Yapıştırma İzleyici (Kullanıcı Ctrl+V yapınca algılar)
  useEffect(() => {
    const handlePaste = (e: ClipboardEvent) => {
      const paste = e.clipboardData?.getData('text');
      if (paste && paste.includes('features') && paste.includes('geometry')) {
        processRawInput(paste);
      }
    };
    window.addEventListener('paste', handlePaste);
    return () => window.removeEventListener('paste', handlePaste);
  }, []);

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement>) => {
    const { name, value } = e.target;
    setFormData((prev: any) => ({ ...prev, [name]: value }));
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const points = processRawInput(formData.geoJsonInput);
    onCalculate({
      ...formData,
      alan: Number(formData.alan),
      taks: Number(formData.taks) || 0.3,
      katAdedi: Number(formData.katAdedi) || 1,
      daireSayisiTercihi: Number(formData.daireSayisiTercihi),
      koordinatlar: points.length > 0 ? points : undefined
    });
  };

  return (
    <form onSubmit={handleSubmit} className="space-y-6">
      {step === 1 && (
        <div className="space-y-4">
          {/* AKILLI DROPZONE */}
          <div 
            onDragOver={(e) => { e.preventDefault(); setIsDragging(true); }}
            onDragLeave={() => setIsDragging(false)}
            onDrop={handleDrop}
            className={`relative group transition-all duration-500 border-4 border-dashed rounded-[2rem] p-8 text-center ${
              isDragging ? 'border-blue-500 bg-blue-50/50 scale-[1.02]' : 'border-gray-200 dark:border-slate-700 hover:border-blue-400'
            }`}
          >
            <div className="space-y-3">
              <div className="w-20 h-20 bg-blue-600 rounded-3xl mx-auto flex items-center justify-center shadow-2xl shadow-blue-500/40 transform group-hover:rotate-12 transition-transform">
                <i className="fa-solid fa-cloud-arrow-up text-3xl text-white"></i>
              </div>
              <div>
                <h4 className="font-black text-slate-800 dark:text-white uppercase tracking-tighter">TKGM Dosyasını Buraya Bırak</h4>
                <p className="text-xs text-slate-400 font-bold uppercase mt-1">Veya herhangi bir yere Ctrl+V ile yapıştır</p>
              </div>
            </div>
            {formData.geoJsonInput && (
              <div className="absolute top-4 right-4 animate-bounce">
                <span className="bg-emerald-500 text-white text-[10px] font-black px-3 py-1.5 rounded-full shadow-lg">VERİ YÜKLENDİ!</span>
              </div>
            )}
          </div>

          <div className="grid grid-cols-3 gap-3">
            <div className="space-y-1">
              <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Mahalle</label>
              <input name="mahalle" value={formData.mahalle} onChange={handleInputChange} className="w-full bg-gray-50 dark:bg-slate-900 border border-gray-200 dark:border-slate-700 rounded-xl py-2 px-3 text-sm font-bold" />
            </div>
            <div className="space-y-1">
              <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Ada</label>
              <input name="ada" value={formData.ada} onChange={handleInputChange} className="w-full bg-gray-50 dark:bg-slate-900 border border-gray-200 dark:border-slate-700 rounded-xl py-2 px-3 text-sm font-bold" />
            </div>
            <div className="space-y-1">
              <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Parsel</label>
              <input name="parsel" value={formData.parsel} onChange={handleInputChange} className="w-full bg-gray-50 dark:bg-slate-900 border border-gray-200 dark:border-slate-700 rounded-xl py-2 px-3 text-sm font-bold" />
            </div>
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div className="space-y-1">
              <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Arsa Alanı (m²)</label>
              <input type="number" name="alan" value={formData.alan} onChange={handleInputChange} className="w-full bg-gray-50 dark:bg-slate-900 border border-gray-200 dark:border-slate-700 rounded-xl py-2 px-3 text-sm font-bold text-blue-600" />
            </div>
            <div className="space-y-1">
              <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Nizam</label>
              <select name="nizam" value={formData.nizam} onChange={handleInputChange} className="w-full bg-gray-50 dark:bg-slate-900 border border-gray-200 dark:border-slate-700 rounded-xl py-2 px-3 text-sm font-bold">
                <option value={NizamType.AYRIK}>Ayrık Nizam</option>
                <option value={NizamType.BITISIK}>Bitişik Nizam</option>
              </select>
            </div>
          </div>

          <button type="button" onClick={() => setStep(2)} className="w-full bg-blue-600 text-white font-black py-4 rounded-2xl shadow-xl shadow-blue-500/20 active:scale-95 transition-all">
            HESAPLAMA ADIMINA GEÇ <i className="fa-solid fa-chevron-right ml-2"></i>
          </button>
        </div>
      )}

      {step === 2 && (
        <div className="space-y-4 animate-in slide-in-from-right duration-300">
          <div className="grid grid-cols-3 gap-3">
            <div className="space-y-1">
              <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Ön (m)</label>
              <input type="number" name="cekmeOn" value={formData.cekmeOn} onChange={handleInputChange} className="w-full bg-gray-50 dark:bg-slate-900 border border-gray-200 dark:border-slate-700 rounded-xl py-2 px-3 text-sm font-bold" />
            </div>
            <div className="space-y-1">
              <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Yan (m)</label>
              <input type="number" name="cekmeYan" value={formData.cekmeYan} onChange={handleInputChange} className="w-full bg-gray-50 dark:bg-slate-900 border border-gray-200 dark:border-slate-700 rounded-xl py-2 px-3 text-sm font-bold" />
            </div>
            <div className="space-y-1">
              <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Arka (m)</label>
              <input type="number" name="cekmeArka" value={formData.cekmeArka} onChange={handleInputChange} className="w-full bg-gray-50 dark:bg-slate-900 border border-gray-200 dark:border-slate-700 rounded-xl py-2 px-3 text-sm font-bold" />
            </div>
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div className="space-y-1">
              <label className="text-[10px] font-black text-slate-400 uppercase ml-1">TAKS Oranı</label>
              <input type="number" step="0.01" name="taks" value={formData.taks} onChange={handleInputChange} placeholder="0.30" className="w-full bg-gray-50 dark:bg-slate-900 border border-gray-200 dark:border-slate-700 rounded-xl py-2 px-3 text-sm font-bold" />
            </div>
            <div className="space-y-1">
              <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Kat Sayısı</label>
              <input type="number" name="katAdedi" value={formData.katAdedi} onChange={handleInputChange} className="w-full bg-gray-50 dark:bg-slate-900 border border-gray-200 dark:border-slate-700 rounded-xl py-2 px-3 text-sm font-bold text-emerald-600" />
            </div>
          </div>

          <div className="space-y-1">
            <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Kattaki Daire Sayısı</label>
            <div className="flex gap-2">
              {[1, 2, 3, 4].map(n => (
                <button 
                  key={n} 
                  type="button" 
                  onClick={() => setFormData((p:any) => ({...p, daireSayisiTercihi: n}))}
                  className={`flex-1 py-3 rounded-xl font-black text-sm transition-all border-2 ${
                    formData.daireSayisiTercihi === n 
                    ? 'bg-blue-600 border-blue-600 text-white shadow-lg' 
                    : 'bg-white dark:bg-slate-800 border-gray-100 dark:border-slate-700 text-slate-400'
                  }`}
                >
                  {n}
                </button>
              ))}
            </div>
          </div>

          <div className="flex gap-4 pt-4">
            <button type="button" onClick={() => setStep(1)} className="flex-1 bg-slate-100 dark:bg-slate-700 text-slate-500 dark:text-white font-black py-4 rounded-2xl uppercase text-xs">Geri</button>
            <button type="submit" className="flex-[2] bg-emerald-600 text-white font-black py-4 rounded-2xl shadow-xl shadow-emerald-500/20 uppercase text-xs tracking-widest">Analizi Başlat</button>
          </div>
        </div>
      )}
    </form>
  );
};

