import React from 'react';
import { ArsaBilgileri, HesapSonuclari, Point } from '../types';

interface PlotVisualizerProps {
  data: ArsaBilgileri;
  results: HesapSonuclari | null;
  id?: string;
}

const PlotVisualizer: React.FC<PlotVisualizerProps> = ({ data, results, id }) => {
  const canvasSize = 650;
  const padding = 120;

  const getMetricPoints = (coords: Point[]): Point[] => {
    if (coords.length === 0) return [];
    const minX = Math.min(...coords.map(p => p.x));
    const maxX = Math.max(...coords.map(p => p.x));
    const minY = Math.min(...coords.map(p => p.y));
    const maxY = Math.max(...coords.map(p => p.y));
    const w = maxX - minX;
    const h = maxY - minY;
    const scale = Math.min((canvasSize - padding * 2) / w, (canvasSize - padding * 2) / h);
    return coords.map(p => ({
      x: padding + (p.x - minX) * scale,
      y: padding + (maxY - p.y) * scale
    }));
  };

  const calculateDistance = (p1: Point, p2: Point): number => {
    const factor = 111320; 
    const dx = (p1.x - p2.x) * factor * Math.cos(p1.y * Math.PI / 180);
    const dy = (p1.y - p2.y) * factor;
    return Math.sqrt(dx * dx + dy * dy);
  };

  const points = data.koordinatlar ? getMetricPoints(data.koordinatlar) : [];

  const getOffsetPoints = (pts: Point[]): Point[] => {
    if (pts.length < 3) return [];
    const centerX = pts.reduce((s,p) => s+p.x, 0) / pts.length;
    const centerY = pts.reduce((s,p) => s+p.y, 0) / pts.length;
    const areaRatio = results ? results.tabanAlani / data.alan : 0.6;
    const scale = Math.sqrt(areaRatio);
    return pts.map(p => ({
      x: centerX + (p.x - centerX) * scale,
      y: centerY + (p.y - centerY) * scale
    }));
  };

  const binaPoints = points.length > 0 ? getOffsetPoints(points) : [];
  const bCenterX = binaPoints.length > 0 ? binaPoints.reduce((s,p) => s+p.x, 0) / binaPoints.length : 0;
  const bCenterY = binaPoints.length > 0 ? binaPoints.reduce((s,p) => s+p.y, 0) / binaPoints.length : 0;

  return (
    <div id={id} className="bg-white dark:bg-slate-800 rounded-[2.5rem] shadow-2xl border border-gray-100 dark:border-slate-700 overflow-hidden">
      <div className="p-6 bg-slate-50 dark:bg-slate-900/50 border-b border-gray-100 dark:border-slate-700 flex justify-between items-center">
        <div>
          <h3 className="font-black text-slate-800 dark:text-slate-200 tracking-tighter uppercase leading-none">PROFESYONEL VAZİYET PLANI</h3>
          <p className="text-[10px] font-bold text-slate-400 mt-1 uppercase tracking-widest">Akıllı Çekme Mesafeleri & Bina Kütlesi</p>
        </div>
        <div className="flex gap-2">
           <span className="text-[10px] bg-blue-100 dark:bg-blue-900/40 text-blue-700 dark:text-blue-300 px-3 py-1.5 rounded-xl font-black uppercase tracking-widest shadow-sm">Ölçek: 1/100</span>
        </div>
      </div>

      <div className="relative flex justify-center items-center bg-[radial-gradient(#cbd5e1_0.5px,transparent_0.5px)] dark:bg-[radial-gradient(#1e293b_1px,transparent_1px)] [background-size:25px_25px] overflow-auto min-h-[550px] p-8">
        {points.length > 0 ? (
          <svg width={canvasSize} height={canvasSize} className="overflow-visible drop-shadow-2xl">
            {/* Arsa Dış Sınırı */}
            <polygon 
              points={points.map(p => `${p.x},${p.y}`).join(' ')} 
              fill="#f8fafc" 
              className="dark:fill-slate-900/40"
              stroke="#334155" 
              strokeWidth="5" 
              strokeLinejoin="round" 
            />

            {/* Bina Oturumu Area */}
            {results && (
              <polygon 
                points={binaPoints.map(p => `${p.x},${p.y}`).join(' ')} 
                className="fill-blue-500/5 stroke-blue-500/30" 
                strokeWidth="2" 
                strokeDasharray="10,5" 
                strokeLinejoin="round" 
              />
            )}

            {/* MINYATUR APARTMAN GORSELI (İki Cepheli Perspektif) */}
            {results && binaPoints.length > 0 && (
              <g transform={`translate(${bCenterX - 40}, ${bCenterY - 45}) scale(1.2)`}>
                {/* Binanın Sol Cephesi */}
                <path d="M10 30 L40 10 L40 60 L10 80 Z" className="fill-blue-600 dark:fill-blue-700" />
                {/* Binanın Sağ Cephesi */}
                <path d="M40 10 L70 30 L70 80 L40 60 Z" className="fill-blue-400 dark:fill-blue-500" />
                {/* Binanın Çatısı */}
                <path d="M10 30 L40 10 L70 30 L40 50 Z" className="fill-blue-800 dark:fill-blue-900" />

                {/* Pencereler - Sol Cephe */}
                {[0, 1, 2].map(i => (
                  <g key={`w-l-${i}`} transform={`translate(0, ${i * 15})`}>
                    <rect x="15" y="40" width="8" height="8" className="fill-white/30" transform="skewY(15)" />
                    <rect x="28" y="32" width="8" height="8" className="fill-white/30" transform="skewY(15)" />
                  </g>
                ))}

                {/* Pencereler - Sağ Cephe */}
                {[0, 1, 2].map(i => (
                  <g key={`w-r-${i}`} transform={`translate(0, ${i * 15})`}>
                    <rect x="45" y="28" width="8" height="8" className="fill-white/30" transform="skewY(-15)" />
                    <rect x="58" y="36" width="8" height="8" className="fill-white/30" transform="skewY(-15)" />
                  </g>
                ))}

                {/* Bina Girişi */}
                <rect x="35" y="60" width="10" height="15" className="fill-slate-800" transform="skewY(-5)" />
              </g>
            )}

            {/* Köşe Numaraları ve Metrajlar */}
            {points.map((p, i) => {
              const nextP = points[(i + 1) % points.length];
              const midX = (p.x + nextP.x) / 2;
              const midY = (p.y + nextP.y) / 2;
              const dist = data.koordinatlar ? calculateDistance(data.koordinatlar[i], data.koordinatlar[(i+1)%points.length]) : 0;

              return (
                <g key={i}>
                  <circle cx={p.x} cy={p.y} r="10" className="fill-white dark:fill-slate-800 stroke-slate-400" strokeWidth="2" />
                  <text x={p.x} y={p.y} dy=".35em" textAnchor="middle" className="text-[9px] font-black fill-slate-800 dark:fill-slate-200">{i+1}</text>
                  <g transform={`translate(${midX},${midY})`}>
                    <rect x="-22" y="-10" width="44" height="14" rx="4" className="fill-white/90 dark:fill-slate-800/90 shadow-sm" />
                    <text textAnchor="middle" className="text-[8px] font-black fill-blue-600 dark:fill-blue-400">
                      {dist.toFixed(2)}m
                    </text>
                  </g>
                </g>
              );
            })}
          </svg>
        ) : (
          <div className="text-center text-slate-300 dark:text-slate-700 p-20 border-4 border-dashed border-slate-100 dark:border-slate-800 rounded-[3rem]">
             <i className="fa-solid fa-hotel text-9xl mb-6 opacity-20"></i>
             <p className="font-black text-xl uppercase tracking-tighter">Vaziyet Planı Hazır Değil</p>
             <p className="text-sm mt-2 font-medium">Koordinat verilerini eklediğinizde bina burada belirecek</p>
          </div>
        )}
      </div>

      <div className="p-6 bg-slate-900 text-white flex items-center justify-between">
         <div className="flex gap-10">
            <div>
               <p className="text-[10px] font-black text-slate-500 uppercase mb-1 tracking-widest">Parsel Alanı</p>
               <p className="text-2xl font-black">{data.alan.toFixed(1)} <span className="text-xs text-slate-400">m²</span></p>
            </div>
            <div className="w-px h-10 bg-slate-800"></div>
            <div>
               <p className="text-[10px] font-black text-blue-500 uppercase mb-1 tracking-widest">İnşaat Tabanı</p>
               <p className="text-2xl font-black text-blue-400">{results ? results.tabanAlani.toFixed(1) : "0"} <span className="text-xs text-blue-600">m²</span></p>
            </div>
         </div>
         <div className="flex flex-col items-end">
            <span className="text-[9px] bg-blue-500 text-white px-3 py-1 rounded-full font-black uppercase mb-2 animate-pulse">Mimari Öneri</span>
            <p className="text-xl font-black text-white">{results ? results.daireTipi : "-"}</p>
         </div>
      </div>
    </div>
  );
};

export default PlotVisualizer;

