import React, { useEffect, useRef } from 'react';
import * as THREE from 'three';
import { ArsaBilgileri, HesapSonuclari, Point } from '../types';

interface PlotVisualizerProps {
  data: ArsaBilgileri;
  results: HesapSonuclari | null;
  id?: string;
}

const PlotVisualizer: React.FC<PlotVisualizerProps> = ({ data, results, id }) => {
  const mountRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (!mountRef.current || !data.koordinatlar) return;

    // SCENE SETUP
    const width = mountRef.current.clientWidth;
    const height = 550;
    const scene = new THREE.Scene();
    scene.background = new THREE.Color(0x0f172a); // Slate-900

    const camera = new THREE.PerspectiveCamera(45, width / height, 0.1, 2000);
    camera.position.set(100, 100, 100);
    camera.lookAt(0, 0, 0);

    const renderer = new THREE.WebGLRenderer({ antialias: true, alpha: true });
    renderer.setSize(width, height);
    renderer.shadowMap.enabled = true;
    mountRef.current.innerHTML = '';
    mountRef.current.appendChild(renderer.domElement);

    // LIGHTING (Güneş Sistemi)
    const ambientLight = new THREE.AmbientLight(0xffffff, 0.6);
    scene.add(ambientLight);

    const sunLight = new THREE.DirectionalLight(0xfff5e1, 1.2);
    sunLight.position.set(50, 120, 50);
    sunLight.castShadow = true;
    sunLight.shadow.mapSize.width = 2048;
    sunLight.shadow.mapSize.height = 2048;
    scene.add(sunLight);

    // Arsa Koordinatlarını Normalleştirme
    const coords = data.koordinatlar;
    const minX = Math.min(...coords.map(p => p.x));
    const maxX = Math.max(...coords.map(p => p.x));
    const minY = Math.min(...coords.map(p => p.y));
    const maxY = Math.max(...coords.map(p => p.y));
    const scale = 500000; // Görsel ölçekleme faktörü

    const points3D = coords.map(p => new THREE.Vector2((p.x - minX) * scale, (p.y - minY) * scale));
    const centerX = ((maxX - minX) * scale) / 2;
    const centerY = ((maxY - minY) * scale) / 2;

    // ARSA ZEMİNİ
    const arsaShape = new THREE.Shape(points3D);
    const arsaGeo = new THREE.ShapeGeometry(arsaShape);
    const arsaMat = new THREE.MeshPhongMaterial({ color: 0x1e293b, side: THREE.DoubleSide });
    const arsaMesh = new THREE.Mesh(arsaGeo, arsaMat);
    arsaMesh.rotation.x = -Math.PI / 2;
    arsaMesh.position.set(-centerX, 0, centerY);
    arsaMesh.receiveShadow = true;
    scene.add(arsaMesh);

    // BİNA EKSTRÜZYONU (3D Bina)
    if (results) {
      const areaRatio = results.tabanAlani / data.alan;
      const bScale = Math.sqrt(areaRatio);

      const binaShape = new THREE.Shape();
      const bPoints = points3D.map(p => {
        const dx = p.x - centerX;
        const dy = p.y - centerY;
        return new THREE.Vector2(centerX + dx * bScale, centerY + dy * bScale);
      });

      binaShape.moveTo(bPoints[0].x, bPoints[0].y);
      bPoints.forEach((p, i) => i > 0 && binaShape.lineTo(p.x, p.y));

      const extrudeSettings = {
        depth: (data.katAdedi || 1) * 8, // Kat başına 8 birim yükseklik
        bevelEnabled: true,
        bevelThickness: 1,
        bevelSize: 0.5
      };

      const binaGeo = new THREE.ExtrudeGeometry(binaShape, extrudeSettings);
      const binaMat = new THREE.MeshStandardMaterial({ 
        color: 0x3b82f6, 
        roughness: 0.3, 
        metalness: 0.2,
        emissive: 0x1d4ed8,
        emissiveIntensity: 0.2
      });
      const binaMesh = new THREE.Mesh(binaGeo, binaMat);
      binaMesh.rotation.x = -Math.PI / 2;
      binaMesh.position.set(-centerX, 0, centerY);
      binaMesh.castShadow = true;
      scene.add(binaMesh);

      // Pencereler için basit bir Grid Helper dokusu simülasyonu
      const wireframe = new THREE.WireframeGeometry(binaGeo);
      const line = new THREE.LineSegments(wireframe);
      line.material.color.setHex(0xffffff);
      line.material.opacity = 0.1;
      line.material.transparent = true;
      line.rotation.x = -Math.PI / 2;
      line.position.set(-centerX, 0.1, centerY);
      scene.add(line);
    }

    // 3D PUSULA
    const compassGroup = new THREE.Group();
    const directions = ['K', 'D', 'G', 'B'];
    const colors = [0xef4444, 0xffffff, 0xffffff, 0xffffff];

    directions.forEach((dir, i) => {
      const arrowGeo = new THREE.ConeGeometry(2, 10, 8);
      const arrowMat = new THREE.MeshBasicMaterial({ color: colors[i] });
      const arrow = new THREE.Mesh(arrowGeo, arrowMat);
      const angle = (i * Math.PI) / 2;
      arrow.position.set(Math.sin(angle) * 15, 0, -Math.cos(angle) * 15);
      arrow.rotation.x = Math.PI / 2;
      arrow.rotation.z = -angle;
      compassGroup.add(arrow);
    });
    compassGroup.position.set(centerX + 20, 1, -centerY - 20);
    scene.add(compassGroup);

    // GRID VE YARDIMCILAR
    const grid = new THREE.GridHelper(500, 50, 0x334155, 0x1e293b);
    scene.add(grid);

    // ANIMATION LOOP
    const animate = () => {
      requestAnimationFrame(animate);
      scene.rotation.y += 0.002; // Hafif bir rotasyon
      renderer.render(scene, camera);
    };
    animate();

    const handleResize = () => {
      if (!mountRef.current) return;
      const w = mountRef.current.clientWidth;
      renderer.setSize(w, height);
      camera.aspect = w / height;
      camera.updateProjectionMatrix();
    };
    window.addEventListener('resize', handleResize);

    return () => {
      window.removeEventListener('resize', handleResize);
      mountRef.current?.removeChild(renderer.domElement);
    };
  }, [data, results]);

  return (
    <div id={id} className="relative bg-slate-900 rounded-[3rem] shadow-[0_50px_100px_-20px_rgba(0,0,0,0.5)] border border-slate-800 overflow-hidden group">
      <div className="absolute top-8 left-8 z-10">
        <h3 className="text-white font-black text-2xl tracking-tighter uppercase leading-none">3D VAZİYET KOKPİTİ</h3>
        <p className="text-blue-400 text-[10px] font-black uppercase tracking-[0.3em] mt-2 flex items-center gap-2">
          <span className="w-2 h-2 bg-blue-500 rounded-full animate-ping"></span>
          Canlı İzometrik Görünüm
        </p>
      </div>

      <div className="absolute top-8 right-8 z-10 flex gap-3">
        <div className="bg-slate-800/80 backdrop-blur-md px-4 py-2 rounded-2xl border border-slate-700 flex items-center gap-3">
          <i className="fa-solid fa-sun text-yellow-500 animate-spin-slow"></i>
          <span className="text-white text-[10px] font-bold uppercase tracking-widest">Güneş Simülasyonu Aktif</span>
        </div>
      </div>

      <div ref={mountRef} className="cursor-move" />

      <div className="absolute bottom-0 left-0 right-0 p-8 bg-gradient-to-t from-slate-950 to-transparent flex justify-between items-end">
        <div className="flex gap-12">
          <div>
            <p className="text-slate-500 text-[10px] font-black uppercase mb-1 tracking-widest">Arsa Alanı</p>
            <p className="text-3xl font-black text-white">{data.alan.toFixed(1)} <span className="text-sm text-slate-500">m²</span></p>
          </div>
          <div className="w-px h-12 bg-slate-800"></div>
          <div>
            <p className="text-blue-500 text-[10px] font-black uppercase mb-1 tracking-widest">Kat Yüksekliği</p>
            <p className="text-3xl font-black text-white">{(data.katAdedi * 3).toFixed(1)} <span className="text-sm text-slate-500">m</span></p>
          </div>
        </div>

        <div className="bg-blue-600 px-6 py-4 rounded-3xl shadow-2xl shadow-blue-500/20 transform group-hover:scale-105 transition-transform">
           <p className="text-[9px] font-black text-blue-200 uppercase tracking-widest mb-1">Daire Konsepti</p>
           <p className="text-white font-black text-lg uppercase tracking-tight">{results ? results.daireTipi : "PROJE BEKLENİYOR"}</p>
        </div>
      </div>
    </div>
  );
};

export default PlotVisualizer;

