import React, { useState, useCallback, useEffect } from 'react';
import { NizamType, ArsaBilgileri, Point } from '../types';

interface ConstructionFormProps {
  onCalculate: (data: ArsaBilgileri) => void;
  onSearchUsak: (mahalle: string, ada: string, parsel: string) => Promise<any>;
  isSearching: boolean;
}

const ConstructionForm: React.FC<ConstructionFormProps> = ({ onCalculate, onSearchUsak, isSearching }) => {
  const [step, setStep] = useState(1);
  const [isDragging, setIsDragging] = useState(false);
  const [formData, setFormData] = useState<any>({
    alan: '',
    nizam: NizamType.AYRIK,
    daireSayisiTercihi: 4,
    taks: '',
    katAdedi: '',
    cekmeOn: 5,
    cekmeYan: 3,
    cekmeArka: 3,
    il: 'Uşak',
    ilce: 'Merkez',
    mahalle: '',
    ada: '',
    parsel: '',
    geoJsonInput: ''
  });

  const processRawInput = (input: string) => {
    try {
      if (input.includes('features')) {
        const data = JSON.parse(input);
        const feature = data.features[0];
        const rawCoords = feature.geometry.coordinates[0];

        const points = rawCoords.map((c: any) => ({ x: c[0], y: c[1] }));

        const props = feature.properties || {};
        setFormData((prev: any) => ({
          ...prev,
          mahalle: props.Mahalle || prev.mahalle,
          ada: props.Ada || prev.ada,
          parsel: props.ParselNo || prev.parsel,
          alan: props.Alan ? parseFloat(props.Alan.replace(',', '.')) : prev.alan,
          geoJsonInput: input
        }));

        return points;
      }
      return [];
    } catch (e) {
      console.error("Parse error:", e);
      return [];
    }
  };

  const handleDrop = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);
    const file = e.dataTransfer.files[0];
    if (file && (file.name.endsWith('.json') || file.name.endsWith('.geojson'))) {
      const reader = new FileReader();
      reader.onload = (event) => {
        const content = event.target?.result as string;
        processRawInput(content);
      };
      reader.readAsText(file);
    }
  }, []);

  useEffect(() => {
    const handlePaste = (e: ClipboardEvent) => {
      const paste = e.clipboardData?.getData('text');
      if (paste && paste.includes('features') && paste.includes('geometry')) {
        processRawInput(paste);
      }
    };
    window.addEventListener('paste', handlePaste);
    return () => window.removeEventListener('paste', handlePaste);
  }, []);

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement>) => {
    const { name, value } = e.target;
    setFormData((prev: any) => ({ ...prev, [name]: value }));
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const points = processRawInput(formData.geoJsonInput);
    onCalculate({
      ...formData,
      alan: Number(formData.alan),
      taks: Number(formData.taks) || 0.3,
      katAdedi: Number(formData.katAdedi) || 1,
      daireSayisiTercihi: Number(formData.daireSayisiTercihi),
      koordinatlar: points.length > 0 ? points : undefined
    });
  };

  return (
    <form onSubmit={handleSubmit} className="space-y-6">
      {step === 1 && (
        <div className="space-y-4">
          <div 
            onDragOver={(e) => { e.preventDefault(); setIsDragging(true); }}
            onDragLeave={() => setIsDragging(false)}
            onDrop={handleDrop}
            className={`relative group transition-all duration-500 border-4 border-dashed rounded-[2rem] p-8 text-center ${
              isDragging ? 'border-blue-500 bg-blue-50/50 scale-[1.02]' : 'border-gray-200 dark:border-slate-700 hover:border-blue-400'
            }`}
          >
            <div className="space-y-3">
              <div className="w-20 h-20 bg-blue-600 rounded-3xl mx-auto flex items-center justify-center shadow-2xl shadow-blue-500/40 transform group-hover:rotate-12 transition-transform">
                <i className="fa-solid fa-cloud-arrow-up text-3xl text-white"></i>
              </div>
              <div>
                <h4 className="font-black text-slate-800 dark:text-white uppercase tracking-tighter">TKGM Dosyasını Buraya Bırak</h4>
                <p className="text-xs text-slate-400 font-bold uppercase mt-1">Veya herhangi bir yere Ctrl+V ile yapıştır</p>
              </div>
            </div>
            {formData.geoJsonInput && (
              <div className="absolute top-4 right-4 animate-bounce">
                <span className="bg-emerald-500 text-white text-[10px] font-black px-3 py-1.5 rounded-full shadow-lg">VERİ YÜKLENDİ!</span>
              </div>
            )}
          </div>

          <div className="grid grid-cols-3 gap-3">
            <div className="space-y-1">
              <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Mahalle</label>
              <input name="mahalle" value={formData.mahalle} onChange={handleInputChange} className="w-full bg-gray-50 dark:bg-slate-900 border border-gray-200 dark:border-slate-700 rounded-xl py-2 px-3 text-sm font-bold" />
            </div>
            <div className="space-y-1">
              <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Ada</label>
