import React, { useEffect, useRef } from 'react';
import * as THREE from 'three';
import { OrbitControls } from 'three/addons/controls/OrbitControls.js';
import { ArsaBilgileri, HesapSonuclari, Point } from '../types';

interface PlotVisualizerProps {
  data: ArsaBilgileri;
  results: HesapSonuclari | null;
  id?: string;
}

const PlotVisualizer: React.FC<PlotVisualizerProps> = ({ data, results, id }) => {
  const mountRef = useRef<HTMLDivElement>(null);
  const lastInteractionRef = useRef<number>(Date.now());

  useEffect(() => {
    if (!mountRef.current || !data.koordinatlar) return;

    const width = mountRef.current.clientWidth;
    const height = 550;
    const scene = new THREE.Scene();
    scene.background = new THREE.Color(0x0f172a); 

    const camera = new THREE.PerspectiveCamera(45, width / height, 0.1, 5000);
    camera.position.set(150, 150, 150);

    const renderer = new THREE.WebGLRenderer({ antialias: true, alpha: true });
    renderer.setSize(width, height);
    mountRef.current.innerHTML = '';
    mountRef.current.appendChild(renderer.domElement);

    const controls = new OrbitControls(camera, renderer.domElement);
    controls.enableDamping = true;
    controls.dampingFactor = 0.05;

    // INTERACTION TRACKING
    const updateInteraction = () => {
      lastInteractionRef.current = Date.now();
    };
    renderer.domElement.addEventListener('mousedown', updateInteraction);
    renderer.domElement.addEventListener('mousemove', updateInteraction);

    // LIGHTING (Gölgesiz, Soft Aydınlatma)
    const ambientLight = new THREE.AmbientLight(0xffffff, 0.8);
    scene.add(ambientLight);

    const mainLight = new THREE.PointLight(0xffffff, 1.0);
    mainLight.position.set(100, 200, 100);
    scene.add(mainLight);

    // COORDINATE SCALING
    const coords = data.koordinatlar;
    const minX = Math.min(...coords.map(p => p.x));
    const maxX = Math.max(...coords.map(p => p.x));
    const minY = Math.min(...coords.map(p => p.y));
    const maxY = Math.max(...coords.map(p => p.y));
    const scale = 500000; 

    const points3D = coords.map(p => new THREE.Vector2((p.x - minX) * scale, (p.y - minY) * scale));
    const centerX = ((maxX - minX) * scale) / 2;
    const centerY = ((maxY - minY) * scale) / 2;

    // ARSA ZEMİNİ
    const arsaShape = new THREE.Shape(points3D);
    const arsaGeo = new THREE.ShapeGeometry(arsaShape);
    const arsaMat = new THREE.MeshPhongMaterial({ color: 0x1e293b, side: THREE.DoubleSide, transparent: true, opacity: 0.8 });
    const arsaMesh = new THREE.Mesh(arsaGeo, arsaMat);
    arsaMesh.rotation.x = -Math.PI / 2;
    arsaMesh.position.set(-centerX, 0, centerY);
    scene.add(arsaMesh);

    // BLINKING ARSA SINIRI (Sarı - Lacivert)
    const boundaryPoints: THREE.Vector3[] = [];
    points3D.forEach(p => boundaryPoints.push(new THREE.Vector3(p.x, p.y, 0)));
    boundaryPoints.push(boundaryPoints[0]); // Kapat

    const boundaryGeo = new THREE.BufferGeometry().setFromPoints(boundaryPoints);
    const boundaryMat = new THREE.LineBasicMaterial({ color: 0xffff00, linewidth: 3 });
    const boundaryLine = new THREE.Line(boundaryGeo, boundaryMat);
    boundaryLine.rotation.x = -Math.PI / 2;
    boundaryLine.position.set(-centerX, 0.5, centerY);
    scene.add(boundaryLine);

    // GERÇEKÇİ BİNA MODELLEME
    if (results) {
      const areaRatio = results.tabanAlani / data.alan;
      const bScale = Math.sqrt(areaRatio);

      const binaShape = new THREE.Shape();
      const bPoints = points3D.map(p => {
        const dx = p.x - centerX;
        const dy = p.y - centerY;
        return new THREE.Vector2(centerX + dx * bScale, centerY + dy * bScale);
      });

      binaShape.moveTo(bPoints[0].x, bPoints[0].y);
      bPoints.forEach((p, i) => i > 0 && binaShape.lineTo(p.x, p.y));

      const katYuksekligi = 6;
      const totalHeight = (data.katAdedi || 1) * katYuksekligi;

      const extrudeSettings = { depth: totalHeight, bevelEnabled: false };
      const binaGeo = new THREE.ExtrudeGeometry(binaShape, extrudeSettings);
      const binaMat = new THREE.MeshStandardMaterial({ color: 0xe2e8f0, roughness: 0.7 });
      const binaMesh = new THREE.Mesh(binaGeo, binaMat);
      binaMesh.rotation.x = -Math.PI / 2;
      binaMesh.position.set(-centerX, 0, centerY);
      scene.add(binaMesh);

      // PENCERE VE KAPI EKLEME
      const windowColor = 0x0f172a;
      const windowMat = new THREE.MeshBasicMaterial({ color: windowColor });

      for (let floor = 0; floor < data.katAdedi; floor++) {
        const yPos = floor * katYuksekligi + 2;
        // Basitçe her kenara pencereler yerleştir
        bPoints.forEach((p, i) => {
          const nextP = bPoints[(i + 1) % bPoints.length];
          const dist = p.distanceTo(nextP);
          const numWindows = Math.floor(dist / 4);

          for (let w = 0; w < numWindows; w++) {
            const ratio = (w + 0.5) / numWindows;
            const wx = p.x + (nextP.x - p.x) * ratio;
            const wy = p.y + (nextP.y - p.y) * ratio;

            const winGeo = new THREE.PlaneGeometry(1.5, 2.5);
            const win = new THREE.Mesh(winGeo, windowMat);

            // Yüzey normalini hesapla
            const angle = Math.atan2(nextP.y - p.y, nextP.x - p.x) + Math.PI / 2;
            win.rotation.y = -angle;
            win.position.set(wx - centerX, yPos, wy + centerY);

            // Kapı kontrolü (Zemin kat, ilk kenar, orta)
            if (floor === 0 && i === 0 && w === Math.floor(numWindows/2)) {
                win.scale.set(1.5, 1.5, 1);
                win.position.y -= 1;
                win.material = new THREE.MeshBasicMaterial({ color: 0x1e293b });
            }

            scene.add(win);
          }
        });
      }

      // ÇATI
      const roofGeo = new THREE.ShapeGeometry(binaShape);
      const roofMat = new THREE.MeshStandardMaterial({ color: 0x475569 });
      const roof = new THREE.Mesh(roofGeo, roofMat);
      roof.rotation.x = -Math.PI / 2;
      roof.position.set(-centerX, totalHeight + 0.1, centerY);
      scene.add(roof);
    }

    // POCKET PUSULA (3D HUD Tarzı)
    const compassGroup = new THREE.Group();
    const compassBaseGeo = new THREE.CircleGeometry(10, 32);
    const compassBaseMat = new THREE.MeshBasicMaterial({ color: 0x1e293b, transparent: true, opacity: 0.8 });
    const compassBase = new THREE.Mesh(compassBaseGeo, compassBaseMat);
    compassBase.rotation.x = -Math.PI / 2;
    compassGroup.add(compassBase);

    const needleGeo = new THREE.ConeGeometry(1, 8, 4);
    const needleN = new THREE.Mesh(needleGeo, new THREE.MeshBasicMaterial({ color: 0xef4444 }));
    needleN.rotation.x = Math.PI / 2;
    needleN.position.z = -4;
    compassGroup.add(needleN);

    const needleS = new THREE.Mesh(needleGeo, new THREE.MeshBasicMaterial({ color: 0xffffff }));
    needleS.rotation.x = -Math.PI / 2;
    needleS.position.z = 4;
    compassGroup.add(needleS);

    // Pusulayı sahnenin bir köşesine sabitle (Görsel referans)
    compassGroup.position.set(centerX + 30, 10, -centerY - 30);
    scene.add(compassGroup);

    // GRID
    const grid = new THREE.GridHelper(1000, 50, 0x334155, 0x1e293b);
    scene.add(grid);

    // ANIMATION
    let frame = 0;
    const animate = () => {
      requestAnimationFrame(animate);
      frame++;

      // BLINKING LOGIC
      if (frame % 30 === 0) {
        boundaryMat.color.setHex(boundaryMat.color.getHex() === 0xffff00 ? 0x000080 : 0xffff00);
      }

      // AUTO ROTATION LOGIC (Inactivity > 5s)
      const timeSinceInteraction = Date.now() - lastInteractionRef.current;
      if (timeSinceInteraction > 5000) {
        scene.rotation.y += 0.003;
      }

      controls.update();
      renderer.render(scene, camera);
    };
    animate();

    const handleResize = () => {
      if (!mountRef.current) return;
      const w = mountRef.current.clientWidth;
      renderer.setSize(w, height);
      camera.aspect = w / height;
      camera.updateProjectionMatrix();
    };
    window.addEventListener('resize', handleResize);

    return () => {
      window.removeEventListener('resize', handleResize);
      renderer.domElement.removeEventListener('mousedown', updateInteraction);
      renderer.domElement.removeEventListener('mousemove', updateInteraction);
      mountRef.current?.removeChild(renderer.domElement);
    };
  }, [data, results]);

  return (
    <div id={id} className="relative bg-slate-900 rounded-[3rem] shadow-2xl border border-slate-800 overflow-hidden group">
      <div className="absolute top-8 left-8 z-10 pointer-events-none">
        <h3 className="text-white font-black text-2xl tracking-tighter uppercase leading-none">3D VAZİYET KOKPİTİ</h3>
        <p className="text-blue-400 text-[10px] font-black uppercase tracking-[0.3em] mt-2 flex items-center gap-2">
          <span className="w-2 h-2 bg-blue-500 rounded-full animate-ping"></span>
          Evrensel Serbest Bakış Aktif
        </p>
      </div>

      <div className="absolute top-8 right-8 z-10 flex gap-3 pointer-events-none">
        <div className="bg-slate-800/80 backdrop-blur-md px-4 py-2 rounded-2xl border border-slate-700 flex items-center gap-3 shadow-xl">
          <i className="fa-solid fa-compass text-blue-500"></i>
          <span className="text-white text-[10px] font-bold uppercase tracking-widest">3D Cep Pusulası</span>
        </div>
      </div>

      <div ref={mountRef} className="cursor-move" />

      <div className="absolute bottom-0 left-0 right-0 p-8 bg-gradient-to-t from-slate-950 to-transparent flex justify-between items-end pointer-events-none">
        <div className="flex gap-12">
          <div>
            <p className="text-slate-500 text-[10px] font-black uppercase mb-1 tracking-widest">Arsa Alanı</p>
            <p className="text-3xl font-black text-white">{data.alan.toFixed(1)} <span className="text-sm text-slate-500">m²</span></p>
          </div>
          <div className="w-px h-12 bg-slate-800"></div>
          <div>
            <p className="text-blue-500 text-[10px] font-black uppercase mb-1 tracking-widest">Bina Yüksekliği</p>
            <p className="text-3xl font-black text-white">{(data.katAdedi * 6).toFixed(1)} <span className="text-sm text-slate-500">m</span></p>
          </div>
        </div>

        <div className="bg-blue-600 px-6 py-4 rounded-3xl shadow-2xl shadow-blue-500/20 transform group-hover:translate-y-[-5px] transition-transform">
           <p className="text-[9px] font-black text-blue-200 uppercase tracking-widest mb-1">Daire Konsepti</p>
           <p className="text-white font-black text-lg uppercase tracking-tight">{results ? results.daireTipi : "PROJE BEKLENİYOR"}</p>
        </div>
      </div>

      {/* Kontrol İpucu */}
      <div className="absolute bottom-8 right-8 bg-black/40 backdrop-blur px-3 py-1 rounded-full border border-white/10 opacity-0 group-hover:opacity-100 transition-opacity">
        <p className="text-[8px] text-white font-medium uppercase tracking-tighter">Sol Tık: Döndür | Kaydırma: Yaklaş</p>
      </div>
    </div>
  );
};

