    let hudRenderer: THREE.WebGLRenderer | null = null;
    let hudScene: THREE.Scene | null = null;
    let hudCamera: THREE.PerspectiveCamera | null = null;
    let hudNeedle: THREE.Group | null = null;

    if (compassHUDRef.current) {
        hudRenderer = new THREE.WebGLRenderer({ antialias: true, alpha: true });
        hudRenderer.setSize(120, 120);
        compassHUDRef.current.appendChild(hudRenderer.domElement);

        hudScene = new THREE.Scene();
        hudCamera = new THREE.PerspectiveCamera(45, 1, 0.1, 100);
        hudCamera.position.set(0, 15, 0);
        hudCamera.lookAt(0, 0, 0);

        const hudBaseGeo = new THREE.CircleGeometry(4, 32);
        const hudBaseMat = new THREE.MeshBasicMaterial({ color: 0x1e293b, transparent: true, opacity: 0.9 });
        const hudBase = new THREE.Mesh(hudBaseGeo, hudBaseMat);
        hudBase.rotation.x = -Math.PI / 2;
        hudScene.add(hudBase);

        hudNeedle = new THREE.Group();
        const coneGeo = new THREE.ConeGeometry(0.5, 3, 4);
        const needleN = new THREE.Mesh(coneGeo, new THREE.MeshBasicMaterial({ color: 0xef4444 }));
        needleN.rotation.x = Math.PI / 2;
        needleN.position.z = -1.5;
        hudNeedle.add(needleN);

        const needleS = new THREE.Mesh(coneGeo, new THREE.MeshBasicMaterial({ color: 0xffffff }));
        needleS.rotation.x = -Math.PI / 2;
        needleS.position.z = 1.5;
        hudNeedle.add(needleS);

        hudScene.add(hudNeedle);
    }

    // ANIMATION
    let frame = 0;
    const clock = new THREE.Clock();

    const animate = () => {
      requestAnimationFrame(animate);
      const time = clock.getElapsedTime();
      frame++;

      // RGB SMOOTH TRANSITION (3 saniyede bir tur)
      const hue = (time / 10) % 1; // Daha yavaş geçiş için 10
      boundaryMat.color.setHSL(hue, 1.0, 0.5);

      // AUTO ROTATION LOGIC
      const timeSinceInteraction = Date.now() - lastInteractionRef.current;
      if (timeSinceInteraction > 5000) {
        scene.rotation.y += 0.003;
      }

      // Update Compass HUD
      if (hudNeedle && hudRenderer && hudScene && hudCamera) {
          // Pusula iğnesi sahne rotasyonunu takip eder
          hudNeedle.rotation.y = -scene.rotation.y;
          hudRenderer.render(hudScene, hudCamera);
      }

      controls.update();
      renderer.render(scene, camera);
    };
    animate();

    const handleResize = () => {
      if (!mountRef.current) return;
      const w = mountRef.current.clientWidth;
      renderer.setSize(w, height);
      camera.aspect = w / height;
      camera.updateProjectionMatrix();
    };
    window.addEventListener('resize', handleResize);

    return () => {
      window.removeEventListener('resize', handleResize);
      renderer.domElement.removeEventListener('mousedown', updateInteraction);
      renderer.domElement.removeEventListener('mousemove', updateInteraction);
      mountRef.current?.removeChild(renderer.domElement);
      if (compassHUDRef.current && hudRenderer) {
          compassHUDRef.current.innerHTML = '';
      }
    };
  }, [data, results]);

  return (
    <div id={id} className="relative bg-slate-900 rounded-[3rem] shadow-2xl border border-slate-800 overflow-hidden group">
      {/* Header UI */}
      <div className="absolute top-8 left-8 z-10 pointer-events-none">
        <h3 className="text-white font-black text-2xl tracking-tighter uppercase leading-none">3D VAZİYET KOKPİTİ</h3>
        <div className="flex items-center gap-2 mt-2">
            <span className="w-2 h-2 bg-emerald-500 rounded-full animate-pulse"></span>
            <p className="text-emerald-400 text-[10px] font-black uppercase tracking-[0.3em]">
              SİSTEM AKTİF: {(data.katAdedi * 6).toFixed(1)}m Yapı
            </p>
        </div>
      </div>

      {/* 3D HUD COMPASS (Cep Pusulası) */}
      <div className="absolute top-8 right-8 z-20 pointer-events-none">
        <div className="bg-slate-800/90 backdrop-blur-xl p-3 rounded-[2rem] border border-slate-700/50 shadow-2xl flex flex-col items-center">
          <div ref={compassHUDRef} className="w-[120px] h-[120px]" />
          <div className="mt-[-10px] pb-2 text-center">
            <span className="text-[9px] font-black text-slate-500 uppercase tracking-widest">Gerçek Zamanlı</span>
            <p className="text-[11px] font-black text-white uppercase tracking-tighter">Cep Pusulası</p>
          </div>
        </div>
      </div>

      {/* Main Canvas Container */}
      <div ref={mountRef} className="cursor-move" />

      {/* Bottom Data HUD */}
      <div className="absolute bottom-0 left-0 right-0 p-8 bg-gradient-to-t from-slate-950 via-slate-900/40 to-transparent flex justify-between items-end pointer-events-none">
        <div className="flex gap-12">
          <div className="group/stat">
            <p className="text-slate-500 text-[10px] font-black uppercase mb-1 tracking-widest group-hover/stat:text-blue-500 transition-colors">Arsa Sınırı</p>
            <div className="flex items-center gap-2">
                <div className="w-3 h-3 rounded-full bg-blue-500 shadow-[0_0_10px_rgba(59,130,246,0.8)]"></div>
                <p className="text-3xl font-black text-white">{data.alan.toFixed(1)} <span className="text-sm text-slate-500">m²</span></p>
            </div>
          </div>
          <div className="w-px h-12 bg-slate-800/50"></div>
          <div>
            <p className="text-emerald-500 text-[10px] font-black uppercase mb-1 tracking-widest">Yapı Oturumu</p>
            <p className="text-3xl font-black text-white">{results ? results.tabanAlani.toFixed(1) : "0.0"} <span className="text-sm text-slate-500">m²</span></p>
          </div>
        </div>

        <div className="bg-gradient-to-br from-blue-600 to-indigo-700 px-8 py-5 rounded-[2.5rem] shadow-2xl shadow-blue-900/40 transform group-hover:translate-y-[-10px] transition-all duration-500 border border-blue-400/20">
           <p className="text-[9px] font-black text-blue-200 uppercase tracking-[0.2em] mb-1">Mühendislik Önerisi</p>
           <p className="text-white font-black text-xl uppercase tracking-tight">{results ? results.daireTipi : "PROJE BEKLENİYOR"}</p>
        </div>
      </div>

      {/* Control Overlay */}
      <div className="absolute bottom-8 right-8 bg-black/60 backdrop-blur-md px-4 py-2 rounded-full border border-white/10 opacity-0 group-hover:opacity-100 transition-all duration-500 translate-y-4 group-hover:translate-y-0 shadow-2xl pointer-events-none">
        <p className="text-[9px] text-white font-bold uppercase tracking-widest flex items-center gap-2">
            <i className="fa-solid fa-hand-pointer text-blue-400"></i>
            SOL TIK: DÖNDÜR | TEKERLEK: YAKLAŞ
        </p>
      </div>
    </div>
  );
