import React, { useState, useCallback, useEffect } from 'react';
import { NizamType, ArsaBilgileri, Point } from '../types';

interface ConstructionFormProps {
  onCalculate: (data: ArsaBilgileri) => void;
  onSearchUsak: (mahalle: string, ada: string, parsel: string) => Promise<any>;
  isSearching: boolean;
}

const ConstructionForm: React.FC<ConstructionFormProps> = ({ onCalculate, onSearchUsak, isSearching }) => {
  const [step, setStep] = useState(1);
  const [isDragging, setIsDragging] = useState(false);
  const [isFetchingZoning, setIsFetchingZoning] = useState(false);
  const [formData, setFormData] = useState<any>({
    alan: '',
    nizam: NizamType.AYRIK,
    daireSayisiTercihi: 4,
    taks: '0.30',
    katAdedi: '',
    kaks: '', // Emsal değeri
    cekmeOn: 5,
    cekmeYan: 3,
    cekmeArka: 3,
    il: 'Uşak',
    ilce: 'Merkez',
    mahalle: '',
    ada: '',
    parsel: '',
    geoJsonInput: ''
  });

  const processRawInput = (input: string) => {
    try {
      if (input.includes('features')) {
        const data = JSON.parse(input);
        const feature = data.features[0];
        const rawCoords = feature.geometry.coordinates[0];
        const points = rawCoords.map((c: any) => ({ x: c[0], y: c[1] }));
        const props = feature.properties || {};

        setFormData((prev: any) => ({
          ...prev,
          mahalle: props.Mahalle || prev.mahalle,
          ada: props.Ada || prev.ada,
          parsel: props.ParselNo || prev.parsel,
          alan: props.Alan ? parseFloat(props.Alan.replace(',', '.')) : prev.alan,
          geoJsonInput: input
        }));
        return points;
      }
      return [];
    } catch (e) {
      return [];
    }
  };

  const handleFetchFromKeos = async () => {
    if (!formData.ada || !formData.parsel) {
      alert("Lütfen önce Ada ve Parsel bilgilerini giriniz.");
      return;
    }
    setIsFetchingZoning(true);
    try {
      // Bu bölüm Gemini API üzerinden Uşak KEOS verilerini aratır (Grounding simülasyonu)
      const info = await onSearchUsak(formData.mahalle, formData.ada, formData.parsel);
      if (info) {
        setFormData((prev: any) => ({
          ...prev,
          katAdedi: info.kat || prev.katAdedi,
          kaks: info.emsal || prev.kaks
        }));
      }
    } finally {
      setIsFetchingZoning(false);
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const points = processRawInput(formData.geoJsonInput);
    onCalculate({
      ...formData,
      alan: Number(formData.alan),
      taks: Number(formData.taks),
      katAdedi: Number(formData.katAdedi),
      kaks: Number(formData.kaks),
      daireSayisiTercihi: Number(formData.daireSayisiTercihi),
      koordinatlar: points.length > 0 ? points : undefined
    });
  };

  return (
    <form onSubmit={handleSubmit} className="space-y-6">
      {step === 1 && (
        <div className="space-y-4">
          <div className="relative group transition-all duration-500 border-4 border-dashed rounded-[2rem] p-8 text-center border-gray-200 dark:border-slate-700 hover:border-blue-400">
            <div className="space-y-3">
              <div className="w-20 h-20 bg-blue-600 rounded-3xl mx-auto flex items-center justify-center shadow-2xl">
                <i className="fa-solid fa-cloud-arrow-up text-3xl text-white"></i>
              </div>
              <h4 className="font-black text-slate-800 dark:text-white uppercase tracking-tighter">TKGM Dosyası veya Ctrl+V</h4>
            </div>
          </div>

          <div className="grid grid-cols-3 gap-3">
            <input placeholder="Mahalle" name="mahalle" value={formData.mahalle} onChange={(e)=>setFormData({...formData, mahalle: e.target.value})} className="w-full bg-gray-50 dark:bg-slate-900 border border-gray-200 dark:border-slate-700 rounded-xl py-2 px-3 text-sm font-bold" />
            <input placeholder="Ada" name="ada" value={formData.ada} onChange={(e)=>setFormData({...formData, ada: e.target.value})} className="w-full bg-gray-50 dark:bg-slate-900 border border-gray-200 dark:border-slate-700 rounded-xl py-2 px-3 text-sm font-bold" />
            <input placeholder="Parsel" name="parsel" value={formData.parsel} onChange={(e)=>setFormData({...formData, parsel: e.target.value})} className="w-full bg-gray-50 dark:bg-slate-900 border border-gray-200 dark:border-slate-700 rounded-xl py-2 px-3 text-sm font-bold" />
          </div>

          <button type="button" onClick={handleFetchFromKeos} disabled={isFetchingZoning} className="w-full bg-slate-800 text-blue-400 font-black py-3 rounded-xl border border-slate-700 flex items-center justify-center gap-2 hover:bg-slate-700 transition-colors uppercase text-[10px] tracking-widest">
            {isFetchingZoning ? <i className="fa-solid fa-circle-notch animate-spin"></i> : <i className="fa-solid fa-earth-africa"></i>}
            KEOS'tan Bilgileri Getir (Uşak)
          </button>

          <div className="grid grid-cols-2 gap-4">
            <input type="number" placeholder="Alan (m²)" name="alan" value={formData.alan} onChange={(e)=>setFormData({...formData, alan: e.target.value})} className="w-full bg-gray-50 dark:bg-slate-900 border border-gray-200 dark:border-slate-700 rounded-xl py-2 px-3 text-sm font-bold" />
            <select name="nizam" value={formData.nizam} onChange={(e)=>setFormData({...formData, nizam: e.target.value})} className="w-full bg-gray-50 dark:bg-slate-900 border border-gray-200 dark:border-slate-700 rounded-xl py-2 px-3 text-sm font-bold">
                <option value={NizamType.AYRIK}>Ayrık Nizam</option>
                <option value={NizamType.BITISIK}>Bitişik Nizam</option>
            </select>
          </div>

          <button type="button" onClick={() => setStep(2)} className="w-full bg-blue-600 text-white font-black py-4 rounded-2xl shadow-xl active:scale-95 transition-all">
            HESAPLAMA ADIMINA GEÇ <i className="fa-solid fa-chevron-right ml-2"></i>
          </button>
        </div>
      )}

      {step === 2 && (
        <div className="space-y-4 animate-in slide-in-from-right duration-300">
          <div className="grid grid-cols-2 gap-4">
            <div className="space-y-1">
              <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Kat Sayısı <span className="text-blue-500">(Bodrum Hariç)</span></label>
              <input type="number" name="katAdedi" value={formData.katAdedi} onChange={(e)=>setFormData({...formData, katAdedi: e.target.value})} className="w-full bg-gray-50 dark:bg-slate-900 border border-gray-200 dark:border-slate-700 rounded-xl py-2 px-3 text-sm font-bold" />
            </div>
            <div className="space-y-1">
              <label className="text-[10px] font-black text-slate-400 uppercase ml-1">K.A.K.S (Emsal)</label>
              <input type="number" step="0.01" name="kaks" value={formData.kaks} onChange={(e)=>setFormData({...formData, kaks: e.target.value})} className="w-full bg-gray-50 dark:bg-slate-900 border border-gray-200 dark:border-slate-700 rounded-xl py-2 px-3 text-sm font-bold" />
            </div>
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div className="space-y-1">
              <label className="text-[10px] font-black text-slate-400 uppercase ml-1">TAKS Oranı</label>
              <input type="number" step="0.01" name="taks" value={formData.taks} onChange={(e)=>setFormData({...formData, taks: e.target.value})} className="w-full bg-gray-50 dark:bg-slate-900 border border-gray-200 dark:border-slate-700 rounded-xl py-2 px-3 text-sm font-bold" />
            </div>
            <div className="space-y-1">
              <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Kattaki Daire Sayısı</label>
              <div className="flex gap-1">
                {[1, 2, 3, 4].map(n => (
                  <button key={n} type="button" onClick={() => setFormData({...formData, daireSayisiTercihi: n})} className={`flex-1 py-2 rounded-lg font-black text-xs ${formData.daireSayisiTercihi === n ? 'bg-blue-600 text-white' : 'bg-slate-100 dark:bg-slate-800 text-slate-400'}`}>{n}</button>
                ))}
              </div>
            </div>
          </div>

          <div className="flex gap-4 pt-4">
            <button type="button" onClick={() => setStep(1)} className="flex-1 bg-slate-100 dark:bg-slate-700 text-slate-500 dark:text-white font-black py-4 rounded-2xl uppercase text-[10px]">Geri</button>
            <button type="submit" className="flex-[2] bg-emerald-600 text-white font-black py-4 rounded-2xl shadow-xl uppercase text-[10px] tracking-widest">Analizi Başlat</button>
          </div>
        </div>
      )}
    </form>
  );
};

export default ConstructionForm;

import React, { useState, useEffect } from 'react';
import { NizamType, ArsaBilgileri, HesapSonuclari, LocationAnalysisData } from './types';
import ConstructionForm from './components/ConstructionForm';
import PlotVisualizer from './components/PlotVisualizer';
import ResultsPanel from './components/ResultsPanel';
import Header from './components/Header';
import { GoogleGenAI } from "@google/genai";

const App: React.FC = () => {
  const [darkMode, setDarkMode] = useState(true);
  const [formData, setFormData] = useState<ArsaBilgileri | null>(null);
  const [results, setResults] = useState<HesapSonuclari | null>(null);
  const [isSearching, setIsSearching] = useState(false);

  useEffect(() => {
    if (darkMode) {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [darkMode]);

  const searchUsakZoning = async (mahalle: string, ada: string, parsel: string) => {
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const prompt = `Uşak İli Merkez İlçesi ${mahalle} Mahallesi Ada ${ada} Parsel ${parsel} için güncel imar durumundaki Kat Adedi ve KAKS (Emsal) bilgilerini bul. 
      Eğer bulamazsan bölge için tahmini/standart bir değer dön. Yanıtı JSON olarak ver: {"kat": 4, "emsal": 1.20}`;

      const response = await ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: prompt,
        config: { tools: [{ googleSearch: {} }] },
      });

      const jsonMatch = response.text?.match(/\{.*\}/s);
      return jsonMatch ? JSON.parse(jsonMatch[0]) : { kat: 3, emsal: 0.90 };
    } catch (e) {
      return { kat: 3, emsal: 0.90 };
    }
  };

  const calculateData = async (data: ArsaBilgileri) => {
    setIsSearching(true);

    // KAKS doğrudan kullanıcıdan veya KEOS'tan gelen emsal değeridir
    const kaks = data.kaks || (data.taks * data.katAdedi);
    const tabanAlani = data.alan * data.taks;
    const zeminBrut = tabanAlani * 1.1;
    const normalKatBrut = zeminBrut * 1.15;
    const daireBasiMetrekare = normalKatBrut / data.daireSayisiTercihi;

    let daireTipi = "Özel";
    if (daireBasiMetrekare < 105) daireTipi = "1+1 Apart";
    else if (daireBasiMetrekare < 115) daireTipi = "2+1";
    else if (daireBasiMetrekare < 150) daireTipi = "3+1";
    else daireTipi = "4+1";

    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const locationInfo = await ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: `${data.il} ${data.ilce} ${data.mahalle} Ada ${data.ada} çevresini analiz et. JSON dön: {"score": 80, "summary": "Hızlı gelişen bölge", "nearbyPlaces": ["Merkez Park", "AVM"]}`,
        config: { tools: [{ googleSearch: {} }] },
    }).then(res => {
        const match = res.text?.match(/\{.*\}/s);
        return match ? JSON.parse(match[0]) : null;
    }).catch(() => null);

    setResults({
      kaks,
      tabanAlani,
      zeminBrut,
      normalKatBrut,
      toplamKat: data.katAdedi,
      daireTipi,
      daireBasiMetrekare,
      locationAnalysis: locationInfo || undefined
    });
    setFormData(data);
    setIsSearching(false);
  };

  return (
    <div className="min-h-screen pb-12 transition-colors duration-300 bg-gray-50 dark:bg-slate-900 text-slate-900 dark:text-slate-100">
      <Header darkMode={darkMode} setDarkMode={setDarkMode} />

      <main className="container mx-auto px-4 mt-8 max-w-7xl">
        <div className="grid grid-cols-1 xl:grid-cols-12 gap-8 relative">

          {isSearching && (
            <div className="fixed inset-0 z-[100] bg-slate-950/80 backdrop-blur-xl flex flex-col items-center justify-center animate-in fade-in duration-300">
               <div className="w-24 h-24 border-4 border-blue-500/20 border-t-blue-500 rounded-full animate-spin"></div>
               <h2 className="mt-8 text-2xl font-black uppercase tracking-[0.3em] text-white">Analiz Yapılıyor...</h2>
            </div>
          )}

          <div className="xl:col-span-4">
            <section className="bg-white dark:bg-slate-800/50 backdrop-blur-xl p-6 rounded-[2.5rem] shadow-2xl border border-gray-100 dark:border-slate-700/50">
              <ConstructionForm 
                onCalculate={calculateData} 
                onSearchUsak={searchUsakZoning} 
                isSearching={isSearching}
              />
            </section>
          </div>

          <div className="xl:col-span-8 space-y-8">
            {formData ? (
              <div className="space-y-8 animate-in fade-in zoom-in duration-500">
                <PlotVisualizer data={formData} results={results} />
                {results && <ResultsPanel results={results} data={formData} />}
              </div>
            ) : (
              <div className="h-[600px] flex flex-col items-center justify-center bg-white dark:bg-slate-800/30 rounded-[3rem] border-4 border-dashed border-gray-100 dark:border-slate-800 text-center p-12">
                <i className="fa-solid fa-cube text-5xl text-blue-600/30 animate-bounce mb-8"></i>
                <h3 className="text-2xl font-black text-slate-400 dark:text-slate-600 uppercase tracking-widest">Veri Bekleniyor</h3>
              </div>
            )}
          </div>
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useEffect, useRef } from 'react';
import * as THREE from 'three';
import { OrbitControls } from 'three/addons/controls/OrbitControls.js';
import { ArsaBilgileri, HesapSonuclari, Point } from '../types';

interface PlotVisualizerProps {
  data: ArsaBilgileri;
  results: HesapSonuclari | null;
  id?: string;
}

const PlotVisualizer: React.FC<PlotVisualizerProps> = ({ data, results, id }) => {
  const mountRef = useRef<HTMLDivElement>(null);
  const compassHUDRef = useRef<HTMLDivElement>(null);
  const lastInteractionRef = useRef<number>(Date.now());

  useEffect(() => {
    if (!mountRef.current || !data.koordinatlar) return;

    const width = mountRef.current.clientWidth;
    const height = 550;
    const scene = new THREE.Scene();
    scene.background = new THREE.Color(0x0f172a); 

    const camera = new THREE.PerspectiveCamera(45, width / height, 0.1, 5000);
    camera.position.set(150, 150, 150);

    const renderer = new THREE.WebGLRenderer({ antialias: true, alpha: true });
    renderer.setSize(width, height);
    mountRef.current.innerHTML = '';
    mountRef.current.appendChild(renderer.domElement);

    const controls = new OrbitControls(camera, renderer.domElement);
    controls.enableDamping = true;
    controls.dampingFactor = 0.05;

    const updateInteraction = () => { lastInteractionRef.current = Date.now(); };
    renderer.domElement.addEventListener('mousedown', updateInteraction);
    renderer.domElement.addEventListener('mousemove', updateInteraction);

    const ambientLight = new THREE.AmbientLight(0xffffff, 0.9);
    scene.add(ambientLight);
    const mainLight = new THREE.PointLight(0xffffff, 1.2);
    mainLight.position.set(100, 200, 100);
    scene.add(mainLight);

    const coords = data.koordinatlar;
    const minX = Math.min(...coords.map(p => p.x));
    const maxX = Math.max(...coords.map(p => p.x));
    const minY = Math.min(...coords.map(p => p.y));
    const maxY = Math.max(...coords.map(p => p.y));
    const scale = 500000; 

    const points3D = coords.map(p => new THREE.Vector2((p.x - minX) * scale, (p.y - minY) * scale));
    const centerX = ((maxX - minX) * scale) / 2;
    const centerY = ((maxY - minY) * scale) / 2;

    const arsaShape = new THREE.Shape(points3D);
    const arsaGeo = new THREE.ShapeGeometry(arsaShape);
    const arsaMat = new THREE.MeshPhongMaterial({ color: 0x1e293b, side: THREE.DoubleSide, transparent: true, opacity: 0.9 });
    const arsaMesh = new THREE.Mesh(arsaGeo, arsaMat);
    arsaMesh.rotation.x = -Math.PI / 2;
    arsaMesh.position.set(-centerX, 0, centerY);
    scene.add(arsaMesh);

    const boundaryPoints: THREE.Vector3[] = [];
    points3D.forEach(p => boundaryPoints.push(new THREE.Vector3(p.x, p.y, 0)));
    boundaryPoints.push(boundaryPoints[0]); 
    const boundaryGeo = new THREE.BufferGeometry().setFromPoints(boundaryPoints);
    const boundaryMat = new THREE.LineBasicMaterial({ color: 0xff0000, linewidth: 5 });
    const boundaryLine = new THREE.Line(boundaryGeo, boundaryMat);
    boundaryLine.rotation.x = -Math.PI / 2;
    boundaryLine.position.set(-centerX, 0.8, centerY);
    scene.add(boundaryLine);

    if (results) {
      const areaRatio = results.tabanAlani / data.alan;
      const bScale = Math.sqrt(areaRatio);
      const binaShape = new THREE.Shape();
      const bPoints = points3D.map(p => {
        const dx = p.x - centerX;
        const dy = p.y - centerY;
        return new THREE.Vector2(centerX + dx * bScale, centerY + dy * bScale);
      });
      binaShape.moveTo(bPoints[0].x, bPoints[0].y);
      bPoints.forEach((p, i) => i > 0 && binaShape.lineTo(p.x, p.y));

      const katYuksekligi = 6;
      const totalHeight = (data.katAdedi || 1) * katYuksekligi;
      const extrudeSettings = { depth: totalHeight, bevelEnabled: false };
      const binaGeo = new THREE.ExtrudeGeometry(binaShape, extrudeSettings);
      const binaMat = new THREE.MeshStandardMaterial({ color: 0xf1f5f9, roughness: 0.4, metalness: 0.1 });
      const binaMesh = new THREE.Mesh(binaGeo, binaMat);
      binaMesh.rotation.x = -Math.PI / 2;
      binaMesh.position.set(-centerX, 0, centerY);
      scene.add(binaMesh);

      const roofGeo = new THREE.ShapeGeometry(binaShape);
      const roofMat = new THREE.MeshStandardMaterial({ color: 0x0f172a });
      const roof = new THREE.Mesh(roofGeo, roofMat);
      roof.rotation.x = -Math.PI / 2;
      roof.position.set(-centerX, totalHeight + 0.1, centerY);
      scene.add(roof);
    }

    const grid = new THREE.GridHelper(1000, 40, 0x334155, 0x1e293b);
    scene.add(grid);

    let hudRenderer: THREE.WebGLRenderer | null = null;
    let hudScene: THREE.Scene | null = null;
    let hudCamera: THREE.PerspectiveCamera | null = null;
    let hudNeedle: THREE.Group | null = null;

    if (compassHUDRef.current) {
        hudRenderer = new THREE.WebGLRenderer({ antialias: true, alpha: true });
        hudRenderer.setSize(120, 120);
        compassHUDRef.current.appendChild(hudRenderer.domElement);
        hudScene = new THREE.Scene();
        hudCamera = new THREE.PerspectiveCamera(45, 1, 0.1, 100);
        hudCamera.position.set(0, 15, 0);
        hudCamera.lookAt(0, 0, 0);
        const hudBase = new THREE.Mesh(new THREE.CircleGeometry(4, 32), new THREE.MeshBasicMaterial({ color: 0x1e293b, transparent: true, opacity: 0.9 }));
        hudBase.rotation.x = -Math.PI / 2;
        hudScene.add(hudBase);
        hudNeedle = new THREE.Group();
        const coneN = new THREE.Mesh(new THREE.ConeGeometry(0.5, 3, 4), new THREE.MeshBasicMaterial({ color: 0xef4444 }));
        coneN.rotation.x = Math.PI / 2;
        coneN.position.z = -1.5;
        hudNeedle.add(coneN);
        const coneS = new THREE.Mesh(new THREE.ConeGeometry(0.5, 3, 4), new THREE.MeshBasicMaterial({ color: 0xffffff }));
        coneS.rotation.x = -Math.PI / 2;
        coneS.position.z = 1.5;
        hudNeedle.add(coneS);
        hudScene.add(hudNeedle);
    }

    const clock = new THREE.Clock();
    const animate = () => {
      requestAnimationFrame(animate);
      const time = clock.getElapsedTime();
      boundaryMat.color.setHSL((time / 3) % 1, 0.8, 0.5);
      const timeSinceInteraction = Date.now() - lastInteractionRef.current;
      if (timeSinceInteraction > 5000) { scene.rotation.y += 0.003; }
      if (hudNeedle && hudRenderer && hudScene && hudCamera) {
          hudNeedle.rotation.y = -scene.rotation.y - controls.getAzimuthalAngle();
          hudRenderer.render(hudScene, hudCamera);
      }
      controls.update();
      renderer.render(scene, camera);
    };
    animate();

    const handleResize = () => {
      if (!mountRef.current) return;
      const w = mountRef.current.clientWidth;
      renderer.setSize(w, height);
      camera.aspect = w / height;
      camera.updateProjectionMatrix();
    };
    window.addEventListener('resize', handleResize);

    return () => {
      window.removeEventListener('resize', handleResize);
      renderer.domElement.removeEventListener('mousedown', updateInteraction);
      renderer.domElement.removeEventListener('mousemove', updateInteraction);
      mountRef.current?.removeChild(renderer.domElement);
      if (compassHUDRef.current && hudRenderer) { compassHUDRef.current.innerHTML = ''; }
    };
  }, [data, results]);

  return (
