import React, { useState, useCallback, useEffect } from 'react';
import { NizamType, ArsaBilgileri, Point } from '../types';

interface ConstructionFormProps {
  onCalculate: (data: ArsaBilgileri) => void;
  onSearchUsak: (mahalle: string, ada: string, parsel: string) => Promise<any>;
  isSearching: boolean;
}

const ConstructionForm: React.FC<ConstructionFormProps> = ({ onCalculate, onSearchUsak, isSearching }) => {
  const [step, setStep] = useState(1);
  const [isFetchingZoning, setIsFetchingZoning] = useState(false);
  const [formData, setFormData] = useState<any>({
    alan: '',
    nizam: NizamType.AYRIK,
    daireSayisiTercihi: 4,
    taks: '0.30',
    katAdedi: '',
    kaks: '', // Emsal değeri
    cekmeOn: 5,
    cekmeYan: 3,
    cekmeArka: 3,
    il: 'Uşak',
    ilce: 'Merkez',
    mahalle: '',
    ada: '',
    parsel: '',
    geoJsonInput: ''
  });

  const processRawInput = (input: string) => {
    try {
      if (input.includes('features')) {
        const data = JSON.parse(input);
        const feature = data.features[0];
        const rawCoords = feature.geometry.coordinates[0];
        const points = rawCoords.map((c: any) => ({ x: c[0], y: c[1] }));
        const props = feature.properties || {};

        setFormData((prev: any) => ({
          ...prev,
          mahalle: props.Mahalle || prev.mahalle,
          ada: props.Ada || prev.ada,
          parsel: props.ParselNo || prev.parsel,
          alan: props.Alan ? parseFloat(props.Alan.replace(',', '.')) : prev.alan,
          geoJsonInput: input
        }));
        return points;
      }
      return [];
    } catch (e) {
      return [];
    }
  };

  const handleFetchFromKeos = async () => {
    if (!formData.ada || !formData.parsel) {
      alert("Lütfen önce Ada ve Parsel bilgilerini giriniz.");
      return;
    }
    setIsFetchingZoning(true);
    try {
      // simulate KEOS fetching via parent component which uses Gemini Google Search
      const info = await onSearchUsak(formData.mahalle, formData.ada, formData.parsel);
      if (info) {
        setFormData((prev: any) => ({
          ...prev,
          katAdedi: info.kat || prev.katAdedi,
          kaks: info.emsal || prev.kaks
        }));
      }
    } catch (err) {
      console.error("Fetch error", err);
    } finally {
      setIsFetchingZoning(false);
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const points = processRawInput(formData.geoJsonInput);
    onCalculate({
      ...formData,
      alan: Number(formData.alan),
      taks: Number(formData.taks),
      katAdedi: Number(formData.katAdedi),
      kaks: Number(formData.kaks),
      daireSayisiTercihi: Number(formData.daireSayisiTercihi),
      koordinatlar: points.length > 0 ? points : undefined
    });
  };

  return (
    <form onSubmit={handleSubmit} className="space-y-6">
      {step === 1 && (
        <div className="space-y-4">
          <div className="relative group transition-all duration-500 border-4 border-dashed rounded-[2rem] p-8 text-center border-gray-200 dark:border-slate-700 hover:border-blue-400">
            <div className="space-y-3">
              <div className="w-16 h-16 bg-blue-600 rounded-2xl mx-auto flex items-center justify-center shadow-xl">
                <i className="fa-solid fa-file-import text-2xl text-white"></i>
              </div>
              <h4 className="font-black text-slate-800 dark:text-white uppercase tracking-tighter text-sm">TKGM Dosyası veya Ctrl+V</h4>
            </div>
          </div>

          <div className="grid grid-cols-3 gap-2">
            <input placeholder="Mahalle" name="mahalle" value={formData.mahalle} onChange={(e)=>setFormData({...formData, mahalle: e.target.value})} className="w-full bg-gray-50 dark:bg-slate-900 border border-gray-200 dark:border-slate-700 rounded-xl py-2 px-3 text-xs font-bold" />
            <input placeholder="Ada" name="ada" value={formData.ada} onChange={(e)=>setFormData({...formData, ada: e.target.value})} className="w-full bg-gray-50 dark:bg-slate-900 border border-gray-200 dark:border-slate-700 rounded-xl py-2 px-3 text-xs font-bold" />
            <input placeholder="Parsel" name="parsel" value={formData.parsel} onChange={(e)=>setFormData({...formData, parsel: e.target.value})} className="w-full bg-gray-50 dark:bg-slate-900 border border-gray-200 dark:border-slate-700 rounded-xl py-2 px-3 text-xs font-bold" />
          </div>

          <button 
            type="button" 
            onClick={handleFetchFromKeos} 
            disabled={isFetchingZoning}
            className="w-full bg-blue-50 dark:bg-blue-900/20 text-blue-600 dark:text-blue-400 font-black py-3 rounded-xl border border-blue-200 dark:border-blue-800/50 flex items-center justify-center gap-2 hover:bg-blue-100 transition-colors uppercase text-[10px] tracking-widest"
          >
            {isFetchingZoning ? <i className="fa-solid fa-spinner animate-spin"></i> : <i className="fa-solid fa-cloud-arrow-down"></i>}
            USAK KEOS VERİLERİNİ OTOMATİK GETİR
          </button>

          <div className="grid grid-cols-2 gap-4">
            <input type="number" placeholder="Alan (m²)" name="alan" value={formData.alan} onChange={(e)=>setFormData({...formData, alan: e.target.value})} className="w-full bg-gray-50 dark:bg-slate-900 border border-gray-200 dark:border-slate-700 rounded-xl py-2 px-3 text-sm font-bold" />
            <select name="nizam" value={formData.nizam} onChange={(e)=>setFormData({...formData, nizam: e.target.value})} className="w-full bg-gray-50 dark:bg-slate-900 border border-gray-200 dark:border-slate-700 rounded-xl py-2 px-3 text-sm font-bold">
                <option value={NizamType.AYRIK}>Ayrık Nizam</option>
                <option value={NizamType.BITISIK}>Bitişik Nizam</option>
            </select>
          </div>

          <button type="button" onClick={() => setStep(2)} className="w-full bg-blue-600 text-white font-black py-4 rounded-2xl shadow-xl active:scale-95 transition-all uppercase tracking-widest text-xs">
            HESAPLAMA ADIMINA GEÇ <i className="fa-solid fa-chevron-right ml-2"></i>
          </button>
        </div>
      )}

      {step === 2 && (
        <div className="space-y-4 animate-in slide-in-from-right duration-300">
          <div className="grid grid-cols-2 gap-4">
            <div className="space-y-1">
              <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Kat Sayısı <span className="text-emerald-500">(Bodrum Hariç)</span></label>
              <input type="number" name="katAdedi" value={formData.katAdedi} onChange={(e)=>setFormData({...formData, katAdedi: e.target.value})} className="w-full bg-gray-50 dark:bg-slate-900 border border-gray-200 dark:border-slate-700 rounded-xl py-2 px-3 text-sm font-bold" />
            </div>
            <div className="space-y-1">
              <label className="text-[10px] font-black text-slate-400 uppercase ml-1">K.A.K.S (Emsal)</label>
              <input type="number" step="0.01" name="kaks" value={formData.kaks} onChange={(e)=>setFormData({...formData, kaks: e.target.value})} className="w-full bg-gray-50 dark:bg-slate-900 border border-gray-200 dark:border-slate-700 rounded-xl py-2 px-3 text-sm font-bold text-blue-500" />
            </div>
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div className="space-y-1">
              <label className="text-[10px] font-black text-slate-400 uppercase ml-1">TAKS Oranı</label>
              <input type="number" step="0.01" name="taks" value={formData.taks} onChange={(e)=>setFormData({...formData, taks: e.target.value})} className="w-full bg-gray-50 dark:bg-slate-900 border border-gray-200 dark:border-slate-700 rounded-xl py-2 px-3 text-sm font-bold" />
            </div>
            <div className="space-y-1">
              <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Kattaki Daire Sayısı</label>
              <div className="flex gap-1">
                {[1, 2, 3, 4].map(n => (
                  <button key={n} type="button" onClick={() => setFormData({...formData, daireSayisiTercihi: n})} className={`flex-1 py-2 rounded-lg font-black text-xs transition-all ${formData.daireSayisiTercihi === n ? 'bg-blue-600 text-white shadow-lg' : 'bg-slate-100 dark:bg-slate-800 text-slate-400'}`}>{n}</button>
                ))}
              </div>
            </div>
          </div>

          <div className="flex gap-4 pt-4">
            <button type="button" onClick={() => setStep(1)} className="flex-1 bg-slate-100 dark:bg-slate-700 text-slate-500 dark:text-white font-black py-4 rounded-2xl uppercase text-[10px]">Geri</button>
            <button type="submit" className="flex-[2] bg-emerald-600 text-white font-black py-4 rounded-2xl shadow-xl uppercase text-[10px] tracking-widest">Analizi Başlat</button>
          </div>
        </div>
      )}
    </form>
  );
};

export default ConstructionForm;

import React, { useState, useEffect } from 'react';
import { NizamType, ArsaBilgileri, HesapSonuclari, LocationAnalysisData } from './types';
import ConstructionForm from './components/ConstructionForm';
import PlotVisualizer from './components/PlotVisualizer';
import ResultsPanel from './components/ResultsPanel';
import Header from './components/Header';
import { GoogleGenAI } from "@google/genai";

const App: React.FC = () => {
  const [darkMode, setDarkMode] = useState(true);
  const [formData, setFormData] = useState<ArsaBilgileri | null>(null);
  const [results, setResults] = useState<HesapSonuclari | null>(null);
  const [isSearching, setIsSearching] = useState(false);

  useEffect(() => {
    if (darkMode) {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [darkMode]);

  const searchUsakZoning = async (mahalle: string, ada: string, parsel: string) => {
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const prompt = `Uşak İli Merkez İlçesi ${mahalle} Mahallesi Ada ${ada} Parsel ${parsel} için "https://keos.usak.bel.tr/imardurumu/index.aspx" adresindeki imar durumunu araştır. 
      Özellikle 'Kat Adedi' ve 'K.A.K.S (Emsal)' değerlerini bulmaya çalış. 
      Yanıtı sadece şu JSON formatında ver: {"kat": 4, "emsal": 1.25}. 
      Eğer bulamazsan bölgenin genel imar planına göre mantıklı bir tahmin yap.`;

      const response = await ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: prompt,
        config: { tools: [{ googleSearch: {} }] },
      });

      const jsonMatch = response.text?.match(/\{.*\}/s);
      return jsonMatch ? JSON.parse(jsonMatch[0]) : { kat: 4, emsal: 1.20 };
    } catch (e) {
      return { kat: 4, emsal: 1.20 };
    }
  };

  const calculateData = async (data: ArsaBilgileri) => {
    setIsSearching(true);

    // KAKS artık doğrudan kullanıcıdan veya KEOS'tan gelen "emsal" değeridir.
    const kaks = data.kaks || (data.taks * data.katAdedi);
    const tabanAlani = data.alan * data.taks;
    const zeminBrut = tabanAlani * 1.1;
    const normalKatBrut = zeminBrut * 1.15;
    const daireBasiMetrekare = normalKatBrut / data.daireSayisiTercihi;

    let daireTipi = "Özel Proje";
    if (daireBasiMetrekare < 105) daireTipi = "1+1 Apart";
    else if (daireBasiMetrekare < 115) daireTipi = "2+1";
    else if (daireBasiMetrekare < 150) daireTipi = "3+1";
    else daireTipi = "4+1";

    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const locationInfo = await ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: `${data.il} ${data.ilce} ${data.mahalle} Ada ${data.ada} Parsel ${data.parsel} mevkisini gayrimenkul değeri açısından analiz et. JSON dön: {"score": 85, "summary": "Değerli bölge...", "nearbyPlaces": ["Okul", "Hastane"]}`,
        config: { tools: [{ googleSearch: {} }] },
    }).then(res => {
        const match = res.text?.match(/\{.*\}/s);
        return match ? JSON.parse(match[0]) : null;
    }).catch(() => null);

    setResults({
      kaks,
      tabanAlani,
      zeminBrut,
      normalKatBrut,
      toplamKat: data.katAdedi,
      daireTipi,
      daireBasiMetrekare,
      locationAnalysis: locationInfo || undefined
    });
    setFormData(data);
    setIsSearching(false);
  };

  return (
    <div className="min-h-screen pb-12 transition-colors duration-300 bg-gray-50 dark:bg-slate-900 text-slate-900 dark:text-slate-100 font-sans selection:bg-blue-500 selection:text-white">
      <Header darkMode={darkMode} setDarkMode={setDarkMode} />

      <main className="container mx-auto px-4 mt-8 max-w-7xl">
        <div className="grid grid-cols-1 xl:grid-cols-12 gap-8 relative">

          {isSearching && (
            <div className="fixed inset-0 z-[100] bg-slate-950/80 backdrop-blur-xl flex flex-col items-center justify-center animate-in fade-in duration-300">
               <div className="w-20 h-20 border-4 border-emerald-500/20 border-t-emerald-500 rounded-full animate-spin"></div>
               <h2 className="mt-8 text-2xl font-black uppercase tracking-[0.3em] text-white">Analiz Yapılıyor</h2>
               <p className="mt-2 text-slate-400 font-bold uppercase text-[10px] tracking-widest">KEOS ve Grounding Verileri Alınıyor...</p>
            </div>
          )}

          <div className="xl:col-span-4">
            <section className="bg-white dark:bg-slate-800/50 backdrop-blur-xl p-6 rounded-[2.5rem] shadow-2xl border border-gray-100 dark:border-slate-700/50">
              <ConstructionForm 
                onCalculate={calculateData} 
                onSearchUsak={searchUsakZoning} 
                isSearching={isSearching}
              />
            </section>
          </div>

          <div className="xl:col-span-8 space-y-8">
            {formData ? (
              <div className="space-y-8 animate-in fade-in zoom-in duration-500">
                <PlotVisualizer data={formData} results={results} />
                {results && <ResultsPanel results={results} data={formData} />}
              </div>
            ) : (
              <div className="h-[600px] flex flex-col items-center justify-center bg-white dark:bg-slate-800/30 rounded-[3rem] border-4 border-dashed border-gray-100 dark:border-slate-800 text-center p-12">
                <i className="fa-solid fa-drafting-compass text-5xl text-blue-600/30 animate-pulse mb-8"></i>
                <h3 className="text-2xl font-black text-slate-400 dark:text-slate-600 uppercase tracking-widest">Veri Bekleniyor</h3>
              </div>
            )}
          </div>
        </div>
      </main>
    </div>
  );
};

export default App;

