import React, { useEffect, useRef } from 'react';
import * as THREE from 'three';
import { OrbitControls } from 'three/addons/controls/OrbitControls.js';
import { ArsaBilgileri, HesapSonuclari, Point } from '../types';

interface PlotVisualizerProps {
  data: ArsaBilgileri;
  results: HesapSonuclari | null;
  id?: string;
}

const PlotVisualizer: React.FC<PlotVisualizerProps> = ({ data, results, id }) => {
  const mountRef = useRef<HTMLDivElement>(null);
  const compassHUDRef = useRef<HTMLDivElement>(null);
  const lastInteractionRef = useRef<number>(Date.now());

  useEffect(() => {
    if (!mountRef.current || !data.koordinatlar) return;

    const width = mountRef.current.clientWidth;
    const height = 550;
    const scene = new THREE.Scene();
    scene.background = new THREE.Color(0x0f172a); 

    const camera = new THREE.PerspectiveCamera(45, width / height, 0.1, 10000);
    camera.position.set(200, 200, 200);

    const renderer = new THREE.WebGLRenderer({ antialias: true, alpha: true });
    renderer.setSize(width, height);
    mountRef.current.innerHTML = '';
    mountRef.current.appendChild(renderer.domElement);

    const controls = new OrbitControls(camera, renderer.domElement);
    controls.enableDamping = true;
    controls.dampingFactor = 0.05;

    const updateInteraction = () => { lastInteractionRef.current = Date.now(); };
    renderer.domElement.addEventListener('mousedown', updateInteraction);
    renderer.domElement.addEventListener('mousemove', updateInteraction);

    const ambientLight = new THREE.AmbientLight(0xffffff, 0.9);
    scene.add(ambientLight);
    const mainLight = new THREE.DirectionalLight(0xffffff, 1.2);
    mainLight.position.set(100, 300, 100);
    scene.add(mainLight);

    const coords = data.koordinatlar;
    const minX = Math.min(...coords.map(p => p.x));
    const maxX = Math.max(...coords.map(p => p.x));
    const minY = Math.min(...coords.map(p => p.y));
    const maxY = Math.max(...coords.map(p => p.y));
    const scale = 500000; 

    const points3D = coords.map(p => new THREE.Vector2((p.x - minX) * scale, (p.y - minY) * scale));
    const centerX = ((maxX - minX) * scale) / 2;
    const centerY = ((maxY - minY) * scale) / 2;

    const arsaShape = new THREE.Shape(points3D);
    const arsaGeo = new THREE.ShapeGeometry(arsaShape);
    const arsaMat = new THREE.MeshPhongMaterial({ color: 0x1e293b, side: THREE.DoubleSide, transparent: true, opacity: 0.85 });
    const arsaMesh = new THREE.Mesh(arsaGeo, arsaMat);
    arsaMesh.rotation.x = -Math.PI / 2;
    arsaMesh.position.set(-centerX, 0, centerY);
    scene.add(arsaMesh);

    const boundaryPoints: THREE.Vector3[] = [];
    points3D.forEach(p => boundaryPoints.push(new THREE.Vector3(p.x, p.y, 0)));
    boundaryPoints.push(boundaryPoints[0]); 
    const boundaryGeo = new THREE.BufferGeometry().setFromPoints(boundaryPoints);
    const boundaryMat = new THREE.LineBasicMaterial({ color: 0xff0000, linewidth: 5 });
    const boundaryLine = new THREE.Line(boundaryGeo, boundaryMat);
    boundaryLine.rotation.x = -Math.PI / 2;
    boundaryLine.position.set(-centerX, 1.2, centerY);
    scene.add(boundaryLine);

    if (results) {
      const areaRatio = results.tabanAlani / data.alan;
      const bScale = Math.sqrt(areaRatio);
      const binaShape = new THREE.Shape();
      const bPoints = points3D.map(p => {
        const dx = p.x - centerX;
        const dy = p.y - centerY;
        return new THREE.Vector2(centerX + dx * bScale, centerY + dy * bScale);
      });
      binaShape.moveTo(bPoints[0].x, bPoints[0].y);
      bPoints.forEach((p, i) => i > 0 && binaShape.lineTo(p.x, p.y));

      const katYuksekligi = 6;
      const totalHeight = (data.katAdedi || 1) * katYuksekligi;
      const extrudeSettings = { depth: totalHeight, bevelEnabled: false };
      const binaGeo = new THREE.ExtrudeGeometry(binaShape, extrudeSettings);
      const binaMat = new THREE.MeshStandardMaterial({ color: 0xf8fafc, roughness: 0.3, metalness: 0.1 });
      const binaMesh = new THREE.Mesh(binaGeo, binaMat);
      binaMesh.rotation.x = -Math.PI / 2;
      binaMesh.position.set(-centerX, 0, centerY);
      scene.add(binaMesh);

      const roofGeo = new THREE.ShapeGeometry(binaShape);
      const roofMat = new THREE.MeshStandardMaterial({ color: 0x0f172a });
      const roof = new THREE.Mesh(roofGeo, roofMat);
      roof.rotation.x = -Math.PI / 2;
      roof.position.set(-centerX, totalHeight + 0.1, centerY);
      scene.add(roof);
    }

    const grid = new THREE.GridHelper(2000, 80, 0x334155, 0x1e293b);
    scene.add(grid);

    let hudRenderer: THREE.WebGLRenderer | null = null;
    let hudScene: THREE.Scene | null = null;
    let hudCamera: THREE.PerspectiveCamera | null = null;
    let hudNeedle: THREE.Group | null = null;

    if (compassHUDRef.current) {
        hudRenderer = new THREE.WebGLRenderer({ antialias: true, alpha: true });
        hudRenderer.setSize(120, 120);
        compassHUDRef.current.appendChild(hudRenderer.domElement);
        hudScene = new THREE.Scene();
        hudCamera = new THREE.PerspectiveCamera(45, 1, 0.1, 100);
        hudCamera.position.set(0, 15, 0);
        hudCamera.lookAt(0, 0, 0);
        const hudBase = new THREE.Mesh(new THREE.CircleGeometry(4, 32), new THREE.MeshBasicMaterial({ color: 0x1e293b, transparent: true, opacity: 0.9 }));
        hudBase.rotation.x = -Math.PI / 2;
        hudScene.add(hudBase);
        hudNeedle = new THREE.Group();
        const coneN = new THREE.Mesh(new THREE.ConeGeometry(0.5, 3, 4), new THREE.MeshBasicMaterial({ color: 0xef4444 }));
        coneN.rotation.x = Math.PI / 2;
        coneN.position.z = -1.5;
        hudNeedle.add(coneN);
        const coneS = new THREE.Mesh(new THREE.ConeGeometry(0.5, 3, 4), new THREE.MeshBasicMaterial({ color: 0xffffff }));
        coneS.rotation.x = -Math.PI / 2;
        coneS.position.z = 1.5;
        hudNeedle.add(coneS);
        hudScene.add(hudNeedle);
    }

    const clock = new THREE.Clock();
    const animate = () => {
      requestAnimationFrame(animate);
      const time = clock.getElapsedTime();

      // RGB Boundary Transition
      boundaryMat.color.setHSL((time / 3) % 1, 0.7, 0.5);

      const timeSinceInteraction = Date.now() - lastInteractionRef.current;
      if (timeSinceInteraction > 5000) { 
        scene.rotation.y += 0.003; 
      }

      // HUD Compass logic: needs to point to the parcel's North relative to view
      if (hudNeedle && hudRenderer && hudScene && hudCamera) {
          hudNeedle.rotation.y = -scene.rotation.y - controls.getAzimuthalAngle();
          hudRenderer.render(hudScene, hudCamera);
      }

      controls.update();
      renderer.render(scene, camera);
    };
    animate();

    const handleResize = () => {
      if (!mountRef.current) return;
      const w = mountRef.current.clientWidth;
      renderer.setSize(w, height);
      camera.aspect = w / height;
      camera.updateProjectionMatrix();
    };
    window.addEventListener('resize', handleResize);

    return () => {
      window.removeEventListener('resize', handleResize);
      renderer.domElement.removeEventListener('mousedown', updateInteraction);
      renderer.domElement.removeEventListener('mousemove', updateInteraction);
      mountRef.current?.removeChild(renderer.domElement);
      if (compassHUDRef.current && hudRenderer) { compassHUDRef.current.innerHTML = ''; }
    };
  }, [data, results]);

  return (
    <div id={id} className="relative bg-slate-900 rounded-[3rem] shadow-2xl border border-slate-800 overflow-hidden group">
      <div className="absolute top-8 left-8 z-10 pointer-events-none">
        <h3 className="text-white font-black text-2xl tracking-tighter uppercase leading-none">3D VAZİYET KOKPİTİ</h3>
        <p className="text-blue-400 text-[10px] font-black uppercase tracking-[0.3em] mt-2">Mühendislik Modeli Aktif</p>
      </div>

      <div className="absolute top-8 right-8 z-20 pointer-events-none">
        <div className="bg-slate-800/90 backdrop-blur-xl p-3 rounded-[2rem] border border-slate-700/50 shadow-2xl flex flex-col items-center">
          <div ref={compassHUDRef} className="w-[120px] h-[120px]" />
          <div className="mt-[-10px] pb-2 text-center">
            <span className="text-[8px] font-black text-slate-500 uppercase tracking-widest">Senkronize</span>
            <p className="text-[10px] font-black text-white uppercase tracking-tighter">Cep Pusulası</p>
          </div>
        </div>
      </div>

      <div ref={mountRef} className="cursor-move" />

      <div className="absolute bottom-0 left-0 right-0 p-8 bg-gradient-to-t from-slate-950 via-slate-900/40 to-transparent flex justify-between items-end pointer-events-none">
        <div className="flex gap-10">
          <div>
            <p className="text-slate-500 text-[9px] font-black uppercase mb-1 tracking-widest">Parsel Alanı</p>
            <p className="text-2xl font-black text-white">{data.alan.toFixed(1)} <span className="text-xs text-slate-500">m²</span></p>
          </div>
          <div className="w-px h-8 bg-slate-800 self-center"></div>
          <div>
            <p className="text-emerald-500 text-[9px] font-black uppercase mb-1 tracking-widest">Oturum Alanı</p>
            <p className="text-2xl font-black text-white">{results ? results.tabanAlani.toFixed(1) : "0.0"} <span className="text-xs text-slate-500">m²</span></p>
          </div>
        </div>

        <div className="bg-gradient-to-br from-blue-600 to-indigo-700 px-8 py-5 rounded-[2.5rem] shadow-2xl border border-blue-400/20">
           <p className="text-[9px] font-black text-blue-200 uppercase tracking-widest mb-1">Kat Sayısı</p>
           <p className="text-white font-black text-xl uppercase tracking-tight">{data.katAdedi} Kat (B. Hariç)</p>
        </div>
      </div>
    </div>
  );
};

export default PlotVisualizer;

export enum NizamType {
  AYRIK = 'AYRIK',
  BITISIK = 'BITISIK'
}

export interface Point {
  x: number;
  y: number;
}

export interface LocationSource {
  title: string;
  uri: string;
}

export interface LocationAnalysisData {
  score: number;
  summary: string;
  nearbyPlaces: string[];
  sources: LocationSource[];
}

export interface ArsaBilgileri {
  alan: number;
  il: string;
  ilce: string;
  mahalle: string;
  ada: string;
  parsel: string;
  nizam: NizamType;
  cekmeOn?: number;
  cekmeYan?: number;
  cekmeArka?: number;
  taks: number;
  katAdedi: number;
  // KAKS (Kat Alanı Kat Sayısı) property added to fix "Property 'kaks' does not exist on type 'ArsaBilgileri'" error.
  kaks: number;
  daireSayisiTercihi: number;
  geoJsonInput?: string;
  koordinatlar?: Point[];
}

export interface HesapSonuclari {
  kaks: number;
  tabanAlani: number;
  zeminBrut: number;
  normalKatBrut: number;
  toplamKat: number;
  daireTipi: string;
  daireBasiMetrekare: number;
  locationAnalysis?: LocationAnalysisData;
}

import React, { useState, useEffect } from 'react';
import { NizamType, ArsaBilgileri, HesapSonuclari, LocationAnalysisData, LocationSource } from './types';
import ConstructionForm from './components/ConstructionForm';
import PlotVisualizer from './components/PlotVisualizer';
import ResultsPanel from './components/ResultsPanel';
import Header from './components/Header';
import { GoogleGenAI } from "@google/genai";

const App: React.FC = () => {
  const [darkMode, setDarkMode] = useState(true);
  const [formData, setFormData] = useState<ArsaBilgileri | null>(null);
  const [results, setResults] = useState<HesapSonuclari | null>(null);
  const [isSearching, setIsSearching] = useState(false);

  useEffect(() => {
    if (darkMode) {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [darkMode]);

  const searchUsakZoning = async (mahalle: string, ada: string, parsel: string) => {
    try {
      // Re-initialize GoogleGenAI right before use to ensure the latest API key is used.
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const prompt = `Uşak İli Merkez İlçesi ${mahalle} Mahallesi Ada ${ada} Parsel ${parsel} için "https://keos.usak.bel.tr/imardurumu/index.aspx" adresindeki imar durumunu araştır. 
      Özellikle 'Kat Adedi' ve 'K.A.K.S (Emsal)' değerlerini bulmaya çalış. 
      Yanıtı sadece şu JSON formatında ver: {"kat": 4, "emsal": 1.25}. 
      Eğer bulamazsan bölgenin genel imar planına göre mantıklı bir tahmin yap.`;

      const response = await ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: prompt,
        config: { tools: [{ googleSearch: {} }] },
      });

      const jsonMatch = response.text?.match(/\{.*\}/s);
      return jsonMatch ? JSON.parse(jsonMatch[0]) : { kat: 4, emsal: 1.20 };
    } catch (e) {
      return { kat: 4, emsal: 1.20 };
    }
  };

  const calculateData = async (data: ArsaBilgileri) => {
    setIsSearching(true);

    // KAKS artık doğrudan kullanıcıdan veya KEOS'tan gelen "emsal" değeridir.
    // Fixed: Properly accessing data.kaks which now exists in the ArsaBilgileri interface.
    const calculatedKaks = data.kaks || (data.taks * data.katAdedi);
    const tabanAlani = data.alan * data.taks;
    const zeminBrut = tabanAlani * 1.1;
    const normalKatBrut = zeminBrut * 1.15;
    const daireBasiMetrekare = normalKatBrut / data.daireSayisiTercihi;

    let daireTipi = "Özel Proje";
    if (daireBasiMetrekare < 105) daireTipi = "1+1 Apart";
    else if (daireBasiMetrekare < 115) daireTipi = "2+1";
    else if (daireBasiMetrekare < 150) daireTipi = "3+1";
    else daireTipi = "4+1";

    // Re-initialize GoogleGenAI right before the model call.
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const locationRes = await ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: `${data.il} ${data.ilce} ${data.mahalle} Ada ${data.ada} Parsel ${data.parsel} mevkisini gayrimenkul değeri açısından analiz et. JSON dön: {"score": 85, "summary": "Değerli bölge...", "nearbyPlaces": ["Okul", "Hastane"]}`,
        config: { tools: [{ googleSearch: {} }] },
    }).catch(() => null);

    let locationInfo: LocationAnalysisData | undefined = undefined;
    if (locationRes) {
        const match = locationRes.text?.match(/\{.*\}/s);
        const jsonData = match ? JSON.parse(match[0]) : null;
        if (jsonData) {
            // Mandated: Always extract and list URLs from groundingChunks when using googleSearch.
            const sources: LocationSource[] = locationRes.candidates?.[0]?.groundingMetadata?.groundingChunks
                ?.filter((chunk: any) => chunk.web)
                ?.map((chunk: any) => ({
                    title: chunk.web.title || 'Kaynak',
                    uri: chunk.web.uri
                })) || [];
            locationInfo = { ...jsonData, sources };
        }
    }

    setResults({
      kaks: calculatedKaks,
      tabanAlani,
      zeminBrut,
      normalKatBrut,
      toplamKat: data.katAdedi,
      daireTipi,
      daireBasiMetrekare,
      locationAnalysis: locationInfo || undefined
    });
    setFormData(data);
    setIsSearching(false);
  };

  return (
    <div className="min-h-screen pb-12 transition-colors duration-300 bg-gray-50 dark:bg-slate-900 text-slate-900 dark:text-slate-100 font-sans selection:bg-blue-500 selection:text-white">
      <Header darkMode={darkMode} setDarkMode={setDarkMode} />

      <main className="container mx-auto px-4 mt-8 max-w-7xl">
        <div className="grid grid-cols-1 xl:grid-cols-12 gap-8 relative">

          {isSearching && (
            <div className="fixed inset-0 z-[100] bg-slate-950/80 backdrop-blur-xl flex flex-col items-center justify-center animate-in fade-in duration-300">
               <div className="w-20 h-20 border-4 border-emerald-500/20 border-t-emerald-500 rounded-full animate-spin"></div>
               <h2 className="mt-8 text-2xl font-black uppercase tracking-[0.3em] text-white">Analiz Yapılıyor</h2>
               <p className="mt-2 text-slate-400 font-bold uppercase text-[10px] tracking-widest">KEOS ve Grounding Verileri Alınıyor...</p>
            </div>
          )}

          <div className="xl:col-span-4">
            <section className="bg-white dark:bg-slate-800/50 backdrop-blur-xl p-6 rounded-[2.5rem] shadow-2xl border border-gray-100 dark:border-slate-700/50">
              <ConstructionForm 
                onCalculate={calculateData} 
                onSearchUsak={searchUsakZoning} 
                isSearching={isSearching}
              />
            </section>
          </div>

          <div className="xl:col-span-8 space-y-8">
            {formData ? (
              <div className="space-y-8 animate-in fade-in zoom-in duration-500">
                <PlotVisualizer data={formData} results={results} />
                {results && <ResultsPanel results={results} data={formData} />}
              </div>
            ) : (
              <div className="h-[600px] flex flex-col items-center justify-center bg-white dark:bg-slate-800/30 rounded-[3rem] border-4 border-dashed border-gray-100 dark:border-slate-800 text-center p-12">
                <i className="fa-solid fa-drafting-compass text-5xl text-blue-600/30 animate-pulse mb-8"></i>
                <h3 className="text-2xl font-black text-slate-400 dark:text-slate-600 uppercase tracking-widest">Veri Bekleniyor</h3>
              </div>
            )}
          </div>
        </div>
      </main>
    </div>
  );
};

export default App;

