import React, { useState, useCallback } from 'react';
import { NizamType, ArsaBilgileri, Point } from '../types';

interface ConstructionFormProps {
  onCalculate: (data: ArsaBilgileri) => void;
  onSearchUsak: (mahalle: string, ada: string, parsel: string) => Promise<any>;
  isSearching: boolean;
}

const ConstructionForm: React.FC<ConstructionFormProps> = ({ onCalculate, onSearchUsak, isSearching }) => {
  const [step, setStep] = useState(1);
  const [isFetchingZoning, setIsFetchingZoning] = useState(false);
  const [isDragging, setIsDragging] = useState(false);
  const [formData, setFormData] = useState<any>({
    alan: '',
    nizam: NizamType.AYRIK,
    daireSayisiTercihi: 4,
    taks: '0.30',
    katAdedi: '',
    kaks: '', // Emsal değeri
    cekmeOn: 5,
    cekmeYan: 3,
    cekmeArka: 3,
    il: 'Uşak',
    ilce: 'Merkez',
    mahalle: '',
    ada: '',
    parsel: '',
    geoJsonInput: '',
    koordinatlar: []
  });

  const parseTKGMData = (input: string) => {
    try {
      const data = JSON.parse(input);
      let feature = null;

      if (data.type === 'FeatureCollection' && data.features && data.features.length > 0) {
        feature = data.features[0];
      } else if (data.type === 'Feature') {
        feature = data;
      }

      if (feature && feature.geometry && feature.geometry.coordinates) {
        const rawCoords = feature.geometry.type === 'Polygon' 
          ? feature.geometry.coordinates[0] 
          : feature.geometry.coordinates[0][0];

        const points = rawCoords.map((c: any) => ({ x: c[0], y: c[1] }));
        const props = feature.properties || {};

        setFormData((prev: any) => ({
          ...prev,
          mahalle: props.Mahalle || props.MAHALLE || prev.mahalle,
          ada: props.Ada || props.ADA || prev.ada,
          parsel: props.ParselNo || props.PARSEL || prev.parsel,
          alan: props.Alan ? parseFloat(String(props.Alan).replace(',', '.')) : prev.alan,
          geoJsonInput: input,
          koordinatlar: points
        }));
        return true;
      }
    } catch (e) {
      console.error("JSON Ayrıştırma Hatası:", e);
    }
    return false;
  };

  const handleFileDrop = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);
    const file = e.dataTransfer.files[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (event) => {
        const content = event.target?.result as string;
        parseTKGMData(content);
      };
      reader.readAsText(file);
    }
  };

  const handlePaste = (e: React.ClipboardEvent) => {
    const text = e.clipboardData.getData('text');
    if (text.includes('{') && text.includes('}')) {
      parseTKGMData(text);
    }
  };

  const handleFetchFromKeos = async () => {
    if (!formData.ada || !formData.parsel) {
      alert("Lütfen önce Ada ve Parsel bilgilerini giriniz.");
      return;
    }
    setIsFetchingZoning(true);
    try {
      const info = await onSearchUsak(formData.mahalle, formData.ada, formData.parsel);
      if (info) {
        setFormData((prev: any) => ({
          ...prev,
          katAdedi: info.kat || prev.katAdedi,
          kaks: info.emsal || prev.kaks
        }));
      }
    } catch (err) {
      console.error("Fetch error", err);
    } finally {
      setIsFetchingZoning(false);
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onCalculate({
      ...formData,
      alan: Number(formData.alan),
      taks: Number(formData.taks),
      katAdedi: Number(formData.katAdedi),
      kaks: Number(formData.kaks),
      daireSayisiTercihi: Number(formData.daireSayisiTercihi),
      koordinatlar: formData.koordinatlar.length > 0 ? formData.koordinatlar : undefined
    });
  };

  return (
    <form onSubmit={handleSubmit} className="space-y-6" onPaste={handlePaste}>
      {step === 1 && (
        <div className="space-y-4">
          <div 
            onDragOver={(e) => { e.preventDefault(); setIsDragging(true); }}
            onDragLeave={() => setIsDragging(false)}
            onDrop={handleFileDrop}
            className={`relative group transition-all duration-500 border-4 border-dashed rounded-[2rem] p-8 text-center transition-all ${isDragging ? 'border-blue-500 bg-blue-50 dark:bg-blue-900/20 scale-[1.02]' : 'border-gray-200 dark:border-slate-700 hover:border-blue-400'}`}
          >
            <div className="space-y-3 pointer-events-none">
              <div className={`w-16 h-16 rounded-2xl mx-auto flex items-center justify-center shadow-xl transition-colors ${isDragging ? 'bg-blue-500' : 'bg-blue-600'}`}>
                <i className={`fa-solid ${isDragging ? 'fa-hand-holding-heart animate-bounce' : 'fa-file-import'} text-2xl text-white`}></i>
              </div>
              <h4 className="font-black text-slate-800 dark:text-white uppercase tracking-tighter text-sm">
                {isDragging ? 'BURAYA BIRAKIN' : 'TKGM Dosyası Sürükle veya Ctrl+V'}
              </h4>
              <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">ParselSorgu'dan indirilen .json dosyası</p>
            </div>
          </div>

          <div className="grid grid-cols-3 gap-2">
            <input placeholder="Mahalle" name="mahalle" value={formData.mahalle} onChange={(e)=>setFormData({...formData, mahalle: e.target.value})} className="w-full bg-gray-50 dark:bg-slate-900 border border-gray-200 dark:border-slate-700 rounded-xl py-2 px-3 text-xs font-bold focus:ring-2 focus:ring-blue-500 outline-none" />
            <input placeholder="Ada" name="ada" value={formData.ada} onChange={(e)=>setFormData({...formData, ada: e.target.value})} className="w-full bg-gray-50 dark:bg-slate-900 border border-gray-200 dark:border-slate-700 rounded-xl py-2 px-3 text-xs font-bold focus:ring-2 focus:ring-blue-500 outline-none" />
            <input placeholder="Parsel" name="parsel" value={formData.parsel} onChange={(e)=>setFormData({...formData, parsel: e.target.value})} className="w-full bg-gray-50 dark:bg-slate-900 border border-gray-200 dark:border-slate-700 rounded-xl py-2 px-3 text-xs font-bold focus:ring-2 focus:ring-blue-500 outline-none" />
          </div>

          <button 
            type="button" 
            onClick={handleFetchFromKeos} 
            disabled={isFetchingZoning}
            className="w-full bg-blue-50 dark:bg-blue-900/20 text-blue-600 dark:text-blue-400 font-black py-3 rounded-xl border border-blue-200 dark:border-blue-800/50 flex items-center justify-center gap-2 hover:bg-blue-100 dark:hover:bg-blue-900/30 transition-colors uppercase text-[10px] tracking-widest"
          >
            {isFetchingZoning ? <i className="fa-solid fa-spinner animate-spin"></i> : <i className="fa-solid fa-cloud-arrow-down"></i>}
            USAK KEOS VERİLERİNİ OTOMATİK GETİR
          </button>

          <div className="grid grid-cols-2 gap-4">
            <div className="relative">
              <input type="number" placeholder="Alan (m²)" name="alan" value={formData.alan} onChange={(e)=>setFormData({...formData, alan: e.target.value})} className="w-full bg-gray-50 dark:bg-slate-900 border border-gray-200 dark:border-slate-700 rounded-xl py-2 px-3 text-sm font-bold focus:ring-2 focus:ring-blue-500 outline-none" />
              <span className="absolute right-3 top-2 text-[10px] font-black text-slate-400 uppercase">m²</span>
            </div>
            <select name="nizam" value={formData.nizam} onChange={(e)=>setFormData({...formData, nizam: e.target.value})} className="w-full bg-gray-50 dark:bg-slate-900 border border-gray-200 dark:border-slate-700 rounded-xl py-2 px-3 text-sm font-bold focus:ring-2 focus:ring-blue-500 outline-none">
                <option value={NizamType.AYRIK}>Ayrık Nizam</option>
                <option value={NizamType.BITISIK}>Bitişik Nizam</option>
            </select>
          </div>

          <button type="button" onClick={() => setStep(2)} className="w-full bg-blue-600 text-white font-black py-4 rounded-2xl shadow-xl active:scale-95 transition-all uppercase tracking-widest text-xs">
            HESAPLAMA ADIMINA GEÇ <i className="fa-solid fa-chevron-right ml-2"></i>
          </button>
        </div>
      )}

      {step === 2 && (
        <div className="space-y-4 animate-in slide-in-from-right duration-300">
          <div className="grid grid-cols-2 gap-4">
            <div className="space-y-1">
              <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Kat Sayısı <span className="text-emerald-500">(Bodrum Hariç)</span></label>
              <input type="number" name="katAdedi" value={formData.katAdedi} onChange={(e)=>setFormData({...formData, katAdedi: e.target.value})} className="w-full bg-gray-50 dark:bg-slate-900 border border-gray-200 dark:border-slate-700 rounded-xl py-2 px-3 text-sm font-bold focus:ring-2 focus:ring-blue-500 outline-none" />
            </div>
            <div className="space-y-1">
              <label className="text-[10px] font-black text-slate-400 uppercase ml-1">K.A.K.S (Emsal)</label>
              <input type="number" step="0.01" name="kaks" value={formData.kaks} onChange={(e)=>setFormData({...formData, kaks: e.target.value})} className="w-full bg-gray-50 dark:bg-slate-900 border border-gray-200 dark:border-slate-700 rounded-xl py-2 px-3 text-sm font-bold text-blue-500 focus:ring-2 focus:ring-blue-500 outline-none" />
            </div>
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div className="space-y-1">
              <label className="text-[10px] font-black text-slate-400 uppercase ml-1">TAKS Oranı</label>
              <input type="number" step="0.01" name="taks" value={formData.taks} onChange={(e)=>setFormData({...formData, taks: e.target.value})} className="w-full bg-gray-50 dark:bg-slate-900 border border-gray-200 dark:border-slate-700 rounded-xl py-2 px-3 text-sm font-bold focus:ring-2 focus:ring-blue-500 outline-none" />
            </div>
            <div className="space-y-1">
              <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Kattaki Daire Sayısı</label>
              <div className="flex gap-1">
                {[1, 2, 3, 4].map(n => (
                  <button key={n} type="button" onClick={() => setFormData({...formData, daireSayisiTercihi: n})} className={`flex-1 py-2 rounded-lg font-black text-xs transition-all ${formData.daireSayisiTercihi === n ? 'bg-blue-600 text-white shadow-lg' : 'bg-slate-100 dark:bg-slate-800 text-slate-400'}`}>{n}</button>
                ))}
              </div>
            </div>
          </div>

          <div className="flex gap-4 pt-4">
            <button type="button" onClick={() => setStep(1)} className="flex-1 bg-slate-100 dark:bg-slate-700 text-slate-500 dark:text-white font-black py-4 rounded-2xl uppercase text-[10px]">Geri</button>
            <button type="submit" className="flex-[2] bg-emerald-600 text-white font-black py-4 rounded-2xl shadow-xl uppercase text-[10px] tracking-widest">Analizi Başlat</button>
          </div>
        </div>
      )}
    </form>
  );
};

