            </div>
            <div className="space-y-1">
              <label className="text-[10px] font-black text-slate-400 uppercase ml-1">K.A.K.S (Emsal)</label>
              <input type="number" step="0.01" name="kaks" value={formData.kaks} onChange={(e)=>setFormData({...formData, kaks: e.target.value})} className="w-full bg-gray-50 dark:bg-slate-900 border border-gray-200 dark:border-slate-700 rounded-xl py-2 px-3 text-sm font-bold text-blue-500 focus:ring-2 focus:ring-blue-500 outline-none" />
            </div>
