          <div className="grid grid-cols-2 gap-4">
            <div className="relative">
              <input type="number" placeholder="Alan (m²)" name="alan" value={formData.alan} onChange={(e)=>setFormData({...formData, alan: e.target.value})} className="w-full bg-gray-50 dark:bg-slate-900 border border-gray-200 dark:border-slate-700 rounded-xl py-2 px-3 text-sm font-bold focus:ring-2 focus:ring-blue-500 outline-none" />
              <span className="absolute right-3 top-2 text-[10px] font-black text-slate-400 uppercase">m²</span>
