            <select name="nizam" value={formData.nizam} onChange={(e)=>setFormData({...formData, nizam: e.target.value})} className="w-full bg-gray-50 dark:bg-slate-900 border border-gray-200 dark:border-slate-700 rounded-xl py-2 px-3 text-sm font-bold focus:ring-2 focus:ring-blue-500 outline-none">
                <option value={NizamType.AYRIK}>Ayrık Nizam</option>
                <option value={NizamType.BITISIK}>Bitişik Nizam</option>
