import React, { useRef } from 'react';
import { HesapSonuclari, ArsaBilgileri, Point } from '../types';

interface ResultsPanelProps {
  results: HesapSonuclari;
  data: ArsaBilgileri;
}

const ResultsPanel: React.FC<ResultsPanelProps> = ({ results, data }) => {
  const infographicRef = useRef<HTMLDivElement>(null);

  const calculateDistance = (p1: Point, p2: Point) => {
    // TKGM koordinatları genellikle derece veya metre cinsindendir. 
    // Basit Öklid mesafesi ve uygun bir ölçekleme ile kenar uzunluklarını tahmin ediyoruz.
    // Gerçek dünya koordinatları için haversine gerekebilir ancak yerel parselde Öklid yeterlidir.
    const dx = p1.x - p2.x;
    const dy = p1.y - p2.y;
    // Ölçek çarpanı (Koordinat sistemine göre değişebilir, genellikle metreye çevrim gerekir)
    // Eğer koordinatlar metrik değilse (örn. WGS84), yaklaşık bir katsayı kullanılır.
    const dist = Math.sqrt(dx * dx + dy * dy);

    // Eğer koordinatlar derece ise (0.00... gibi), 111320 ile çarparak metreye yaklaşıyoruz.
    const isDecimalDegrees = Math.abs(dx) < 1;
    return isDecimalDegrees ? dist * 111320 : dist;
  };

  const handleDownloadInfographic = async () => {
    if (!infographicRef.current) return;

    // Geçici olarak görünür yap
    const el = infographicRef.current;
    el.style.display = 'block';
    el.style.position = 'fixed';
    el.style.left = '-9999px';
    el.style.top = '0';

    try {
      // @ts-ignore
      const canvas = await window.html2canvas(el, {
        backgroundColor: '#0f172a',
        scale: 2,
        logging: false,
        useCORS: true
      });

      const link = document.createElement('a');
      link.download = `Arsa_Raporu_${data.ada}_${data.parsel}.png`;
      link.href = canvas.toDataURL('image/png');
      link.click();
    } catch (err) {
      console.error("Görsel oluşturma hatası:", err);
    } finally {
      el.style.display = 'none';
    }
  };

  const StatItem = ({ label, value, unit = "", subValue = "", color = "text-slate-800 dark:text-white" }: any) => (
    <div className="bg-white/50 dark:bg-slate-900/50 backdrop-blur-sm p-4 rounded-3xl border border-gray-100 dark:border-slate-800 transition-all hover:border-blue-500/30 group">
      <p className="text-[9px] font-black text-gray-400 dark:text-slate-500 uppercase mb-2 tracking-widest group-hover:text-blue-500 transition-colors">{label}</p>
      <div className="flex items-baseline gap-1">
        <span className={`text-xl font-black tracking-tighter ${color}`}>{value}</span>
        <span className="text-[10px] font-bold text-gray-400">{unit}</span>
      </div>
      {subValue && <p className="text-[9px] text-blue-500 mt-1 font-bold uppercase tracking-tight">{subValue}</p>}
    </div>
  );

  const toplamDaireSayisi = results.toplamKat * data.daireSayisiTercihi;

  // 2D SVG Çizimi için koordinatları normalize et
  const getSvgPath = () => {
    if (!data.koordinatlar || data.koordinatlar.length === 0) return null;
    const coords = data.koordinatlar;
    const minX = Math.min(...coords.map(p => p.x));
    const maxX = Math.max(...coords.map(p => p.x));
    const minY = Math.min(...coords.map(p => p.y));
    const maxY = Math.max(...coords.map(p => p.y));

    const w = maxX - minX;
    const h = maxY - minY;
    const padding = Math.max(w, h) * 0.1;

    const svgW = 400;
    const svgH = 300;
    const scale = Math.min((svgW - 40) / w, (svgH - 40) / h);

    const points = coords.map(p => ({
      x: (p.x - minX) * scale + 20,
      y: svgH - ((p.y - minY) * scale + 20)
    }));

    const d = points.map((p, i) => `${i === 0 ? 'M' : 'L'} ${p.x} ${p.y}`).join(' ') + ' Z';

    // Kenar uzunluklarını hesapla ve etiketleri oluştur
    const labels = [];
    for (let i = 0; i < points.length; i++) {
      const p1 = points[i];
      const p2 = points[(i + 1) % points.length];
      const realP1 = coords[i];
      const realP2 = coords[(i + 1) % coords.length];

      const midX = (p1.x + p2.x) / 2;
      const midY = (p1.y + p2.y) / 2;
      const length = calculateDistance(realP1, realP2).toFixed(1);

      labels.push(
        <text 
          key={i} 
          x={midX} 
          y={midY} 
          fill="#3b82f6" 
          fontSize="8" 
          fontWeight="bold" 
          textAnchor="middle"
          className="drop-shadow-sm"
        >
          {length}m
        </text>
      );
    }

    return { d, points, labels };
  };

  const svgData = getSvgPath();

  return (
    <>
      <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
        {/* Teknik Rapor */}
        <div className="bg-white dark:bg-slate-800/80 rounded-[2.5rem] shadow-2xl p-8 border border-gray-100 dark:border-slate-700/50">
          <h3 className="text-xl font-black mb-8 flex items-center gap-3 uppercase tracking-tighter">
            <div className="w-10 h-10 bg-emerald-500/10 text-emerald-500 rounded-2xl flex items-center justify-center">
              <i className="fa-solid fa-calculator text-sm"></i>
            </div>
            Mühendislik Metrajı
          </h3>

          <div className="grid grid-cols-2 gap-3">
            <StatItem label="Hesaplanan KAKS" value={results.kaks.toFixed(2)} subValue="K.A.K.S (Emsal Verisi)" />
            <StatItem label="İnşaat Tabanı" value={results.tabanAlani.toFixed(1)} unit="m²" color="text-emerald-500" />
            <StatItem label="Normal Kat Alanı" value={results.normalKatBrut.toFixed(1)} unit="m²" />
            <StatItem label="Kat Sayısı" value={results.toplamKat} subValue="B. Hariç" />

            <div className="col-span-2 bg-gradient-to-r from-blue-600/5 to-blue-500/10 dark:from-blue-500/10 dark:to-indigo-500/10 p-6 rounded-[2.5rem] border border-blue-200 dark:border-blue-800/50 flex flex-col items-center justify-center text-center group hover:scale-[1.02] transition-transform">
              <p className="text-[10px] font-black text-blue-600 dark:text-blue-400 uppercase tracking-widest mb-1">Toplam Bağımsız Bölüm</p>
              <div className="flex items-baseline gap-2">
                  <span className="text-5xl font-black text-blue-700 dark:text-blue-400">{toplamDaireSayisi}</span>
                  <span className="text-xl font-black text-blue-700 dark:text-blue-400 uppercase">Daire</span>
              </div>
              <div className="mt-3 bg-blue-600 text-white text-[10px] font-black px-6 py-2 rounded-full uppercase tracking-widest shadow-lg shadow-blue-500/20">
                  {toplamDaireSayisi} ADET {results.daireTipi} TİPİ
              </div>
            </div>
          </div>
        </div>

        {/* Konum Değer Analizi */}
        <div className="bg-slate-900 text-white rounded-[2.5rem] shadow-2xl p-8 border border-slate-800 relative overflow-hidden flex flex-col justify-between">
          <div className="absolute top-0 right-0 p-8 opacity-5"><i className="fa-solid fa-city text-9xl"></i></div>
          <div className="relative z-10 space-y-6">
            <div className="flex justify-between items-start">
              <h3 className="text-xl font-black uppercase tracking-tighter">Konum Analizi</h3>
              <div className="flex gap-2">
                <button 
                  onClick={handleDownloadInfographic}
                  title="Raporu İndir"
                  className="w-10 h-10 bg-blue-600 hover:bg-blue-500 text-white rounded-2xl flex items-center justify-center shadow-lg transition-all active:scale-95 border border-blue-400/30"
                >
                  <i className="fa-solid fa-download text-xs"></i>
                </button>
                <div className="text-center bg-slate-800 p-3 rounded-2xl border border-slate-700">
                  <div className="text-3xl font-black text-blue-500 leading-none">{results.locationAnalysis?.score || "--"}</div>
                  <div className="text-[8px] font-black uppercase tracking-widest text-slate-500 mt-1">Puan</div>
                </div>
              </div>
            </div>
            <div className="bg-white/5 rounded-2xl p-5 border border-white/5 backdrop-blur-md">
              <p className="text-sm text-slate-300 leading-relaxed font-medium italic">
                "{results.locationAnalysis?.summary || "Bölgesel veriler analiz edilerek yatırım değeri puanlanıyor..."}"
              </p>
            </div>

            {results.locationAnalysis?.sources && results.locationAnalysis.sources.length > 0 && (
              <div className="space-y-2 mt-4">
                <p className="text-[8px] font-black text-slate-500 uppercase tracking-widest border-b border-white/10 pb-1">Bilgi Kaynakları</p>
                <div className="flex flex-col gap-1.5 max-h-24 overflow-y-auto pr-2">
                  {results.locationAnalysis.sources.map((source, i) => (
                    <a 
                      key={i} 
                      href={source.uri} 
                      target="_blank" 
                      rel="noopener noreferrer" 
                      className="flex items-center gap-2 group/link"
                    >
                      <i className="fa-solid fa-link text-[8px] text-blue-500 group-hover/link:scale-110 transition-transform"></i>
                      <span className="text-[9px] text-slate-400 hover:text-blue-400 transition-colors truncate">
                        {source.title || source.uri}
                      </span>
                    </a>
                  ))}
                </div>
              </div>
            )}
          </div>
          <div className="pt-6 border-t border-white/5 flex gap-2 overflow-x-auto">
              {results.locationAnalysis?.nearbyPlaces?.map((place, i) => (
                  <span key={i} className="whitespace-nowrap bg-blue-500/10 text-blue-400 text-[9px] font-black px-3 py-1.5 rounded-lg border border-blue-500/20 uppercase tracking-tighter">{place}</span>
              ))}
          </div>
        </div>
      </div>

      {/* GİZLİ İNFOGRAFİK ŞABLONU (Html2Canvas için) */}
      <div 
        ref={infographicRef}
        style={{ display: 'none', width: '800px', padding: '40px', background: '#0f172a' }}
        className="text-white font-sans"
      >
        <div className="flex justify-between items-center border-b border-white/10 pb-8 mb-8">
          <div>
            <h1 className="text-3xl font-black uppercase tracking-tighter">İmar Analiz Raporu</h1>
            <p className="text-blue-400 font-bold uppercase text-xs tracking-widest">{data.il} / {data.ilce} / {data.mahalle}</p>
          </div>
          <div className="text-right">
            <p className="text-slate-500 text-[10px] font-black uppercase tracking-widest">Ada - Parsel</p>
            <p className="text-2xl font-black text-white">{data.ada} / {data.parsel}</p>
          </div>
        </div>

        <div className="grid grid-cols-2 gap-10">
          <div className="space-y-8">
            <div className="bg-slate-800/50 p-6 rounded-[2rem] border border-white/5">
              <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-4">Arsa Geometrisi (2D)</h4>
              <div className="flex justify-center bg-slate-900/50 rounded-2xl p-4">
                {svgData && (
                  <svg width="300" height="225" viewBox="0 0 400 300">
                    <path d={svgData.d} fill="rgba(59, 130, 246, 0.1)" stroke="#3b82f6" strokeWidth="2" />
                    {svgData.points.map((p, i) => (
                      <circle key={i} cx={p.x} cy={p.y} r="3" fill="#3b82f6" />
                    ))}
                    {svgData.labels}
                  </svg>
                )}
              </div>
            </div>

            <div className="grid grid-cols-2 gap-4">
               <div className="bg-slate-800/30 p-4 rounded-2xl border border-white/5">
                  <p className="text-[8px] text-slate-500 uppercase font-black">Parsel Alanı</p>
                  <p className="text-xl font-black">{data.alan.toFixed(1)} m²</p>
               </div>
               <div className="bg-slate-800/30 p-4 rounded-2xl border border-white/5">
                  <p className="text-[8px] text-slate-500 uppercase font-black">Taban Alanı</p>
                  <p className="text-xl font-black text-emerald-400">{results.tabanAlani.toFixed(1)} m²</p>
               </div>
            </div>
          </div>

          <div className="space-y-6">
            <div className="bg-blue-600 p-8 rounded-[2.5rem] shadow-xl">
               <p className="text-[10px] font-black text-blue-100 uppercase tracking-widest mb-1">Daire Tipolojisi</p>
               <p className="text-3xl font-black mb-2">{toplamDaireSayisi} Daire</p>
               <p className="bg-white/20 inline-block px-4 py-1 rounded-full text-[10px] font-black uppercase tracking-widest">
                  {results.daireTipi} (Ort. {results.daireBasiMetrekare.toFixed(1)} m²)
               </p>
            </div>

            <div className="grid grid-cols-2 gap-3">
              {[
                { label: 'T.A.K.S', value: data.taks.toFixed(2) },
                { label: 'K.A.K.S', value: results.kaks.toFixed(2) },
                { label: 'Zemin Brüt', value: results.zeminBrut.toFixed(1) + ' m²' },
                { label: 'Kat Sayısı', value: data.katAdedi + ' Kat' },
              ].map((item, idx) => (
                <div key={idx} className="bg-slate-800/30 p-4 rounded-2xl border border-white/5">
                  <p className="text-[8px] text-slate-500 uppercase font-black">{item.label}</p>
                  <p className="text-lg font-black">{item.value}</p>
                </div>
              ))}
            </div>

            <div className="p-6 bg-slate-800/50 rounded-3xl border border-white/5">
              <h4 className="text-[9px] font-black text-slate-400 uppercase tracking-widest mb-3">Grounding Analizi</h4>
              <p className="text-xs text-slate-300 leading-relaxed italic line-clamp-4">
                {results.locationAnalysis?.summary || "Bölge analiz verisi mevcut değil."}
              </p>
            </div>
          </div>
        </div>

        <div className="mt-12 pt-8 border-t border-white/10 flex justify-between items-center opacity-30">
          <p className="text-[8px] font-black uppercase tracking-widest">İnşaat Proje Asistanı | Profesyonel Raporlama</p>
          <p className="text-[8px] font-black uppercase tracking-widest">{new Date().toLocaleDateString()}</p>
        </div>
      </div>
    </>
  );
};

