import React, { useState, useEffect } from 'react';
import { NizamType, ArsaBilgileri, HesapSonuclari, LocationAnalysisData, LocationSource } from './types';
import ConstructionForm from './components/ConstructionForm';
import PlotVisualizer from './components/PlotVisualizer';
import ResultsPanel from './components/ResultsPanel';
import Header from './components/Header';
import { GoogleGenAI } from "@google/genai";

const App: React.FC = () => {
  const [darkMode, setDarkMode] = useState(true);
  const [formData, setFormData] = useState<ArsaBilgileri | null>(null);
  const [results, setResults] = useState<HesapSonuclari | null>(null);
  const [isSearching, setIsSearching] = useState(false);

  useEffect(() => {
    if (darkMode) {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [darkMode]);

  const searchUsakZoning = async (mahalle: string, ada: string, parsel: string) => {
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const prompt = `Uşak İli Merkez İlçesi ${mahalle} Mahallesi Ada ${ada} Parsel ${parsel} için "https://keos.usak.bel.tr/imardurumu/index.aspx" adresindeki imar durumunu sorgula. 
      Sistemden şu bilgileri tam olarak çek: 
      1. T.A.K.S oranı (Örn: 0.30)
      2. K.A.K.S (Emsal) değeri (Örn: 1.20)
      3. Resmi Kat Adedi (Örn: 4)

      Yanıtı sadece şu JSON formatında ver: {"kat": 4, "emsal": 1.20, "taks": 0.30}. 
      Eğer veriyi bulamazsan bölge için geçerli olan en olası imar planı verilerini dön.`;

      const response = await ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: prompt,
        config: { tools: [{ googleSearch: {} }] },
      });

      const jsonMatch = response.text?.match(/\{.*\}/s);
      return jsonMatch ? JSON.parse(jsonMatch[0]) : { kat: 4, emsal: 1.20, taks: 0.30 };
    } catch (e) {
      return { kat: 4, emsal: 1.20, taks: 0.30 };
    }
  };

  const calculateData = async (data: ArsaBilgileri) => {
    setIsSearching(true);

    const calculatedKaks = data.kaks || (data.taks * data.katAdedi);
    const tabanAlani = data.alan * data.taks;
    const zeminBrut = tabanAlani * 1.1;
    const normalKatBrut = zeminBrut * 1.15;
    const daireBasiMetrekare = normalKatBrut / data.daireSayisiTercihi;

    let daireTipi = "Özel Proje";
    if (daireBasiMetrekare < 105) daireTipi = "1+1 Apart";
    else if (daireBasiMetrekare < 115) daireTipi = "2+1";
    else if (daireBasiMetrekare < 150) daireTipi = "3+1";
    else daireTipi = "4+1";

    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    // Piyasa araştırması ve konum analizi
    const marketPrompt = `${data.il} ${data.ilce} ${data.mahalle} mahallesi yakınlarında Türkiye genelindeki gayrimenkul satış platformlarındaki güncel satılık arsa ilanlarını araştır. 
    Bu arsanın (${data.alan} m2) toplam piyasa satış değeri yaklaşık ne kadar olmalı? 
    Bölgedeki m2 fiyatlarını baz alarak analiz et. Yanıtında spesifik web sitesi isimleri kullanma.
    Yanıtı şu JSON formatında ver: {"score": 85, "summary": "Bölge analizi...", "nearbyPlaces": ["Okul"], "tahminiDeger": "12.500.000 TL - 14.000.000 TL"}`;

    const locationRes = await ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: marketPrompt,
        config: { tools: [{ googleSearch: {} }] },
    }).catch(() => null);

    let locationInfo: LocationAnalysisData | undefined = undefined;
    if (locationRes) {
        const match = locationRes.text?.match(/\{.*\}/s);
        const jsonData = match ? JSON.parse(match[0]) : null;
        if (jsonData) {
            const sources: LocationSource[] = locationRes.candidates?.[0]?.groundingMetadata?.groundingChunks
                ?.filter((chunk: any) => chunk.web)
                ?.map((chunk: any) => ({
                    title: chunk.web.title || 'Kaynak',
                    uri: chunk.web.uri
                })) || [];
            locationInfo = { ...jsonData, sources };
        }
    }

    setResults({
      kaks: calculatedKaks,
      tabanAlani,
      zeminBrut,
      normalKatBrut,
      toplamKat: data.katAdedi,
      daireTipi,
      daireBasiMetrekare,
      locationAnalysis: locationInfo || undefined
    });
    setFormData(data);
    setIsSearching(false);
  };

  return (
    <div className="min-h-screen pb-12 transition-colors duration-300 bg-gray-50 dark:bg-slate-900 text-slate-900 dark:text-slate-100 font-sans selection:bg-blue-500 selection:text-white">
      <Header darkMode={darkMode} setDarkMode={setDarkMode} />

      <main className="container mx-auto px-4 mt-8 max-w-7xl">
        <div className="grid grid-cols-1 xl:grid-cols-12 gap-8 relative">

          {isSearching && (
            <div className="fixed inset-0 z-[100] bg-slate-950/80 backdrop-blur-xl flex flex-col items-center justify-center animate-in fade-in duration-300">
               <div className="w-20 h-20 border-4 border-emerald-500/20 border-t-emerald-500 rounded-full animate-spin"></div>
               <h2 className="mt-8 text-2xl font-black uppercase tracking-[0.3em] text-white">BEKLEYİN ARAŞTIRIYORUM</h2>
               <p className="mt-2 text-slate-400 font-bold uppercase text-[10px] tracking-widest">Türkiyedeki emlak siteleri araştırılıyor</p>
            </div>
          )}

          <div className="xl:col-span-4">
            <section className="bg-white dark:bg-slate-800/50 backdrop-blur-xl p-6 rounded-[2.5rem] shadow-2xl border border-gray-100 dark:border-slate-700/50">
              <ConstructionForm 
                onCalculate={calculateData} 
                onSearchUsak={searchUsakZoning} 
                isSearching={isSearching}
              />
            </section>
          </div>

          <div className="xl:col-span-8 space-y-8">
            {formData ? (
              <div className="space-y-8 animate-in fade-in zoom-in duration-500">
                <PlotVisualizer data={formData} results={results} />
                {results && <ResultsPanel results={results} data={formData} />}
              </div>
            ) : (
              <div className="h-[600px] flex flex-col items-center justify-center bg-white dark:bg-slate-800/30 rounded-[3rem] border-4 border-dashed border-gray-100 dark:border-slate-800 text-center p-12">
                <i className="fa-solid fa-house-chimney-window text-5xl text-blue-600/30 animate-pulse mb-8"></i>
                <h3 className="text-2xl font-black text-slate-400 dark:text-slate-600 uppercase tracking-widest">İnşaat Analizi İçin Dosya Bekleniyor</h3>
              </div>
            )}
          </div>
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useRef } from 'react';
import { HesapSonuclari, ArsaBilgileri, Point } from '../types';

interface ResultsPanelProps {
  results: HesapSonuclari;
  data: ArsaBilgileri;
}

const ResultsPanel: React.FC<ResultsPanelProps> = ({ results, data }) => {
  const infographicRef = useRef<HTMLDivElement>(null);

  const calculateDistance = (p1: Point, p2: Point) => {
    const dx = p1.x - p2.x;
    const dy = p1.y - p2.y;
    const dist = Math.sqrt(dx * dx + dy * dy);
    const isDecimalDegrees = Math.abs(dx) < 1;
    return isDecimalDegrees ? dist * 111320 : dist;
  };

  const handleDownloadInfographic = async () => {
    if (!infographicRef.current) return;
    const el = infographicRef.current;
    el.style.display = 'block';
    el.style.position = 'fixed';
    el.style.left = '-9999px';
    el.style.top = '0';

    try {
      // @ts-ignore
      const canvas = await window.html2canvas(el, {
        backgroundColor: '#0f172a',
        scale: 2,
        logging: false,
        useCORS: true
      });
      const link = document.createElement('a');
      link.download = `Gayrimenkul_Analizi_${data.ada}_${data.parsel}.png`;
      link.href = canvas.toDataURL('image/png');
      link.click();
    } catch (err) {
      console.error("Görsel oluşturma hatası:", err);
    } finally {
      el.style.display = 'none';
    }
  };

  const StatItem = ({ label, value, unit = "", subValue = "", color = "text-slate-800 dark:text-white" }: any) => (
    <div className="bg-white/50 dark:bg-slate-900/50 backdrop-blur-sm p-4 rounded-3xl border border-gray-100 dark:border-slate-800 transition-all hover:border-blue-500/30 group">
      <p className="text-[9px] font-black text-gray-400 dark:text-slate-500 uppercase mb-2 tracking-widest group-hover:text-blue-500 transition-colors">{label}</p>
      <div className="flex items-baseline gap-1">
        <span className={`text-xl font-black tracking-tighter ${color}`}>{value}</span>
        <span className="text-[10px] font-bold text-gray-400">{unit}</span>
      </div>
      {subValue && <p className="text-[9px] text-blue-500 mt-1 font-bold uppercase tracking-tight">{subValue}</p>}
    </div>
  );

  const toplamDaireSayisi = results.toplamKat * data.daireSayisiTercihi;

  const getSvgPath = () => {
    if (!data.koordinatlar || data.koordinatlar.length === 0) return null;
    const coords = data.koordinatlar;
    const minX = Math.min(...coords.map(p => p.x));
    const maxX = Math.max(...coords.map(p => p.x));
    const minY = Math.min(...coords.map(p => p.y));
    const maxY = Math.max(...coords.map(p => p.y));

    const w = maxX - minX;
    const h = maxY - minY;
    const svgW = 400;
    const svgH = 300;
    const scale = Math.min((svgW - 40) / w, (svgH - 40) / h);
    const areaRatio = results.tabanAlani / data.alan;
    const bScale = Math.sqrt(areaRatio);

    const arsaPoints = coords.map(p => ({
      x: (p.x - minX) * scale + 20,
      y: svgH - ((p.y - minY) * scale + 20)
    }));

    const centerX = 200;
    const centerY = 150;

    const binaPoints = arsaPoints.map(p => ({
        x: centerX + (p.x - centerX) * bScale,
        y: centerY + (p.y - centerY) * bScale
    }));

    const arsaD = arsaPoints.map((p, i) => `${i === 0 ? 'M' : 'L'} ${p.x} ${p.y}`).join(' ') + ' Z';
    const binaD = binaPoints.map((p, i) => `${i === 0 ? 'M' : 'L'} ${p.x} ${p.y}`).join(' ') + ' Z';

    const labels = [];
    for (let i = 0; i < arsaPoints.length; i++) {
      const p1 = arsaPoints[i];
      const p2 = arsaPoints[(i + 1) % arsaPoints.length];
      const length = calculateDistance(coords[i], coords[(i + 1) % coords.length]).toFixed(1);
      const midX = (p1.x + p2.x) / 2;
      const midY = (p1.y + p2.y) / 2;
      labels.push(<text key={`a-${i}`} x={midX} y={midY} fill="#ef4444" fontSize="7" fontWeight="black" textAnchor="middle">{length}m</text>);

      const bp1 = binaPoints[i];
      const bp2 = binaPoints[(i + 1) % binaPoints.length];
      const bLength = (parseFloat(length) * bScale).toFixed(1);
      labels.push(<text key={`b-${i}`} x={(bp1.x + bp2.x) / 2} y={(bp1.y + bp2.y) / 2} fill="#3b82f6" fontSize="7" fontWeight="black" textAnchor="middle">{bLength}m</text>);
    }

    return { arsaD, binaD, labels };
  };

  const svgData = getSvgPath();

  return (
    <>
      <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
        <div className="bg-white dark:bg-slate-800/80 rounded-[2.5rem] shadow-2xl p-8 border border-gray-100 dark:border-slate-700/50">
          <h3 className="text-xl font-black mb-8 flex items-center gap-3 uppercase tracking-tighter">
            <div className="w-10 h-10 bg-emerald-500/10 text-emerald-500 rounded-2xl flex items-center justify-center">
              <i className="fa-solid fa-calculator text-sm"></i>
            </div>
            Mühendislik Metrajı
          </h3>
          <div className="grid grid-cols-2 gap-3">
            <StatItem label="Hesaplanan KAKS" value={results.kaks.toFixed(2)} subValue="K.A.K.S (Emsal Verisi)" />
            <StatItem label="İnşaat Tabanı" value={results.tabanAlani.toFixed(1)} unit="m²" color="text-emerald-500" />
            <StatItem label="Normal Kat Alanı" value={results.normalKatBrut.toFixed(1)} unit="m²" />
            <StatItem label="Kat Sayısı" value={results.toplamKat} subValue="Resmi Limit" />
            <div className="col-span-2 bg-gradient-to-r from-blue-600/5 to-blue-500/10 dark:from-blue-500/10 dark:to-indigo-500/10 p-6 rounded-[2.5rem] border border-blue-200 dark:border-blue-800/50 flex flex-col items-center justify-center text-center group hover:scale-[1.02] transition-transform">
              <p className="text-[10px] font-black text-blue-600 dark:text-blue-400 uppercase tracking-widest mb-1">Toplam Bağımsız Bölüm</p>
              <div className="flex items-baseline gap-2">
                  <span className="text-5xl font-black text-blue-700 dark:text-blue-400">{toplamDaireSayisi}</span>
                  <span className="text-xl font-black text-blue-700 dark:text-blue-400 uppercase">Daire</span>
              </div>
              <div className="mt-3 bg-blue-600 text-white text-[10px] font-black px-6 py-2 rounded-full uppercase tracking-widest shadow-lg shadow-blue-500/20">{results.daireTipi} TİPİ</div>
            </div>
          </div>
        </div>

        <div className="bg-slate-900 text-white rounded-[2.5rem] shadow-2xl p-8 border border-slate-800 relative overflow-hidden flex flex-col justify-between">
          <div className="absolute top-0 right-0 p-8 opacity-5"><i className="fa-solid fa-city text-9xl"></i></div>
          <div className="relative z-10 space-y-6">
