import React, { useState, useEffect } from 'react';
import { NizamType, ArsaBilgileri, HesapSonuclari, LocationAnalysisData, LocationSource } from './types';
import ConstructionForm from './components/ConstructionForm';
import PlotVisualizer from './components/PlotVisualizer';
import ResultsPanel from './components/ResultsPanel';
import Header from './components/Header';
import { GoogleGenAI } from "@google/genai";

const App: React.FC = () => {
  const [darkMode, setDarkMode] = useState(true);
  const [formData, setFormData] = useState<ArsaBilgileri | null>(null);
  const [results, setResults] = useState<HesapSonuclari | null>(null);
  const [isSearching, setIsSearching] = useState(false);

  useEffect(() => {
    if (darkMode) {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [darkMode]);

  const searchUsakZoning = async (mahalle: string, ada: string, parsel: string) => {
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      // Kullanıcının paylaştığı fotoğraflardaki akışa göre prompt optimize edildi.
      const prompt = `Uşak KEOS (https://keos.usak.bel.tr/imardurumu/index.aspx) sistemine gir. 
      'Ada/Parsel' sekmesinde 'Tapu Mahalle' listesinden "${mahalle}" mahallesini seç. 
      'Ada' kutusuna "${ada}", 'Parsel' kutusuna "${parsel}" yaz ve 'Ara' (Yeşil buton) tıkla. 
      Çıkan sonuca tıklandığında açılan bilgi kartındaki (ds.png görüntüsündeki tablo) verileri çek:
      1. 'Kat Adedi' satırı
      2. 'İnşaat Nizamı' satırı (AYRIK veya BİTİŞİK)
      3. 'T.A.K.S' satırı
      4. 'K.A.K.S (Emsal)' satırı

      Yanıtı sadece şu JSON formatında ver: {"kat": 4, "nizam": "AYRIK", "taks": 0.35, "emsal": 1.40}. 
      Eğer veriyi bulamazsan bölge standartlarını dön.`;

      const response = await ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: prompt,
        config: { tools: [{ googleSearch: {} }] },
      });

      const jsonMatch = response.text?.match(/\{.*\}/s);
      return jsonMatch ? JSON.parse(jsonMatch[0]) : { kat: 4, nizam: "AYRIK", taks: 0.30, emsal: 1.20 };
    } catch (e) {
      return { kat: 4, nizam: "AYRIK", taks: 0.30, emsal: 1.20 };
    }
  };

  const calculateData = async (data: ArsaBilgileri) => {
    setIsSearching(true);

    // KAKS siteden geliyorsa onu kullan, gelmiyorsa TAKS * Kat olarak hesapla
    const calculatedKaks = data.kaks || (data.taks * data.katAdedi);
    const tabanAlani = data.alan * data.taks;
    const zeminBrut = tabanAlani * 1.1;
    const normalKatBrut = zeminBrut * 1.15;
    const daireBasiMetrekare = normalKatBrut / data.daireSayisiTercihi;

    let daireTipi = "Özel Proje";
    if (daireBasiMetrekare < 105) daireTipi = "1+1 Apart";
    else if (daireBasiMetrekare < 115) daireTipi = "2+1";
    else if (daireBasiMetrekare < 150) daireTipi = "3+1";
    else daireTipi = "4+1";

    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    const marketPrompt = `${data.il} ${data.ilce} ${data.mahalle} mahallesi yakınlarında Türkiye genelindeki gayrimenkul satış platformlarındaki güncel satılık arsa ilanlarını araştır. 
    Bu arsanın (${data.alan} m2) toplam piyasa satış değeri yaklaşık ne kadar olmalı? 
    Bölgedeki m2 fiyatlarını baz alarak analiz et. Yanıtında spesifik web sitesi isimleri kullanma.
    Yanıtı şu JSON formatında ver: {"score": 85, "summary": "Bölge analizi...", "nearbyPlaces": ["Okul"], "tahminiDeger": "12.500.000 TL - 14.000.000 TL"}`;

    const locationRes = await ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: marketPrompt,
        config: { tools: [{ googleSearch: {} }] },
    }).catch(() => null);

    let locationInfo: LocationAnalysisData | undefined = undefined;
    if (locationRes) {
        const match = locationRes.text?.match(/\{.*\}/s);
        const jsonData = match ? JSON.parse(match[0]) : null;
        if (jsonData) {
            const sources: LocationSource[] = locationRes.candidates?.[0]?.groundingMetadata?.groundingChunks
                ?.filter((chunk: any) => chunk.web)
                ?.map((chunk: any) => ({
                    title: chunk.web.title || 'Kaynak',
                    uri: chunk.web.uri
                })) || [];
            locationInfo = { ...jsonData, sources };
        }
    }

    setResults({
      kaks: calculatedKaks,
      tabanAlani,
      zeminBrut,
      normalKatBrut,
      toplamKat: data.katAdedi,
      daireTipi,
      daireBasiMetrekare,
      locationAnalysis: locationInfo || undefined
    });
    setFormData(data);
    setIsSearching(false);
  };

  return (
    <div className="min-h-screen pb-12 transition-colors duration-300 bg-gray-50 dark:bg-slate-900 text-slate-900 dark:text-slate-100 font-sans selection:bg-blue-500 selection:text-white">
      <Header darkMode={darkMode} setDarkMode={setDarkMode} />

      <main className="container mx-auto px-4 mt-8 max-w-7xl">
        <div className="grid grid-cols-1 xl:grid-cols-12 gap-8 relative">

          {isSearching && (
            <div className="fixed inset-0 z-[100] bg-slate-950/80 backdrop-blur-xl flex flex-col items-center justify-center animate-in fade-in duration-300">
               <div className="w-20 h-20 border-4 border-emerald-500/20 border-t-emerald-500 rounded-full animate-spin"></div>
               <h2 className="mt-8 text-2xl font-black uppercase tracking-[0.3em] text-white">BEKLEYİN ARAŞTIRIYORUM</h2>
               <p className="mt-2 text-slate-400 font-bold uppercase text-[10px] tracking-widest">Türkiyedeki emlak siteleri araştırılıyor</p>
            </div>
          )}

          <div className="xl:col-span-4">
            <section className="bg-white dark:bg-slate-800/50 backdrop-blur-xl p-6 rounded-[2.5rem] shadow-2xl border border-gray-100 dark:border-slate-700/50">
              <ConstructionForm 
                onCalculate={calculateData} 
                onSearchUsak={searchUsakZoning} 
                isSearching={isSearching}
              />
            </section>
          </div>

          <div className="xl:col-span-8 space-y-8">
            {formData ? (
              <div className="space-y-8 animate-in fade-in zoom-in duration-500">
                <PlotVisualizer data={formData} results={results} />
                {results && <ResultsPanel results={results} data={formData} />}
              </div>
            ) : (
              <div className="h-[600px] flex flex-col items-center justify-center bg-white dark:bg-slate-800/30 rounded-[3rem] border-4 border-dashed border-gray-100 dark:border-slate-800 text-center p-12">
                <i className="fa-solid fa-house-chimney-window text-5xl text-blue-600/30 animate-pulse mb-8"></i>
                <h3 className="text-2xl font-black text-slate-400 dark:text-slate-600 uppercase tracking-widest">İnşaat Analizi İçin Dosya Bekleniyor</h3>
              </div>
            )}
          </div>
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState, useCallback, useRef } from 'react';
import { NizamType, ArsaBilgileri, Point } from '../types';

interface ConstructionFormProps {
  onCalculate: (data: ArsaBilgileri) => void;
  onSearchUsak: (mahalle: string, ada: string, parsel: string) => Promise<any>;
  isSearching: boolean;
}

const ConstructionForm: React.FC<ConstructionFormProps> = ({ onCalculate, onSearchUsak, isSearching }) => {
  const [step, setStep] = useState(1);
  const [isFetchingZoning, setIsFetchingZoning] = useState(false);
  const [isDragging, setIsDragging] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [formData, setFormData] = useState<any>({
    alan: '',
    nizam: NizamType.AYRIK,
    daireSayisiTercihi: 4,
    taks: '',
    katAdedi: '',
    kaks: '', // Emsal değeri
    cekmeOn: 5,
    cekmeYan: 3,
    cekmeArka: 3,
    il: 'Uşak',
    ilce: 'Merkez',
    mahalle: '',
    ada: '',
    parsel: '',
    geoJsonInput: '',
    koordinatlar: []
  });

  const parseTKGMData = (input: string) => {
    try {
      const data = JSON.parse(input);
      let feature = null;

      if (data.type === 'FeatureCollection' && data.features && data.features.length > 0) {
        feature = data.features[0];
      } else if (data.type === 'Feature') {
        feature = data;
      }

      if (feature && feature.geometry && feature.geometry.coordinates) {
        const rawCoords = feature.geometry.type === 'Polygon' 
          ? feature.geometry.coordinates[0] 
          : feature.geometry.coordinates[0][0];

        const points = rawCoords.map((c: any) => ({ x: c[0], y: c[1] }));
        const props = feature.properties || {};

        setFormData((prev: any) => ({
          ...prev,
          mahalle: props.Mahalle || props.MAHALLE || prev.mahalle,
          ada: props.Ada || props.ADA || prev.ada,
          parsel: props.ParselNo || props.PARSEL || prev.parsel,
          alan: props.Alan ? parseFloat(String(props.Alan).replace(',', '.')) : prev.alan,
          geoJsonInput: input,
          koordinatlar: points
        }));
        return true;
      }
    } catch (e) {
      console.error("JSON Ayrıştırma Hatası:", e);
    }
    return false;
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (event) => {
        const content = event.target?.result as string;
        parseTKGMData(content);
      };
      reader.readAsText(file);
    }
  };

  const handleFileDrop = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);
    const file = e.dataTransfer.files[0];
    if (file && file.name.endsWith('.json')) {
      const reader = new FileReader();
      reader.onload = (event) => {
        const content = event.target?.result as string;
        parseTKGMData(content);
      };
      reader.readAsText(file);
    } else if (file) {
      alert("Lütfen sadece .json formatında bir TKGM dosyası yükleyin.");
    }
  };

  const handlePaste = (e: React.ClipboardEvent) => {
    const text = e.clipboardData.getData('text');
    if (text.includes('{') && text.includes('}')) {
      parseTKGMData(text);
    }
  };

  const handleFetchFromKeos = async () => {
    if (!formData.ada || !formData.parsel) {
      alert("Lütfen önce Ada ve Parsel bilgilerini giriniz.");
      return;
    }
    setIsFetchingZoning(true);
    try {
      const info = await onSearchUsak(formData.mahalle, formData.ada, formData.parsel);
      if (info) {
        setFormData((prev: any) => ({
          ...prev,
          katAdedi: info.kat || prev.katAdedi,
          kaks: info.emsal || prev.kaks,
          taks: info.taks || prev.taks,
          nizam: info.nizam?.includes('AYRIK') ? NizamType.AYRIK : (info.nizam?.includes('BİTİŞİK') ? NizamType.BITISIK : prev.nizam)
        }));
      }
    } catch (err) {
      console.error("Fetch error", err);
    } finally {
      setIsFetchingZoning(false);
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onCalculate({
      ...formData,
      alan: Number(formData.alan),
      taks: Number(formData.taks),
      katAdedi: Number(formData.katAdedi),
      kaks: Number(formData.kaks),
      daireSayisiTercihi: Number(formData.daireSayisiTercihi),
      koordinatlar: formData.koordinatlar.length > 0 ? formData.koordinatlar : undefined
    });
  };

  return (
    <form onSubmit={handleSubmit} className="space-y-6" onPaste={handlePaste}>
      {step === 1 && (
        <div className="space-y-4">
          <input 
            type="file" 
            ref={fileInputRef} 
            onChange={handleFileChange} 
            accept=".json" 
            className="hidden" 
          />
          <div 
            onDragOver={(e) => { e.preventDefault(); setIsDragging(true); }}
            onDragLeave={() => setIsDragging(false)}
            onDrop={handleFileDrop}
            onClick={() => fileInputRef.current?.click()}
            className={`relative group transition-all duration-500 border-4 border-dashed rounded-[2rem] p-8 text-center cursor-pointer ${isDragging ? 'border-blue-500 bg-blue-50 dark:bg-blue-900/20 scale-[1.02]' : 'border-gray-200 dark:border-slate-700 hover:border-blue-400'}`}
          >
            <div className="space-y-3 pointer-events-none">
              <div className={`w-16 h-16 rounded-2xl mx-auto flex items-center justify-center shadow-xl transition-colors ${isDragging ? 'bg-blue-500' : 'bg-blue-600'}`}>
                <i className={`fa-solid ${isDragging ? 'fa-hand-holding-heart animate-bounce' : 'fa-file-import'} text-2xl text-white`}></i>
              </div>
              <h4 className="font-black text-slate-800 dark:text-white uppercase tracking-tighter text-sm">
                {isDragging ? 'BURAYA BIRAKIN' : 'TKGM Dosyası Sürükle, Yapıştır veya'}
              </h4>
              <button 
                type="button" 
                className="bg-blue-100 dark:bg-blue-900/40 text-blue-600 dark:text-blue-300 px-4 py-1.5 rounded-full text-[10px] font-black uppercase tracking-widest hover:bg-blue-200 transition-colors pointer-events-auto"
                onClick={(e) => { e.stopPropagation(); fileInputRef.current?.click(); }}
              >
                Dosya Seç
              </button>
              <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest block mt-2">Sadece .json dosyası</p>
            </div>
          </div>

          <div className="grid grid-cols-3 gap-2">
            <input placeholder="Mahalle" name="mahalle" value={formData.mahalle} onChange={(e)=>setFormData({...formData, mahalle: e.target.value})} className="w-full bg-gray-50 dark:bg-slate-900 border border-gray-200 dark:border-slate-700 rounded-xl py-2 px-3 text-xs font-bold focus:ring-2 focus:ring-blue-500 outline-none" />
            <input placeholder="Ada" name="ada" value={formData.ada} onChange={(e)=>setFormData({...formData, ada: e.target.value})} className="w-full bg-gray-50 dark:bg-slate-900 border border-gray-200 dark:border-slate-700 rounded-xl py-2 px-3 text-xs font-bold focus:ring-2 focus:ring-blue-500 outline-none" />
            <input placeholder="Parsel" name="parsel" value={formData.parsel} onChange={(e)=>setFormData({...formData, parsel: e.target.value})} className="w-full bg-gray-50 dark:bg-slate-900 border border-gray-200 dark:border-slate-700 rounded-xl py-2 px-3 text-xs font-bold focus:ring-2 focus:ring-blue-500 outline-none" />
